window.LUAU_VM_MODULES={"opcodes":"-- luau-vm/src/opcodes.lua\n-- Custom instruction set for the ferret VM.\n--\n-- Register-based. Operands are register indices unless noted. Multi-value\n-- calls/returns/varargs follow a Lua-style convention: a count field of 0 means\n-- \"up to the current frame top\" (set by a preceding multi-value producer), and\n-- a result count of 0 means \"produce all results and set top\". Everything else\n-- uses exact counts, which keeps the common case simple and fast.\n--\n-- Instructions are stored at compile time as tables {op=, a=, b=, c=, bx=, sbx=}\n-- for readability; the serializer packs them into a compact binary form.\n--\n-- Captured locals and upvalues are unified as \"cells\" (a 1-field box {v=...}),\n-- so closures never touch the parent's live registers  no open/closed upvalue\n-- machinery is required.\n\nlocal Op = {}\nlocal names = {}\nlocal n = 0\nlocal function def(name)\n  n = n + 1\n  Op[name] = n\n  names[n] = name\n  return n\nend\n\n--  data movement / constants \ndef('MOVE')      -- A B      R[A] = R[B]\ndef('LOADK')     -- A Bx     R[A] = K[Bx]\ndef('LOADINT')   -- A sBx    R[A] = sBx                (immediate small integer)\ndef('LOADBOOL')  -- A B      R[A] = (B ~= 0)\ndef('LOADNIL')   -- A B      R[A..A+B] = nil\n\n--  globals / environment \ndef('GETGLOBAL') -- A Bx     R[A] = ENV[K[Bx]]\ndef('SETGLOBAL') -- A Bx     ENV[K[Bx]] = R[A]\n\n--  cells (captured locals) & upvalues \ndef('NEWCELL')   -- A        R[A] = { v = R[A] }       (box a captured local)\ndef('GETCELL')   -- A B      R[A] = R[B].v\ndef('SETCELL')   -- A B      R[A].v = R[B]\ndef('GETUPVAL')  -- A B      R[A] = U[B].v\ndef('SETUPVAL')  -- A B      U[B].v = R[A]\n\n--  tables \ndef('NEWTABLE')  -- A        R[A] = {}\ndef('GETTABLE')  -- A B C    R[A] = R[B][R[C]]\ndef('SETTABLE')  -- A B C    R[A][R[B]] = R[C]\ndef('GETFIELD')  -- A B Bx   R[A] = R[B][K[Bx]]        (const-string key fast path)\ndef('SETFIELD')  -- A Bx C   R[A][K[Bx]] = R[C]\ndef('SELF')      -- A B C    R[A+1] = R[B]; R[A] = R[B][K[C]]  (method prep)\ndef('SETLIST')   -- A B C    R[A][C + i] = R[A+i], i=1..B (B=0 -> up to top)\n\n--  arithmetic (R[A] = R[B] op R[C]) \ndef('ADD'); def('SUB'); def('MUL'); def('DIV'); def('MOD'); def('POW'); def('IDIV')\n--  bitwise \ndef('BAND'); def('BOR'); def('BXOR'); def('SHL'); def('SHR')\n--  concat \ndef('CONCAT')    -- A B C    R[A] = R[B] .. R[B+1] .. ... .. R[C]\n--  unary \ndef('UNM'); def('NOT'); def('LEN'); def('BNOT')  -- A B   R[A] = op R[B]\n--  comparison (R[A] = R[B] op R[C]) \ndef('EQ'); def('LT'); def('LE')\n\n--  control flow \ndef('JMP')       -- sBx      pc += sBx\ndef('JMPIF')     -- A sBx    if truthy(R[A]) then pc += sBx\ndef('JMPIFNOT')  -- A sBx    if not truthy(R[A]) then pc += sBx\n\n--  calls / returns \ndef('CALL')      -- A B C    call R[A] with (B-1) args; keep (C-1) results (0 = to top)\ndef('TAILCALL')  -- A B      return R[A]((B-1) args)   (no host TCO; result-preserving)\ndef('RETURN')    -- A B      return R[A..A+B-2]        (B=0 -> to top)\n\n--  closures / varargs \ndef('CLOSURE')   -- A Bx     R[A] = closure(protos[Bx], captured upvals)\ndef('VARARG')    -- A B      R[A..A+B-2] = varargs     (B=0 -> to top)\n\n--  loops \ndef('FORPREP')   -- A sBx    numeric-for init; jump to loop test\ndef('FORLOOP')   -- A sBx    numeric-for step + test; jump back if continuing\ndef('TFORPREP')  -- A        generic-for setup: normalize R[A..A+2] for Luau\n                 --          generalized iteration (table/__iter -> next-triple)\ndef('TFORCALL')  -- A C      generic-for: call iterator, C results into R[A+3..]\ndef('TFORLOOP')  -- A sBx    generic-for: if R[A+1] ~= nil then R[A]=R[A+1]; pc += sBx\n\ndef('NOP')       -- (used by peephole/DCE)\n\n-- Operand layout per opcode: which instruction fields carry data. Used by the\n-- serializer for a compact, self-validating encoding, and as documentation.\nlocal A, AB, ABC = { 'a' }, { 'a', 'b' }, { 'a', 'b', 'c' }\nlocal operands = {\n  [Op.MOVE] = AB, [Op.LOADK] = { 'a', 'bx' }, [Op.LOADINT] = { 'a', 'sbx' },\n  [Op.LOADBOOL] = AB, [Op.LOADNIL] = AB,\n  [Op.GETGLOBAL] = { 'a', 'bx' }, [Op.SETGLOBAL] = { 'a', 'bx' },\n  [Op.NEWCELL] = A, [Op.GETCELL] = AB, [Op.SETCELL] = AB, [Op.GETUPVAL] = AB, [Op.SETUPVAL] = AB,\n  [Op.NEWTABLE] = A, [Op.GETTABLE] = ABC, [Op.SETTABLE] = ABC,\n  [Op.GETFIELD] = { 'a', 'b', 'bx' }, [Op.SETFIELD] = { 'a', 'bx', 'c' },\n  [Op.SELF] = ABC, [Op.SETLIST] = ABC,\n  [Op.ADD] = ABC, [Op.SUB] = ABC, [Op.MUL] = ABC, [Op.DIV] = ABC, [Op.MOD] = ABC,\n  [Op.POW] = ABC, [Op.IDIV] = ABC,\n  [Op.BAND] = ABC, [Op.BOR] = ABC, [Op.BXOR] = ABC, [Op.SHL] = ABC, [Op.SHR] = ABC,\n  [Op.CONCAT] = ABC,\n  [Op.UNM] = AB, [Op.NOT] = AB, [Op.LEN] = AB, [Op.BNOT] = AB,\n  [Op.EQ] = ABC, [Op.LT] = ABC, [Op.LE] = ABC,\n  [Op.JMP] = { 'sbx' }, [Op.JMPIF] = { 'a', 'sbx' }, [Op.JMPIFNOT] = { 'a', 'sbx' },\n  [Op.CALL] = ABC, [Op.TAILCALL] = AB, [Op.RETURN] = AB,\n  [Op.CLOSURE] = { 'a', 'bx' }, [Op.VARARG] = AB,\n  [Op.FORPREP] = { 'a', 'sbx' }, [Op.FORLOOP] = { 'a', 'sbx' },\n  [Op.TFORPREP] = A, [Op.TFORCALL] = { 'a', 'c' }, [Op.TFORLOOP] = { 'a', 'sbx' },\n  [Op.NOP] = {},\n}\n\nlocal Opcodes = { Op = Op, name = names, count = n, operands = operands }\n\nfunction Opcodes.mnemonic(op)\n  return names[op] or ('?' .. tostring(op))\nend\n\nreturn Opcodes\n","bitops":"-- luau-vm/src/bitops.lua\n-- Custom 32-bit bitwise ops. Deliberately does NOT use the standard `bit32`\n-- library: the ops are our own, built from per-nibble lookup tables so a build\n-- ships no recognizable bit32.* calls. Semantics match 32-bit unsigned bit32\n-- (the model Luau uses), so VM programs behave identically on Luau and Lua 5.4.\n-- Processing 4 bits at a time via a 16x16 table keeps this ~8 lookups per op\n-- (far cheaper than a 32-iteration per-bit loop) so hot bitwise code stays fast.\n\nlocal M = {}\nlocal TWO32 = 4294967296\n\n-- Per-nibble truth tables for our three primitive binary ops, built once.\nlocal AND, OR, XOR = {}, {}, {}\nfor x = 0, 15 do\n  AND[x], OR[x], XOR[x] = {}, {}, {}\n  for y = 0, 15 do\n    local a, b, ra, ro, rx, p = x, y, 0, 0, 0, 1\n    for _ = 1, 4 do\n      local xb, yb = a % 2, b % 2\n      if xb == 1 and yb == 1 then ra = ra + p end\n      if xb == 1 or yb == 1 then ro = ro + p end\n      if xb ~= yb then rx = rx + p end\n      a = (a - xb) / 2; b = (b - yb) / 2; p = p * 2\n    end\n    AND[x][y] = ra; OR[x][y] = ro; XOR[x][y] = rx\n  end\nend\n\nlocal function norm(x) return math.floor(x) % TWO32 end\n\n-- Combine two 32-bit values a nibble at a time through table T.\nlocal function apply(a, b, T)\n  a = norm(a); b = norm(b)\n  local r, p = 0, 1\n  for _ = 1, 8 do\n    local an, bn = a % 16, b % 16\n    r = r + T[an][bn] * p\n    a = (a - an) / 16; b = (b - bn) / 16; p = p * 16\n  end\n  return r\nend\n\nfunction M.band(a, b) return apply(a, b, AND) end\nfunction M.bor(a, b) return apply(a, b, OR) end\nfunction M.bxor(a, b) return apply(a, b, XOR) end\nfunction M.lshift(a, n) return norm(norm(a) * (2 ^ n)) end\nfunction M.rshift(a, n) return math.floor(norm(a) / (2 ^ n)) end\nfunction M.bnot(a) return (TWO32 - 1) - norm(a) end\n\nreturn M\n","lexer":"-- luau-vm/src/lexer.lua\n-- Tokenizer for the Luau subset the VM compiler accepts. Single pass, minimal\n-- allocation (one token table per token, no intermediate substrings beyond the\n-- token text). Returns an array of { type, value, line }.\n\nlocal Lexer = {}\n\nlocal KEYWORDS = {}\nfor _, k in ipairs({\n  'and', 'break', 'do', 'else', 'elseif', 'end', 'false', 'for', 'function',\n  'goto', 'if', 'in', 'local', 'nil', 'not', 'or', 'repeat', 'return', 'then',\n  'true', 'until', 'while',\n}) do KEYWORDS[k] = true end\n\n-- Longest match wins, so multi-char operators are listed before their prefixes.\n-- Luau compound assignments (`+=`, `..=`, `//=`, ) are included.\nlocal SYMBOLS = {\n  '...', '//=', '..=',\n  '..', '::', '==', '~=', '<=', '>=', '//', '<<', '>>', '->',\n  '+=', '-=', '*=', '/=', '%=', '^=',\n  '+', '-', '*', '/', '%', '^', '#', '&', '~', '|', '<', '>', '=',\n  '(', ')', '{', '}', '[', ']', ';', ':', ',', '.', '?',\n}\n\nlocal function isDigit(c) return c >= '0' and c <= '9' end\nlocal function isHex(c)\n  return (c >= '0' and c <= '9') or (c >= 'a' and c <= 'f') or (c >= 'A' and c <= 'F')\nend\nlocal function isAlpha(c)\n  return (c >= 'a' and c <= 'z') or (c >= 'A' and c <= 'Z') or c == '_'\nend\nlocal function isAlphaNum(c) return isAlpha(c) or isDigit(c) end\n\n-- Encode a Unicode code point as UTF-8 (mirrors Lua's luaO_utf8esc: up to 6\n-- bytes for values through 0x7FFFFFFF), so \\u{...} matches native Lua/Luau.\nlocal function utf8esc(cp)\n  if cp < 0x80 then return string.char(cp) end\n  local cont, mfb, x = {}, 0x3f, cp\n  repeat\n    cont[#cont + 1] = 0x80 + (x % 0x40)\n    x = math.floor(x / 0x40)\n    mfb = math.floor(mfb / 2)\n  until x <= mfb\n  local firstByte = ((255 - mfb) * 2) % 256 + x -- (~mfb << 1) | x, byte-wide\n  local out = { string.char(firstByte) }\n  for i = #cont, 1, -1 do out[#out + 1] = string.char(cont[i]) end -- continuation bytes, highlow\n  return table.concat(out)\nend\n\nfunction Lexer.tokenize(src, chunk)\n  chunk = chunk or 'input'\n  local tokens = {}\n  local pos, line, n = 1, 1, #src\n\n  local function err(msg) error(chunk .. ':' .. line .. ': ' .. msg, 0) end\n  local function peek(o) return src:sub(pos + (o or 0), pos + (o or 0)) end\n\n  local function newline()\n    local c = peek(); pos = pos + 1\n    local c2 = peek()\n    if (c2 == '\\n' or c2 == '\\r') and c2 ~= c then pos = pos + 1 end\n    line = line + 1\n  end\n\n  local function readLong()\n    if peek() ~= '[' then return nil end\n    local level, p = 0, pos + 1\n    while src:sub(p, p) == '=' do level = level + 1; p = p + 1 end\n    if src:sub(p, p) ~= '[' then return nil end\n    pos = p + 1\n    if peek() == '\\r' or peek() == '\\n' then newline() end\n    local buf, close = {}, ']' .. string.rep('=', level) .. ']'\n    while true do\n      if pos > n then err('unfinished long bracket') end\n      local c = peek()\n      if c == ']' and src:sub(pos, pos + #close - 1) == close then\n        pos = pos + #close; return table.concat(buf)\n      elseif c == '\\n' or c == '\\r' then buf[#buf + 1] = '\\n'; newline()\n      else buf[#buf + 1] = c; pos = pos + 1 end\n    end\n  end\n\n  local function readString(q)\n    pos = pos + 1\n    local buf = {}\n    while true do\n      if pos > n then err('unfinished string') end\n      local c = peek()\n      if c == q then pos = pos + 1; break\n      elseif c == '\\n' or c == '\\r' then err('unfinished string')\n      elseif c == '\\\\' then\n        pos = pos + 1\n        local e = peek()\n        if e == 'n' then buf[#buf + 1] = '\\n'; pos = pos + 1\n        elseif e == 't' then buf[#buf + 1] = '\\t'; pos = pos + 1\n        elseif e == 'r' then buf[#buf + 1] = '\\r'; pos = pos + 1\n        elseif e == 'a' then buf[#buf + 1] = '\\a'; pos = pos + 1\n        elseif e == 'b' then buf[#buf + 1] = '\\b'; pos = pos + 1\n        elseif e == 'f' then buf[#buf + 1] = '\\f'; pos = pos + 1\n        elseif e == 'v' then buf[#buf + 1] = '\\v'; pos = pos + 1\n        elseif e == '\\\\' then buf[#buf + 1] = '\\\\'; pos = pos + 1\n        elseif e == '\"' then buf[#buf + 1] = '\"'; pos = pos + 1\n        elseif e == \"'\" then buf[#buf + 1] = \"'\"; pos = pos + 1\n        elseif e == '\\n' or e == '\\r' then buf[#buf + 1] = '\\n'; newline()\n        elseif e == 'x' then\n          pos = pos + 1\n          local h = ''\n          for _ = 1, 2 do if isHex(peek()) then h = h .. peek(); pos = pos + 1 end end\n          if #h == 0 then err('hexadecimal digit expected') end\n          buf[#buf + 1] = string.char(tonumber(h, 16))\n        elseif e == 'z' then\n          pos = pos + 1\n          while pos <= n do\n            local w = peek()\n            if w == '\\n' or w == '\\r' then newline()\n            elseif w == ' ' or w == '\\t' or w == '\\f' or w == '\\v' then pos = pos + 1\n            else break end\n          end\n        elseif e == 'u' then\n          -- \\u{XXXX}: Unicode code point, UTF-8 encoded (Lua 5.3+/Luau)\n          pos = pos + 1\n          if peek() ~= '{' then err(\"missing '{' in \\\\u{XXXX}\") end\n          pos = pos + 1\n          local h = ''\n          while isHex(peek()) do h = h .. peek(); pos = pos + 1 end\n          if #h == 0 then err('hexadecimal digit expected') end\n          if peek() ~= '}' then err(\"missing '}' in \\\\u{XXXX}\") end\n          pos = pos + 1\n          local cp = tonumber(h, 16)\n          if cp > 0x7FFFFFFF then err('UTF-8 value too large') end\n          buf[#buf + 1] = utf8esc(cp)\n        elseif isDigit(e) then\n          local d = ''\n          for _ = 1, 3 do if isDigit(peek()) then d = d .. peek(); pos = pos + 1 else break end end\n          local num = tonumber(d)\n          if num > 255 then err('decimal escape too large') end\n          buf[#buf + 1] = string.char(num)\n        else err(\"invalid escape sequence '\\\\\" .. e .. \"'\") end\n      else buf[#buf + 1] = c; pos = pos + 1 end\n    end\n    return table.concat(buf)\n  end\n\n  -- Luau string interpolation: `text {expr} more`. Produces an 'interp' token\n  -- carrying the literal chunks and the raw source of each embedded expression;\n  -- the parser turns it into a `..`/tostring concatenation. `\\{` is a literal\n  -- brace; `{` opens an interpolation whose braces/strings are balanced so a `}`\n  -- inside a nested table or string does not close it early.\n  local function readInterp()\n    pos = pos + 1 -- past the opening backtick\n    local literals, exprs = {}, {}\n    local buf = {}\n    while true do\n      if pos > n then err('unfinished interpolated string') end\n      local c = peek()\n      if c == '`' then pos = pos + 1; literals[#literals + 1] = table.concat(buf); break\n      elseif c == '\\n' or c == '\\r' then err('unfinished interpolated string')\n      elseif c == '\\\\' then\n        pos = pos + 1; local e = peek()\n        if e == 'n' then buf[#buf + 1] = '\\n'; pos = pos + 1\n        elseif e == 't' then buf[#buf + 1] = '\\t'; pos = pos + 1\n        elseif e == 'r' then buf[#buf + 1] = '\\r'; pos = pos + 1\n        elseif e == '`' then buf[#buf + 1] = '`'; pos = pos + 1\n        elseif e == '{' then buf[#buf + 1] = '{'; pos = pos + 1\n        elseif e == '}' then buf[#buf + 1] = '}'; pos = pos + 1\n        elseif e == '\\\\' then buf[#buf + 1] = '\\\\'; pos = pos + 1\n        else buf[#buf + 1] = '\\\\' .. e; pos = pos + 1 end\n      elseif c == '{' then\n        literals[#literals + 1] = table.concat(buf); buf = {}\n        pos = pos + 1\n        local estart, depth = pos, 1\n        while depth > 0 do\n          if pos > n then err('unfinished interpolation expression') end\n          local d = peek()\n          if d == '{' then depth = depth + 1; pos = pos + 1\n          elseif d == '}' then depth = depth - 1; pos = pos + 1\n          elseif d == '\"' or d == \"'\" then readString(d) -- skip a nested string literal\n          else pos = pos + 1 end\n        end\n        exprs[#exprs + 1] = src:sub(estart, pos - 2) -- inner source, sans braces\n      else buf[#buf + 1] = c; pos = pos + 1 end\n    end\n    return { literals = literals, exprs = exprs }\n  end\n\n  local function readNumber()\n    local start = pos\n    if peek() == '0' and (peek(1) == 'x' or peek(1) == 'X') then\n      pos = pos + 2\n      while isHex(peek()) or peek() == '.' do pos = pos + 1 end\n      if peek() == 'p' or peek() == 'P' then\n        pos = pos + 1\n        if peek() == '+' or peek() == '-' then pos = pos + 1 end\n        while isDigit(peek()) do pos = pos + 1 end\n      end\n    else\n      while isDigit(peek()) or peek() == '.' do pos = pos + 1 end\n      if peek() == 'e' or peek() == 'E' then\n        pos = pos + 1\n        if peek() == '+' or peek() == '-' then pos = pos + 1 end\n        while isDigit(peek()) do pos = pos + 1 end\n      end\n    end\n    return src:sub(start, pos - 1)\n  end\n\n  while pos <= n do\n    local c = peek()\n    local tokStart = pos\n    if c == '\\n' or c == '\\r' then newline()\n    elseif c == ' ' or c == '\\t' or c == '\\f' or c == '\\v' then pos = pos + 1\n    elseif c == '-' and peek(1) == '-' then\n      pos = pos + 2\n      if peek() == '[' then\n        local saved = pos\n        if readLong() == nil then\n          pos = saved\n          while pos <= n and peek() ~= '\\n' and peek() ~= '\\r' do pos = pos + 1 end\n        end\n      else\n        while pos <= n and peek() ~= '\\n' and peek() ~= '\\r' do pos = pos + 1 end\n      end\n    elseif isAlpha(c) then\n      while isAlphaNum(peek()) do pos = pos + 1 end\n      local w = src:sub(tokStart, pos - 1)\n      tokens[#tokens + 1] = { type = KEYWORDS[w] and 'keyword' or 'name', value = w, line = line }\n    elseif isDigit(c) or (c == '.' and isDigit(peek(1))) then\n      local ln = line\n      tokens[#tokens + 1] = { type = 'number', value = readNumber(), line = ln }\n    elseif c == '\"' or c == \"'\" then\n      local ln = line\n      tokens[#tokens + 1] = { type = 'string', value = readString(c), line = ln }\n    elseif c == '`' then\n      local ln = line\n      local it = readInterp()\n      tokens[#tokens + 1] = { type = 'interp', literals = it.literals, exprs = it.exprs, line = ln }\n    elseif c == '[' and (peek(1) == '[' or peek(1) == '=') then\n      local ln = line\n      local s = readLong()\n      if s ~= nil then tokens[#tokens + 1] = { type = 'string', value = s, line = ln }\n      else tokens[#tokens + 1] = { type = 'symbol', value = '[', line = ln }; pos = pos + 1 end\n    else\n      local matched\n      for _, sym in ipairs(SYMBOLS) do\n        if src:sub(pos, pos + #sym - 1) == sym then matched = sym; break end\n      end\n      if not matched then err(\"unexpected symbol near '\" .. c .. \"'\") end\n      tokens[#tokens + 1] = { type = 'symbol', value = matched, line = line }\n      pos = pos + #matched\n    end\n  end\n  tokens[#tokens + 1] = { type = 'eof', value = '<eof>', line = line }\n  return tokens\nend\n\nreturn Lexer\n","parser":"-- luau-vm/src/parser.lua\n-- Recursive-descent parser with precedence climbing. Produces an AST of tables\n-- tagged with `k`. Covers the executable Luau grammar the compiler lowers.\n\nlocal Lexer = require('lexer')\n\nlocal Parser = {}\nParser.__index = Parser\n\nlocal BLOCK_END = { ['end'] = true, ['else'] = true, ['elseif'] = true, ['until'] = true }\n-- binary op [left, right] priorities; right < left => right associative\nlocal BINPRI = {\n  ['or'] = { 1, 1 }, ['and'] = { 2, 2 },\n  ['<'] = { 3, 3 }, ['>'] = { 3, 3 }, ['<='] = { 3, 3 }, ['>='] = { 3, 3 }, ['~='] = { 3, 3 }, ['=='] = { 3, 3 },\n  ['|'] = { 4, 4 }, ['~'] = { 5, 5 }, ['&'] = { 6, 6 }, ['<<'] = { 7, 7 }, ['>>'] = { 7, 7 },\n  ['..'] = { 9, 8 }, ['+'] = { 10, 10 }, ['-'] = { 10, 10 },\n  ['*'] = { 11, 11 }, ['/'] = { 11, 11 }, ['//'] = { 11, 11 }, ['%'] = { 11, 11 },\n  ['^'] = { 14, 13 },\n}\nlocal UNARY_PRI = 12\n\nlocal function new(tokens, chunk)\n  return setmetatable({ toks = tokens, i = 1, chunk = chunk or 'input' }, Parser)\nend\n\nfunction Parser:peek(o) return self.toks[self.i + (o or 0)] or self.toks[#self.toks] end\nfunction Parser:next() local t = self:peek(); self.i = self.i + 1; return t end\nfunction Parser:err(msg)\n  local t = self:peek()\n  error(self.chunk .. ':' .. t.line .. ': ' .. msg .. \" near '\" .. tostring(t.value) .. \"'\", 0)\nend\nfunction Parser:is(ty, v) local t = self:peek(); return t.type == ty and (v == nil or t.value == v) end\nfunction Parser:isSym(v) return self:is('symbol', v) end\nfunction Parser:isKw(v) return self:is('keyword', v) end\nfunction Parser:accept(ty, v) if self:is(ty, v) then return self:next() end end\nfunction Parser:expect(ty, v) if not self:is(ty, v) then self:err(\"'\" .. tostring(v or ty) .. \"' expected\") end return self:next() end\nfunction Parser:name() if not self:is('name') then self:err('name expected') end return self:next().value end\n\n--  Luau type syntax: parsed and DISCARDED (types are erased at runtime) \n-- Consume a balanced bracketed run open..close (handles nesting of the same\n-- pair). Different bracket kinds inside are ignored, which is fine because Luau\n-- grammar nests them consistently.\nfunction Parser:skipBalanced(open, close)\n  self:expect('symbol', open)\n  local depth = 1\n  while depth > 0 do\n    local t = self:next()\n    if t.type == 'eof' then self:err(\"unterminated '\" .. open .. \"'\") end\n    if t.type == 'symbol' then\n      if t.value == open then depth = depth + 1\n      elseif t.value == close then depth = depth - 1 end\n    end\n  end\nend\n\n-- Angle-bracket generics need special care: the lexer produces `>>` / `>=` as\n-- single tokens, so a closing `>` can be glued to the next one (Foo<Bar<X>>).\nfunction Parser:skipAngles()\n  self:expect('symbol', '<')\n  local depth = 1\n  while depth > 0 do\n    local t = self:next()\n    if t.type == 'eof' then self:err('unterminated generic') end\n    if t.type == 'symbol' then\n      if t.value == '<' then depth = depth + 1\n      elseif t.value == '>' then depth = depth - 1\n      elseif t.value == '>>' then depth = depth - 2\n      elseif t.value == '>=' then depth = depth - 1 end\n    end\n  end\nend\n\n-- A single type \"unit\": name/qualified/generic, table type, function/paren type,\n-- literal type, or variadic. Postfix `?` and binary `| &` and `->` are handled\n-- by skipType.\nfunction Parser:skipTypeUnit()\n  local t = self:peek()\n  if t.type == 'string' then self:next(); return end\n  if t.type == 'number' then self:next(); return end\n  if t.type == 'keyword' and (t.value == 'nil' or t.value == 'true' or t.value == 'false') then\n    self:next(); return\n  end\n  if t.type == 'symbol' and t.value == '...' then self:next(); self:skipTypeUnit(); return end\n  if t.type == 'symbol' and t.value == '{' then self:skipBalanced('{', '}'); return end\n  if t.type == 'symbol' and t.value == '(' then\n    self:skipBalanced('(', ')')\n    if self:isSym('->') then self:next(); self:skipType() end -- function type\n    return\n  end\n  if t.type == 'name' then\n    self:next()\n    while self:isSym('.') do self:next(); self:name() end -- module.Type\n    if self:isSym('(') then self:skipBalanced('(', ')') -- typeof(expr)\n    elseif self:isSym('<') then self:skipAngles() end   -- generic args\n    return\n  end\n  self:err('malformed type annotation')\nend\n\n-- A full type expression (unions/intersections/functions/optionals).\nfunction Parser:skipType()\n  self:skipTypeUnit()\n  while true do\n    if self:isSym('?') then self:next()\n    elseif self:isSym('|') or self:isSym('&') then self:next(); self:skipTypeUnit()\n    elseif self:isSym('->') then self:next(); self:skipTypeUnit()\n    else break end\n  end\nend\n\n-- Optional `: <type>` after a name (local decl, parameter, loop var, return).\nfunction Parser:skipTypeAnnot()\n  if self:accept('symbol', ':') then self:skipType() end\nend\n\n-- Optional generic parameter list `<T, U...>` on a function/type declaration.\nfunction Parser:skipGenerics()\n  if self:isSym('<') then self:skipAngles() end\nend\n\nfunction Parser:parse()\n  local body = self:block()\n  if not self:is('eof') then self:err(\"'<eof>' expected\") end\n  return { k = 'Chunk', body = body }\nend\n\nfunction Parser:block()\n  local stmts = {}\n  while true do\n    local t = self:peek()\n    if t.type == 'eof' then break end\n    if t.type == 'keyword' and BLOCK_END[t.value] then break end\n    if t.type == 'keyword' and t.value == 'return' then stmts[#stmts + 1] = self:retStat(); break end\n    local s = self:statement()\n    if s then stmts[#stmts + 1] = s end\n  end\n  return stmts\nend\n\nfunction Parser:retStat()\n  local line = self:next().line\n  local exprs = {}\n  local t = self:peek()\n  local ends = t.type == 'eof' or (t.type == 'keyword' and BLOCK_END[t.value])\n  if not ends and not self:isSym(';') then exprs = self:exprList() end\n  self:accept('symbol', ';')\n  return { k = 'Return', exprs = exprs, line = line }\nend\n\n-- `continue` is a contextual keyword: only a statement when it stands alone\n-- (followed by a block end or `;`); otherwise it is an ordinary identifier.\nlocal CONT_FOLLOW = { ['end'] = true, ['else'] = true, ['elseif'] = true, ['until'] = true }\nfunction Parser:continueFollows()\n  local nx = self:peek(1)\n  if nx.type == 'eof' then return true end\n  if nx.type == 'symbol' and nx.value == ';' then return true end\n  if nx.type == 'keyword' and CONT_FOLLOW[nx.value] then return true end\n  return false\nend\n\nfunction Parser:statement()\n  local t = self:peek()\n  if t.type == 'symbol' and t.value == ';' then self:next(); return nil end\n  if t.type == 'symbol' and t.value == '::' then\n    self:next(); local nm = self:name(); self:expect('symbol', '::')\n    return { k = 'Label', name = nm, line = t.line }\n  end\n  -- Luau type aliases: `type Name<...> = T` and `export type Name = T` (erased).\n  -- `type`/`export` are ordinary names, so only treat them as aliases when the\n  -- shape matches (a name immediately follows).\n  if t.type == 'name' and t.value == 'type' and self:peek(1).type == 'name' then\n    self:next(); self:name(); self:skipGenerics(); self:expect('symbol', '='); self:skipType()\n    return nil\n  end\n  if t.type == 'name' and t.value == 'export' and self:peek(1).type == 'name'\n      and self:peek(1).value == 'type' and self:peek(2).type == 'name' then\n    self:next(); self:next(); self:name(); self:skipGenerics(); self:expect('symbol', '='); self:skipType()\n    return nil\n  end\n  -- Luau `continue` (contextual)\n  if t.type == 'name' and t.value == 'continue' and self:continueFollows() then\n    self:next(); return { k = 'Continue', line = t.line }\n  end\n  if t.type == 'keyword' then\n    local v = t.value\n    if v == 'break' then self:next(); return { k = 'Break', line = t.line } end\n    if v == 'goto' then self:next(); return { k = 'Goto', label = self:name(), line = t.line } end\n    if v == 'do' then self:next(); local b = self:block(); self:expect('keyword', 'end'); return { k = 'Do', body = b, line = t.line } end\n    if v == 'while' then return self:whileStat() end\n    if v == 'repeat' then return self:repeatStat() end\n    if v == 'if' then return self:ifStat() end\n    if v == 'for' then return self:forStat() end\n    if v == 'function' then return self:funcStat() end\n    if v == 'local' then return self:localStat() end\n  end\n  return self:exprStat()\nend\n\nfunction Parser:whileStat()\n  local line = self:next().line\n  local cond = self:expr(); self:expect('keyword', 'do')\n  local body = self:block(); self:expect('keyword', 'end')\n  return { k = 'While', cond = cond, body = body, line = line }\nend\n\nfunction Parser:repeatStat()\n  local line = self:next().line\n  local body = self:block(); self:expect('keyword', 'until')\n  local cond = self:expr()\n  return { k = 'Repeat', body = body, cond = cond, line = line }\nend\n\nfunction Parser:ifStat()\n  local line = self:next().line\n  local clauses = {}\n  local cond = self:expr(); self:expect('keyword', 'then')\n  clauses[1] = { cond = cond, body = self:block() }\n  while self:isKw('elseif') do\n    self:next(); local c = self:expr(); self:expect('keyword', 'then')\n    clauses[#clauses + 1] = { cond = c, body = self:block() }\n  end\n  local elseBody\n  if self:accept('keyword', 'else') then elseBody = self:block() end\n  self:expect('keyword', 'end')\n  return { k = 'If', clauses = clauses, elseBody = elseBody, line = line }\nend\n\nfunction Parser:forStat()\n  local line = self:next().line\n  local first = self:name()\n  self:skipTypeAnnot() -- loop var type (erased)\n  if self:isSym('=') then\n    self:next()\n    local a = self:expr(); self:expect('symbol', ','); local b = self:expr()\n    local c\n    if self:accept('symbol', ',') then c = self:expr() end\n    self:expect('keyword', 'do'); local body = self:block(); self:expect('keyword', 'end')\n    return { k = 'NumFor', var = first, start = a, stop = b, step = c, body = body, line = line }\n  end\n  local names = { first }\n  while self:accept('symbol', ',') do names[#names + 1] = self:name(); self:skipTypeAnnot() end\n  self:expect('keyword', 'in')\n  local exprs = self:exprList()\n  self:expect('keyword', 'do'); local body = self:block(); self:expect('keyword', 'end')\n  return { k = 'GenFor', names = names, exprs = exprs, body = body, line = line }\nend\n\nfunction Parser:funcStat()\n  local line = self:next().line\n  local base = self:name()\n  local path = {}\n  local method\n  while self:isSym('.') do self:next(); path[#path + 1] = self:name() end\n  if self:accept('symbol', ':') then method = self:name() end\n  local func = self:funcBody(line, method ~= nil)\n  return { k = 'FuncDecl', base = base, path = path, method = method, func = func, line = line }\nend\n\nfunction Parser:localStat()\n  local line = self:next().line\n  if self:accept('keyword', 'function') then\n    local nm = self:name()\n    local func = self:funcBody(line, false)\n    return { k = 'LocalFunc', name = nm, func = func, line = line }\n  end\n  local names = { self:localName() }\n  while self:accept('symbol', ',') do names[#names + 1] = self:localName() end\n  local exprs = {}\n  if self:accept('symbol', '=') then exprs = self:exprList() end\n  return { k = 'Local', names = names, exprs = exprs, line = line }\nend\n\nfunction Parser:localName()\n  local nm = self:name()\n  if self:accept('symbol', '<') then self:name(); self:expect('symbol', '>') end -- attribute, ignored\n  self:skipTypeAnnot() -- variable type annotation (erased)\n  return nm\nend\n\nfunction Parser:funcBody(line, isMethod)\n  self:skipGenerics() -- generic type params <T, U...> (erased)\n  self:expect('symbol', '(')\n  local params, isVararg = {}, false\n  if isMethod then params[1] = 'self' end\n  if not self:isSym(')') then\n    repeat\n      if self:isSym('...') then self:next(); self:skipTypeAnnot(); isVararg = true; break end\n      params[#params + 1] = self:name()\n      self:skipTypeAnnot() -- parameter type (erased)\n    until not self:accept('symbol', ',')\n  end\n  self:expect('symbol', ')')\n  self:skipTypeAnnot() -- return type (erased)\n  local body = self:block(); self:expect('keyword', 'end')\n  return { k = 'Function', params = params, isVararg = isVararg, body = body, line = line }\nend\n\n-- Luau compound assignments desugar to a plain assignment: `t OP= e` becomes\n-- `t = t OP (e)`. Single target only (Luau forbids `a, b += 1`).\nlocal COMPOUND = {\n  ['+='] = '+', ['-='] = '-', ['*='] = '*', ['/='] = '/',\n  ['//='] = '//', ['%='] = '%', ['^='] = '^', ['..='] = '..',\n}\n\n-- Shallow-clone an lvalue node so the desugared RHS references a distinct node\n-- from the assignment target (they share child subtrees, which is fine).\nlocal function cloneLValue(n)\n  local c = {}\n  for k, v in pairs(n) do c[k] = v end\n  return c\nend\n\nfunction Parser:exprStat()\n  local line = self:peek().line\n  local first = self:suffixed()\n  local ct = self:peek()\n  if ct.type == 'symbol' and COMPOUND[ct.value] then\n    if first.k ~= 'Name' and first.k ~= 'Index' and first.k ~= 'Field' then self:err('cannot assign') end\n    local op = COMPOUND[self:next().value]\n    local rhs = self:expr()\n    local sum = { k = 'Binop', op = op, left = cloneLValue(first), right = rhs, line = line }\n    return { k = 'Assign', targets = { first }, exprs = { sum }, line = line }\n  end\n  if self:isSym('=') or self:isSym(',') then\n    local targets = { first }\n    while self:accept('symbol', ',') do targets[#targets + 1] = self:suffixed() end\n    self:expect('symbol', '=')\n    local exprs = self:exprList()\n    for _, tg in ipairs(targets) do\n      if tg.k ~= 'Name' and tg.k ~= 'Index' and tg.k ~= 'Field' then self:err('cannot assign') end\n    end\n    return { k = 'Assign', targets = targets, exprs = exprs, line = line }\n  end\n  if first.k ~= 'CallE' and first.k ~= 'Method' then self:err('syntax error') end\n  return { k = 'CallStat', call = first, line = line }\nend\n\nfunction Parser:exprList()\n  local list = { self:expr() }\n  while self:accept('symbol', ',') do list[#list + 1] = self:expr() end\n  return list\nend\n\nfunction Parser:expr() return self:subExpr(0) end\n\nfunction Parser:getBinop()\n  local t = self:peek()\n  if t.type == 'symbol' and BINPRI[t.value] then return t.value end\n  if t.type == 'keyword' and (t.value == 'and' or t.value == 'or') then return t.value end\nend\nfunction Parser:getUnop()\n  local t = self:peek()\n  if t.type == 'symbol' and (t.value == '-' or t.value == '#' or t.value == '~') then return t.value end\n  if t.type == 'keyword' and t.value == 'not' then return t.value end\nend\n\nfunction Parser:subExpr(limit)\n  local e\n  local u = self:getUnop()\n  if u then\n    local line = self:next().line\n    e = { k = 'Unop', op = u, operand = self:subExpr(UNARY_PRI), line = line }\n  else\n    e = self:simple()\n  end\n  while self:isSym('::') do self:next(); self:skipType() end -- type cast (erased)\n  while true do\n    local op = self:getBinop()\n    if not op or BINPRI[op][1] <= limit then break end\n    local line = self:next().line\n    local right = self:subExpr(BINPRI[op][2])\n    e = { k = 'Binop', op = op, left = e, right = right, line = line }\n  end\n  return e\nend\n\nfunction Parser:simple()\n  local t = self:peek()\n  if t.type == 'number' then self:next(); return { k = 'Number', value = t.value, line = t.line } end\n  if t.type == 'string' then self:next(); return { k = 'String', value = t.value, line = t.line } end\n  if t.type == 'interp' then self:next(); return self:interpExpr(t) end\n  if t.type == 'keyword' then\n    if t.value == 'nil' then self:next(); return { k = 'Nil', line = t.line } end\n    if t.value == 'true' then self:next(); return { k = 'True', line = t.line } end\n    if t.value == 'false' then self:next(); return { k = 'False', line = t.line } end\n    if t.value == 'function' then local l = self:next().line; return self:funcBody(l, false) end\n    if t.value == 'if' then return self:ifExpr() end -- Luau if-then-else expression\n  end\n  if t.type == 'symbol' then\n    if t.value == '...' then self:next(); return { k = 'Vararg', line = t.line } end\n    if t.value == '{' then return self:table() end\n  end\n  return self:suffixed()\nend\n\n-- Luau `if c then a elseif c2 then b else d` as an EXPRESSION (else required).\nfunction Parser:ifExpr()\n  local line = self:next().line\n  local clauses = {}\n  local cond = self:expr(); self:expect('keyword', 'then')\n  clauses[1] = { cond = cond, value = self:expr() }\n  while self:isKw('elseif') do\n    self:next(); local c = self:expr(); self:expect('keyword', 'then')\n    clauses[#clauses + 1] = { cond = c, value = self:expr() }\n  end\n  self:expect('keyword', 'else')\n  local elseValue = self:expr()\n  return { k = 'IfExpr', clauses = clauses, elseValue = elseValue, line = line }\nend\n\n-- Luau string interpolation `a{x}b` -> (\"a\" .. tostring(x) .. \"b\"). Each embedded\n-- expression's source was captured by the lexer and is parsed here.\nfunction Parser:interpExpr(tok)\n  local lits, exprs = tok.literals, tok.exprs\n  local node = { k = 'String', value = lits[1] or '', line = tok.line }\n  for i, esrc in ipairs(exprs) do\n    local inner = Parser.parseExprString(esrc, self.chunk)\n    local ts = { k = 'CallE', func = { k = 'Name', name = 'tostring', line = tok.line },\n      args = { inner }, line = tok.line }\n    node = { k = 'Binop', op = '..', left = node, right = ts, line = tok.line }\n    node = { k = 'Binop', op = '..', left = node,\n      right = { k = 'String', value = lits[i + 1] or '', line = tok.line }, line = tok.line }\n  end\n  return node\nend\n\nfunction Parser:primary()\n  local t = self:peek()\n  if t.type == 'symbol' and t.value == '(' then\n    self:next(); local e = self:expr(); self:expect('symbol', ')')\n    return { k = 'Paren', expr = e, line = t.line }\n  end\n  if t.type == 'name' then self:next(); return { k = 'Name', name = t.value, line = t.line } end\n  self:err('unexpected symbol')\nend\n\nfunction Parser:suffixed()\n  local e = self:primary()\n  while true do\n    local t = self:peek()\n    if t.type == 'symbol' and t.value == '.' then\n      self:next(); e = { k = 'Field', obj = e, name = self:name(), line = t.line }\n    elseif t.type == 'symbol' and t.value == '[' then\n      self:next(); local idx = self:expr(); self:expect('symbol', ']')\n      e = { k = 'Index', obj = e, index = idx, line = t.line }\n    elseif t.type == 'symbol' and t.value == ':' then\n      self:next(); local m = self:name(); local args = self:callArgs()\n      e = { k = 'Method', obj = e, method = m, args = args, line = t.line }\n    elseif (t.type == 'symbol' and (t.value == '(' or t.value == '{')) or t.type == 'string' then\n      e = { k = 'CallE', func = e, args = self:callArgs(), line = t.line }\n    else break end\n  end\n  return e\nend\n\nfunction Parser:callArgs()\n  local t = self:peek()\n  if t.type == 'string' then self:next(); return { { k = 'String', value = t.value, line = t.line } } end\n  if t.type == 'symbol' and t.value == '{' then return { self:table() } end\n  self:expect('symbol', '(')\n  local args = {}\n  if not self:isSym(')') then args = self:exprList() end\n  self:expect('symbol', ')')\n  return args\nend\n\nfunction Parser:table()\n  local line = self:expect('symbol', '{').line\n  local fields = {}\n  while not self:isSym('}') do\n    if self:isSym('[') then\n      self:next(); local key = self:expr(); self:expect('symbol', ']'); self:expect('symbol', '=')\n      fields[#fields + 1] = { kind = 'keyed', key = key, value = self:expr() }\n    elseif self:is('name') and self:peek(1).type == 'symbol' and self:peek(1).value == '=' then\n      local key = self:next().value; self:next()\n      fields[#fields + 1] = { kind = 'named', key = key, value = self:expr() }\n    else\n      fields[#fields + 1] = { kind = 'item', value = self:expr() }\n    end\n    if not self:accept('symbol', ',') and not self:accept('symbol', ';') then break end\n  end\n  self:expect('symbol', '}')\n  return { k = 'Table', fields = fields, line = line }\nend\n\nfunction Parser.parseString(src, chunk)\n  return new(Lexer.tokenize(src, chunk), chunk):parse()\nend\n\n-- Parse a single expression from a source string (used for the embedded\n-- expressions of an interpolated string).\nfunction Parser.parseExprString(src, chunk)\n  local p = new(Lexer.tokenize(src, chunk), chunk)\n  local e = p:expr()\n  if not p:is('eof') then p:err('unexpected token in interpolation expression') end\n  return e\nend\n\nreturn Parser\n","scope":"-- luau-vm/src/scope.lua\n-- Capture analysis. Resolves every Name to its declaration and marks a\n-- declaration `captured` when it is referenced from a nested function. The\n-- compiler uses `captured` to decide whether a local lives in a cell (box) so\n-- closures can share it as an upvalue.\n--\n-- Declaration objects are attached to the AST and reused by the compiler, which\n-- fills in `owner`/`reg` during code generation.\n\nlocal Scope = {}\n\nlocal function newScope(parent, fdepth) return { vars = {}, parent = parent, fdepth = fdepth } end\nlocal function declare(scope, name)\n  local d = { name = name, captured = false, fdepth = scope.fdepth }\n  scope.vars[name] = d\n  return d\nend\nlocal function lookup(scope, name)\n  local s = scope\n  while s do local d = s.vars[name]; if d then return d end; s = s.parent end\n  return nil\nend\n\nlocal rExpr, rStmt, rBlock, rFunc\n\nfunction Scope.analyze(chunk)\n  local top = newScope(nil, 0)\n  for _, s in ipairs(chunk.body) do rStmt(s, top) end\n  return chunk\nend\n\nfunction rBlock(stmts, parent)\n  local scope = newScope(parent, parent.fdepth)\n  for _, s in ipairs(stmts) do rStmt(s, scope) end\nend\n\nfunction rFunc(fn, parent)\n  local scope = newScope(parent, parent.fdepth + 1)\n  fn.paramDecls = {}\n  for i, p in ipairs(fn.params) do fn.paramDecls[i] = declare(scope, p) end\n  for _, s in ipairs(fn.body) do rStmt(s, scope) end\nend\n\nlocal function ref(node, scope)\n  local d = lookup(scope, node.name)\n  if d then\n    node.decl = d\n    if d.fdepth ~= scope.fdepth then d.captured = true end\n  else\n    node.decl = nil -- global\n  end\nend\n\nfunction rExpr(e, scope)\n  local k = e.k\n  if k == 'Name' then ref(e, scope)\n  elseif k == 'Paren' then rExpr(e.expr, scope)\n  elseif k == 'Field' then rExpr(e.obj, scope)\n  elseif k == 'Index' then rExpr(e.obj, scope); rExpr(e.index, scope)\n  elseif k == 'CallE' then rExpr(e.func, scope); for _, a in ipairs(e.args) do rExpr(a, scope) end\n  elseif k == 'Method' then rExpr(e.obj, scope); for _, a in ipairs(e.args) do rExpr(a, scope) end\n  elseif k == 'Binop' then rExpr(e.left, scope); rExpr(e.right, scope)\n  elseif k == 'IfExpr' then\n    for _, c in ipairs(e.clauses) do rExpr(c.cond, scope); rExpr(c.value, scope) end\n    rExpr(e.elseValue, scope)\n  elseif k == 'Unop' then rExpr(e.operand, scope)\n  elseif k == 'Function' then rFunc(e, scope)\n  elseif k == 'Table' then\n    for _, f in ipairs(e.fields) do\n      if f.kind == 'keyed' then rExpr(f.key, scope) end\n      rExpr(f.value, scope)\n    end\n  end\nend\n\nfunction rStmt(s, scope)\n  local k = s.k\n  if k == 'Local' then\n    for _, e in ipairs(s.exprs) do rExpr(e, scope) end\n    s.decls = {}\n    for i, nm in ipairs(s.names) do s.decls[i] = declare(scope, nm) end\n  elseif k == 'Assign' then\n    for _, t in ipairs(s.targets) do rExpr(t, scope) end\n    for _, e in ipairs(s.exprs) do rExpr(e, scope) end\n  elseif k == 'CallStat' then rExpr(s.call, scope)\n  elseif k == 'Do' then rBlock(s.body, scope)\n  elseif k == 'While' then rExpr(s.cond, scope); rBlock(s.body, scope)\n  elseif k == 'Repeat' then\n    local inner = newScope(scope, scope.fdepth)\n    for _, st in ipairs(s.body) do rStmt(st, inner) end\n    rExpr(s.cond, inner)\n  elseif k == 'If' then\n    for _, c in ipairs(s.clauses) do rExpr(c.cond, scope); rBlock(c.body, scope) end\n    if s.elseBody then rBlock(s.elseBody, scope) end\n  elseif k == 'NumFor' then\n    rExpr(s.start, scope); rExpr(s.stop, scope); if s.step then rExpr(s.step, scope) end\n    local inner = newScope(scope, scope.fdepth)\n    s.varDecl = declare(inner, s.var)\n    for _, st in ipairs(s.body) do rStmt(st, inner) end\n  elseif k == 'GenFor' then\n    for _, e in ipairs(s.exprs) do rExpr(e, scope) end\n    local inner = newScope(scope, scope.fdepth)\n    s.decls = {}\n    for i, nm in ipairs(s.names) do s.decls[i] = declare(inner, nm) end\n    for _, st in ipairs(s.body) do rStmt(st, inner) end\n  elseif k == 'FuncDecl' then\n    -- base is a reference (assignment target); resolve it\n    local nameNode = { k = 'Name', name = s.base, line = s.line }\n    ref(nameNode, scope)\n    s.baseDecl = nameNode.decl\n    rFunc(s.func, scope)\n  elseif k == 'LocalFunc' then\n    s.decl = declare(scope, s.name) -- visible in its own body (recursion)\n    rFunc(s.func, scope)\n  elseif k == 'Return' then\n    for _, e in ipairs(s.exprs) do rExpr(e, scope) end\n  end\n  -- Break / Goto / Label: nothing\nend\n\nreturn Scope\n","optimizer":"-- luau-vm/src/optimizer.lua\n-- AST + bytecode optimization passes. Every pass is semantics-preserving AND\n-- runtime-neutral: we only fold operations whose result has the same observable\n-- value/representation on Lua 5.4 and Luau. Notably `/` and `^` are NOT folded\n-- (they float on 5.4 but Luau prints them without `.0`), and bitwise/comparison\n-- folds are skipped for the same reason.\n\nlocal Opcodes = require('opcodes')\nlocal Op = Opcodes.Op\n\nlocal Optimizer = {}\n\n--  AST: constant folding + dead-code elimination \nlocal function isIntLit(e)\n  if e.k ~= 'Number' then return nil end\n  local v = tonumber(e.value)\n  if v == nil then return nil end\n  if v ~= math.floor(v) then return nil end\n  if e.value:find('[%.eExXpP]') then return nil end -- keep hex/float text as-is\n  return v\nend\n\nlocal FOLD = {\n  ['+'] = function(a, b) return a + b end,\n  ['-'] = function(a, b) return a - b end,\n  ['*'] = function(a, b) return a * b end,\n}\n\nlocal foldExpr\n\nlocal function foldChildren(e)\n  if e.left then e.left = foldExpr(e.left) end\n  if e.right then e.right = foldExpr(e.right) end\n  if e.operand then e.operand = foldExpr(e.operand) end\n  if e.obj then e.obj = foldExpr(e.obj) end\n  if e.index then e.index = foldExpr(e.index) end\n  if e.expr then e.expr = foldExpr(e.expr) end\n  if e.func then e.func = foldExpr(e.func) end\n  if e.args then for i, a in ipairs(e.args) do e.args[i] = foldExpr(a) end end\n  if e.fields then\n    for _, f in ipairs(e.fields) do\n      if f.key and type(f.key) == 'table' then f.key = foldExpr(f.key) end\n      f.value = foldExpr(f.value)\n    end\n  end\n  if e.body then Optimizer.foldBlock(e.body) end\n  return e\nend\n\nfoldExpr = function(e)\n  foldChildren(e)\n  if e.k == 'Binop' then\n    local la, lb = isIntLit(e.left), isIntLit(e.right)\n    if la ~= nil and lb ~= nil and FOLD[e.op] then\n      local v = FOLD[e.op](la, lb)\n      return { k = 'Number', value = tostring(v), line = e.line }\n    end\n    -- literal concat of strings/ints is representation-stable\n    if e.op == '..' then\n      local function litStr(n)\n        if n.k == 'String' then return n.value end\n        if n.k == 'Number' then local iv = isIntLit(n); if iv ~= nil then return tostring(iv) end end\n        return nil\n      end\n      local a, b = litStr(e.left), litStr(e.right)\n      if a ~= nil and b ~= nil then return { k = 'String', value = a .. b, line = e.line } end\n    end\n  elseif e.k == 'Unop' and e.op == '-' then\n    local v = isIntLit(e.operand)\n    if v ~= nil then return { k = 'Number', value = tostring(-v), line = e.line } end\n  end\n  return e\nend\n\nfunction Optimizer.foldBlock(stmts)\n  local cut = nil\n  for i, s in ipairs(stmts) do\n    -- fold expressions inside the statement\n    if s.exprs then for j, e in ipairs(s.exprs) do s.exprs[j] = foldExpr(e) end end\n    if s.targets then for j, e in ipairs(s.targets) do s.targets[j] = foldExpr(e) end end\n    if s.cond then s.cond = foldExpr(s.cond) end\n    if s.call then s.call = foldExpr(s.call) end\n    if s.start then s.start = foldExpr(s.start) end\n    if s.stop then s.stop = foldExpr(s.stop) end\n    if s.step then s.step = foldExpr(s.step) end\n    if s.value then s.value = foldExpr(s.value) end\n    if s.func then foldExpr(s.func) end\n    if s.body then Optimizer.foldBlock(s.body) end\n    if s.elseBody then Optimizer.foldBlock(s.elseBody) end\n    if s.clauses then\n      for _, c in ipairs(s.clauses) do c.cond = foldExpr(c.cond); Optimizer.foldBlock(c.body) end\n    end\n    -- dead-code elimination: statements after an unconditional exit are removed\n    if (s.k == 'Return' or s.k == 'Break') and cut == nil then cut = i end\n  end\n  if cut then for i = #stmts, cut + 1, -1 do stmts[i] = nil end end\nend\n\nfunction Optimizer.optimizeAST(chunk)\n  Optimizer.foldBlock(chunk.body)\n  return chunk\nend\n\n--  bytecode peephole \n-- Only these opcodes use sbx as a relative jump offset (LOADINT's sbx is an\n-- immediate value and must never be retargeted).\nlocal JUMP = {\n  [Op.JMP] = true, [Op.JMPIF] = true, [Op.JMPIFNOT] = true,\n  [Op.FORPREP] = true, [Op.FORLOOP] = true, [Op.TFORLOOP] = true,\n}\n\nlocal function isDroppable(ins)\n  return (ins.op == Op.NOP) or (ins.op == Op.MOVE and ins.a == ins.b)\nend\n\n-- Remove NOPs and self-moves, remapping jump targets so control flow is kept.\nfunction Optimizer.peephole(proto)\n  for _, child in ipairs(proto.protos) do Optimizer.peephole(child) end\n  local code = proto.code\n  -- capture absolute jump targets before removal\n  local absTarget = {}\n  for i, ins in ipairs(code) do\n    if JUMP[ins.op] then absTarget[i] = i + 1 + ins.sbx end\n  end\n  -- map every old index (1..#code+1) to the new index it lands on\n  local newOf, kept, keepOldIndex = {}, {}, {}\n  for i, ins in ipairs(code) do\n    if isDroppable(ins) then\n      newOf[i] = #kept + 1 -- redirect to the next kept instruction\n    else\n      kept[#kept + 1] = ins\n      keepOldIndex[#kept] = i\n      newOf[i] = #kept\n    end\n  end\n  newOf[#code + 1] = #kept + 1\n  -- recompute sbx for kept jumps\n  for newPc, ins in ipairs(kept) do\n    if JUMP[ins.op] then\n      local oldIdx = keepOldIndex[newPc]\n      local newTarget = newOf[absTarget[oldIdx]]\n      ins.sbx = newTarget - (newPc + 1)\n    end\n  end\n  proto.code = kept\n  return proto\nend\n\nreturn Optimizer\n","obfuscate":"-- luau-vm/src/obfuscate.lua\n-- Source-level (AST) control-flow obfuscation: opaque-predicate injection.\n--\n-- This pass runs on the parsed + constant-folded AST, BEFORE scope analysis and\n-- code generation, so the compiler performs all register allocation and jump\n-- generation for the injected code exactly as it would for hand-written Lua.\n-- That is what makes it safe: we never touch the bytecode's register/`top`\n-- bookkeeping directly (where a stray write could clobber a live call frame) \n-- we only add ordinary, valid Lua statements and let the compiler lower them.\n--\n-- What it injects:\n--   * One \"seed\" local per function/chunk:  local <s> = #\"<random>\"\n--     `#literal` is a non-negative integer the optimizer does not fold, and once\n--     the string constants are encrypted at runtime (see seal.lua) its value is\n--     not visible to a static reader without running the decryptor.\n--   * Bogus `if` statements guarded by OPAQUE PREDICATES over that seed:\n--       - always-TRUE   `(s % A) <= (A-1)`   (A>=1, so s%A is in [0,A-1])\n--       - always-FALSE  `(s % A) == A`       (never equal to A)\n--     For any integer s and A>0 Lua/Luau guarantee  s % A  in [0, A-1], so the\n--     predicate's truth value is fixed regardless of the seed's actual value \n--     yet a naive static analyzer cannot fold it away.\n--\n-- Every injected branch body contains ONLY self-contained junk (fresh\n-- block-scoped locals, plus reads/dead-writes of the seed). It never wraps or\n-- reorders real statements, so the scoping and semantics of the user's code are\n-- untouched: the always-true bodies have no observable effect, and the\n-- always-false bodies never execute. Result: extra, plausible control-flow\n-- edges in the recovered bytecode without any behavioural change.\n\nlocal M = {}\n\n--  tiny AST builders \nlocal L = 0\nlocal function name(n) return { k = 'Name', name = n, line = L } end\nlocal function num(v) return { k = 'Number', value = tostring(v), line = L } end\nlocal function str(s) return { k = 'String', value = s, line = L } end\nlocal function bin(op, a, b) return { k = 'Binop', op = op, left = a, right = b, line = L } end\nlocal function len(e) return { k = 'Unop', op = '#', operand = e, line = L } end\nlocal function localStmt(nm, expr) return { k = 'Local', names = { nm }, exprs = { expr }, line = L } end\nlocal function assign(nm, expr) return { k = 'Assign', targets = { name(nm) }, exprs = { expr }, line = L } end\nlocal function ifStmt(cond, body) return { k = 'If', clauses = { { cond = cond, body = body } }, elseBody = nil, line = L } end\n\n--  per-build identifier generator (leading `_` + lowercase/digits => never a\n-- keyword or stdlib global; long enough that collision with a user local is\n-- negligible) \nlocal function idGen(rng)\n  local pool = 'abcdefghijklmnopqrstuvwxyz0123456789'\n  local used = {}\n  return function()\n    while true do\n      local s = '_'\n      for _ = 1, 8 do local d = rng.int(#pool); s = s .. pool:sub(d + 1, d + 1) end\n      if not used[s] then used[s] = true; return s end\n    end\n  end\nend\n\nlocal function randString(rng)\n  local pool = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'\n  local n = rng.int(12) + 4\n  local t = {}\n  for i = 1, n do local d = rng.int(#pool); t[i] = pool:sub(d + 1, d + 1) end\n  return table.concat(t)\nend\n\n-- A junk expression over the seed name and integer literals (no side effects).\nlocal function junkExpr(seed, rng)\n  local e = name(seed)\n  for _ = 1, rng.int(2) + 1 do\n    local op = ({ '+', '-', '%', '*' })[rng.int(4) + 1]\n    local k = (op == '%') and (rng.int(97) + 3) or (rng.int(50) + 1)\n    e = bin(op, e, num(k))\n  end\n  return e\nend\n\n-- Junk body statements. `live` = true when the branch actually executes\n-- (always-true): only fresh block-scoped locals, so there is no observable\n-- effect. `live` = false (always-false): may also \"mutate\" the seed for extra\n-- confusion, since the body never runs.\nlocal function junkBody(seed, g, rng, live)\n  local body = {}\n  local m = rng.int(2) + 1\n  for _ = 1, m do body[#body + 1] = localStmt(g(), junkExpr(seed, rng)) end\n  if not live and rng.int(2) == 0 then\n    body[#body + 1] = assign(seed, junkExpr(seed, rng))\n  end\n  return body\nend\n\n-- Build one opaque `if`. Alternates between always-true and always-false forms.\nlocal function opaqueIf(seed, g, rng)\n  local A = rng.int(23) + 2                 -- divisor >= 2\n  local modExpr = bin('%', name(seed), num(A))\n  if rng.int(2) == 0 then\n    -- always TRUE:  (seed % A) <= (A-1)    body runs, but is inert\n    return ifStmt(bin('<=', modExpr, num(A - 1)), junkBody(seed, g, rng, true))\n  else\n    -- always FALSE: (seed % A) == A        body is dead\n    return ifStmt(bin('==', modExpr, num(A)), junkBody(seed, g, rng, false))\n  end\nend\n\n--  AST walk \nlocal injectBlock, injectFunc, walkExprForFuncs\n\n-- Recurse into any Function nodes reachable from an expression, treating each as\n-- a fresh function (its own seed).\nwalkExprForFuncs = function(e, g, rng, density)\n  if type(e) ~= 'table' then return end\n  if e.k == 'Function' then injectFunc(e, g, rng, density); return end\n  -- generic child traversal (covers Binop/Unop/Paren/Field/Index/Call/Method/Table)\n  if e.left then walkExprForFuncs(e.left, g, rng, density) end\n  if e.right then walkExprForFuncs(e.right, g, rng, density) end\n  if e.operand then walkExprForFuncs(e.operand, g, rng, density) end\n  if e.expr then walkExprForFuncs(e.expr, g, rng, density) end\n  if e.obj then walkExprForFuncs(e.obj, g, rng, density) end\n  if e.index then walkExprForFuncs(e.index, g, rng, density) end\n  if e.func then walkExprForFuncs(e.func, g, rng, density) end\n  if e.args then for _, a in ipairs(e.args) do walkExprForFuncs(a, g, rng, density) end end\n  if e.fields then\n    for _, f in ipairs(e.fields) do\n      if f.key and type(f.key) == 'table' then walkExprForFuncs(f.key, g, rng, density) end\n      walkExprForFuncs(f.value, g, rng, density)\n    end\n  end\nend\n\n-- Recurse into nested blocks/functions inside a single statement (same seed for\n-- same-function blocks; a new seed for nested functions).\nlocal function walkStmt(s, seed, g, rng, density)\n  local k = s.k\n  -- expressions that may contain function literals\n  if s.exprs then for _, e in ipairs(s.exprs) do walkExprForFuncs(e, g, rng, density) end end\n  if s.targets then for _, e in ipairs(s.targets) do walkExprForFuncs(e, g, rng, density) end end\n  if s.call then walkExprForFuncs(s.call, g, rng, density) end\n  if s.cond then walkExprForFuncs(s.cond, g, rng, density) end\n  if s.start then walkExprForFuncs(s.start, g, rng, density) end\n  if s.stop then walkExprForFuncs(s.stop, g, rng, density) end\n  if s.step then walkExprForFuncs(s.step, g, rng, density) end\n  -- nested blocks in the SAME function share the enclosing seed\n  if k == 'Do' then injectBlock(s.body, seed, g, rng, density, false)\n  elseif k == 'While' then injectBlock(s.body, seed, g, rng, density, false)\n  elseif k == 'Repeat' then injectBlock(s.body, seed, g, rng, density, false); walkExprForFuncs(s.cond, g, rng, density)\n  elseif k == 'NumFor' then injectBlock(s.body, seed, g, rng, density, false)\n  elseif k == 'GenFor' then injectBlock(s.body, seed, g, rng, density, false)\n  elseif k == 'If' then\n    for _, c in ipairs(s.clauses) do\n      walkExprForFuncs(c.cond, g, rng, density)\n      injectBlock(c.body, seed, g, rng, density, false)\n    end\n    if s.elseBody then injectBlock(s.elseBody, seed, g, rng, density, false) end\n  elseif k == 'LocalFunc' then injectFunc(s.func, g, rng, density)\n  elseif k == 'FuncDecl' then injectFunc(s.func, g, rng, density)\n  end\nend\n\n-- Transform a block (list of statements). `isFuncTop` => declare a fresh seed at\n-- the top and use it for this block and its same-function descendants.\ninjectBlock = function(stmts, seed, g, rng, density, isFuncTop)\n  if isFuncTop then\n    seed = g()\n  end\n  -- recurse first (so nested functions/blocks get their own treatment)\n  for _, s in ipairs(stmts) do walkStmt(s, seed, g, rng, density) end\n\n  -- then splice opaque ifs BEFORE randomly chosen statements (never after a\n  -- trailing return/break: inserting before a statement can't create\n  -- unreachable code, and we simply don't append past the last statement).\n  if seed then\n    local out = {}\n    for _, s in ipairs(stmts) do\n      if rng.int(1000) < density then out[#out + 1] = opaqueIf(seed, g, rng) end\n      out[#out + 1] = s\n    end\n    -- rewrite stmts in place\n    for i = #stmts, 1, -1 do stmts[i] = nil end\n    for i, s in ipairs(out) do stmts[i] = s end\n    if isFuncTop then\n      table.insert(stmts, 1, localStmt(seed, len(str(randString(rng)))))\n    end\n  end\nend\n\ninjectFunc = function(fn, g, rng, density)\n  injectBlock(fn.body, nil, g, rng, density, true)\nend\n\n--  bytecode junk: provably-unreachable dead opcodes \n-- Inserts well-formed but UNREACHABLE instructions into a compiled proto's code,\n-- so a linear-sweep disassembler decodes filler that never runs. Junk is only\n-- placed immediately after an UNCONDITIONAL transfer (RETURN / TAILCALL / JMP),\n-- which never falls through, so the inserted run can only be reached by a jump \n-- and every jump is relocated to land on its real (shifted) target, never on\n-- junk. Because it never executes, its operands are irrelevant to behaviour; we\n-- still keep them in range so the structural validator accepts the stream.\nlocal Opcodes = require('opcodes')\nlocal Op = Opcodes.Op\n\n-- relative-jump opcodes whose sbx must be relocated after insertion\nlocal JUMP = {\n  [Op.JMP] = true, [Op.JMPIF] = true, [Op.JMPIFNOT] = true,\n  [Op.FORPREP] = true, [Op.FORLOOP] = true, [Op.TFORLOOP] = true,\n}\n-- opcodes that never fall through => safe to append unreachable junk after\nlocal TRANSFER = { [Op.RETURN] = true, [Op.TAILCALL] = true, [Op.JMP] = true }\n\n-- Build one junk instruction using only register/immediate operands within the\n-- proto's maxstack (the validator allows register indices in [0, maxstack]).\nlocal function junkIns(maxstack, rng)\n  local rmax = maxstack -- validator permits up to maxstack inclusive\n  local function reg() return rng.int(rmax + 1) end\n  local pick = rng.int(7)\n  if pick == 0 then return { op = Op.MOVE, a = reg(), b = reg() }\n  elseif pick == 1 then return { op = Op.LOADINT, a = reg(), sbx = rng.int(4096) }\n  elseif pick == 2 then return { op = Op.ADD, a = reg(), b = reg(), c = reg() }\n  elseif pick == 3 then return { op = Op.SUB, a = reg(), b = reg(), c = reg() }\n  elseif pick == 4 then return { op = Op.MUL, a = reg(), b = reg(), c = reg() }\n  elseif pick == 5 then return { op = Op.LOADBOOL, a = reg(), b = rng.int(2) }\n  else return { op = Op.NEWTABLE, a = reg() }\n  end\nend\n\nlocal function junkProto(proto, rng, density, maxRun)\n  local code = proto.code\n  local ncode = #code\n  -- absolute jump targets in OLD indexing\n  local absTarget = {}\n  for i, ins in ipairs(code) do\n    if JUMP[ins.op] then absTarget[i] = i + 1 + ins.sbx end\n  end\n  local newCode, newOf = {}, {}\n  for i = 1, ncode do\n    local ins = code[i]\n    newCode[#newCode + 1] = ins\n    newOf[i] = #newCode\n    if TRANSFER[ins.op] and rng.int(1000) < density then\n      local run = rng.int(maxRun) + 1\n      for _ = 1, run do newCode[#newCode + 1] = junkIns(proto.maxstack, rng) end\n    end\n  end\n  newOf[ncode + 1] = #newCode + 1\n  -- relocate every real jump to its shifted target (never a junk slot). The\n  -- jump instruction tables are the same refs in newCode, so patch via old idx.\n  for oldI, ins in ipairs(code) do\n    if JUMP[ins.op] then\n      local tgt = absTarget[oldI]\n      local newTarget = newOf[tgt] or (#newCode + 1)\n      ins.sbx = newTarget - (newOf[oldI] + 1)\n    end\n  end\n  proto.code = newCode\n  for _, child in ipairs(proto.protos) do junkProto(child, rng, density, maxRun) end\nend\n\nfunction M.junk(proto, rng, opts)\n  opts = opts or {}\n  junkProto(proto, rng, opts.density or 700, opts.maxRun or 3)\n  return proto\nend\n\n--  basic-block reordering (a safe, semantics-EXACT relative of control-flow\n-- flattening) \n-- Splits a proto's code into basic blocks, shuffles their physical order\n-- (pinning the entry block first so execution still starts correctly), and\n-- threads the original fall-through edges with explicit jumps. Every instruction\n-- still executes in the exact same runtime order  only the LAYOUT changes  so\n-- there is no register/`top` liveness hazard at all. The payoff is the same as a\n-- dispatcher: the linear byte order no longer matches control flow, so a reader\n-- must reconstruct the CFG instead of reading top-to-bottom.\n--\n-- Opcodes that DO NOT fall through to the next instruction (so a reordered block\n-- ending in one needs no threading jump).\nlocal NOFALL = { [Op.JMP] = true, [Op.RETURN] = true, [Op.TAILCALL] = true, [Op.FORPREP] = true }\n\nlocal function flattenProto(proto, rng)\n  local code = proto.code\n  local ncode = #code\n  if ncode < 4 then\n    for _, child in ipairs(proto.protos) do flattenProto(child, rng) end\n    return\n  end\n\n  -- 1. leaders: instruction 1, every jump target, and the instruction after any\n  --    control-transfer (so blocks break at all CFG edges).\n  local absTarget = {}\n  local leader = { [1] = true }\n  for i, ins in ipairs(code) do\n    if JUMP[ins.op] then\n      local t = i + 1 + ins.sbx\n      absTarget[i] = t\n      leader[t] = true\n      if i + 1 <= ncode then leader[i + 1] = true end\n    elseif ins.op == Op.RETURN or ins.op == Op.TAILCALL then\n      if i + 1 <= ncode then leader[i + 1] = true end\n    end\n  end\n\n  -- 2. slice into blocks [start..end]; map each instruction index to its block.\n  local starts = {}\n  for i = 1, ncode do if leader[i] then starts[#starts + 1] = i end end\n  local blocks, blockOf = {}, {}\n  for bi, s in ipairs(starts) do\n    local e = (starts[bi + 1] or (ncode + 1)) - 1\n    blocks[bi] = { first = s, last = e }\n    for j = s, e do blockOf[j] = bi end\n  end\n\n  -- fall-through successor block (nil when the block's last instr can't fall\n  -- through, or there is no following instruction).\n  for _, b in ipairs(blocks) do\n    local lastOp = code[b.last].op\n    if not NOFALL[lastOp] and b.last + 1 <= ncode then\n      b.fall = blockOf[b.last + 1]\n    end\n  end\n\n  -- 3. new order: entry block pinned first, the rest shuffled (Fisher-Yates).\n  local order = {}\n  for bi = 2, #blocks do order[#order + 1] = bi end\n  for i = #order, 2, -1 do\n    local j = rng.int(i) + 1\n    order[i], order[j] = order[j], order[i]\n  end\n  table.insert(order, 1, 1)\n\n  -- 4. emit instructions in the new block order; after any block with a\n  --    fall-through successor, append a threading JMP (target = successor.first).\n  --    Track each emitted slot so we can recompute offsets against new indices.\n  local newCode, slotOldIdx, slotJmpTo = {}, {}, {}\n  local newIndexOf = {} -- old instruction index -> new position\n  for _, bi in ipairs(order) do\n    local b = blocks[bi]\n    for j = b.first, b.last do\n      newCode[#newCode + 1] = code[j]\n      newIndexOf[j] = #newCode\n      slotOldIdx[#newCode] = j\n    end\n    if b.fall then\n      newCode[#newCode + 1] = { op = Op.JMP, sbx = 0 }\n      slotJmpTo[#newCode] = blocks[b.fall].first -- target as an OLD index\n    end\n  end\n  newIndexOf[ncode + 1] = #newCode + 1\n\n  -- 5. recompute sbx: original jumps against their mapped target, threading jumps\n  --    against their successor's mapped first instruction.\n  for pos, ins in ipairs(newCode) do\n    local oldI = slotOldIdx[pos]\n    if oldI and JUMP[ins.op] then\n      ins.sbx = newIndexOf[absTarget[oldI]] - (pos + 1)\n    elseif slotJmpTo[pos] then\n      ins.sbx = newIndexOf[slotJmpTo[pos]] - (pos + 1)\n    end\n  end\n\n  proto.code = newCode\n  for _, child in ipairs(proto.protos) do flattenProto(child, rng) end\nend\n\nfunction M.flatten(proto, rng)\n  flattenProto(proto, rng)\n  return proto\nend\n\n-- Public: inject opaque predicates into a parsed chunk. `rng` is a Harden.prng\n-- (has :int(n)); `opts.density` is the per-statement injection chance in\n-- thousandths (default 350 = ~35%).\nfunction M.inject(chunk, rng, opts)\n  opts = opts or {}\n  local density = opts.density or 350\n  local g = idGen(rng)\n  injectBlock(chunk.body, nil, g, rng, density, true)\n  return chunk\nend\n\nreturn M\n","compiler":"-- luau-vm/src/compiler.lua\n-- Lowers the AST into register-based bytecode protos.\n--\n-- Register model: a function's locals occupy the low registers; expression\n-- temporaries are allocated above `freereg` and freed by restoring it. Captured\n-- locals (scope.captured) are boxed with NEWCELL and accessed via GETCELL/SETCELL\n-- so closures can share them as upvalues.\n--\n-- Multi-value positions (last of a call-arg / return / local-init / assignment\n-- list) use the count convention from opcodes.lua (0 = \"to top\").\n\nlocal Parser = require('parser')\nlocal Scope = require('scope')\nlocal Opcodes = require('opcodes')\nlocal Op = Opcodes.Op\n\nlocal Compiler = {}\n\nlocal function isMultiExpr(e) return e.k == 'CallE' or e.k == 'Method' or e.k == 'Vararg' end\n\n-- '...' is only valid inside a vararg function (Lua/Luau reject it otherwise).\nlocal function assertVararg(fs, line)\n  if not fs.proto.isVararg then\n    error(\"ferret-vm: cannot use '...' outside a vararg function (line \" .. tostring(line) .. ')')\n  end\nend\n\n--  function state \nlocal FS = {}\nFS.__index = FS\n\nlocal function newFS(parent, isVararg)\n  return setmetatable({\n    parent = parent,\n    proto = { code = {}, consts = {}, protos = {}, upvals = {}, lines = {}, numparams = 0, isVararg = isVararg, maxstack = 2 },\n    freereg = 0,\n    constMap = {},\n    upvalMap = {},   -- decl -> upvalue index\n    loops = {},      -- stack of { breaks = {} }\n    lines = {},\n  }, FS)\nend\n\nfunction FS:emit(ins, line)\n  local code = self.proto.code\n  code[#code + 1] = ins\n  self.proto.lines[#code] = line\n  return #code\nend\nfunction FS:here() return #self.proto.code + 1 end -- index the NEXT emitted instruction will get\nfunction FS:patch(j, target)\n  self.proto.code[j].sbx = target - (j + 1)\nend\nfunction FS:reserve(n)\n  self.freereg = self.freereg + n\n  if self.freereg > self.proto.maxstack then self.proto.maxstack = self.freereg end\nend\n\nfunction FS:const(v)\n  local key = type(v) .. '\\0' .. tostring(v)\n  local idx = self.constMap[key]\n  if idx then return idx end\n  local consts = self.proto.consts\n  consts[#consts + 1] = v\n  idx = #consts\n  self.constMap[key] = idx\n  return idx\nend\n\n-- resolve a decl declared in an enclosing function to an upvalue index here.\nfunction FS:upval(decl)\n  local cached = self.upvalMap[decl]\n  if cached then return cached end\n  local parent = self.parent\n  local desc\n  if decl.owner == parent then\n    desc = { kind = 'reg', index = decl.reg }\n  else\n    desc = { kind = 'up', index = parent:upval(decl) }\n  end\n  local ups = self.proto.upvals\n  ups[#ups + 1] = desc\n  local idx = #ups\n  self.upvalMap[decl] = idx\n  return idx\nend\n\n--  expression compilation \nlocal compileExpr, compileExprInto, compileStmt, compileBlock, compileFunc\n\n-- Return a register holding a non-cell local's value directly, else nil.\nlocal function localReg(fs, node)\n  if node.k == 'Name' and node.decl and node.decl.owner == fs and not node.decl.captured then\n    return node.decl.reg\n  end\n  return nil\nend\n\n-- Compile into a freshly reserved register at the top; return it.\nlocal function exprNext(fs, node)\n  local r = fs.freereg\n  fs:reserve(1)\n  compileExprInto(fs, node, r)\n  return r\nend\n\n-- Register holding node's value: a local reg (no copy) or a fresh temp.\nlocal function exprAny(fs, node)\n  local lr = localReg(fs, node)\n  if lr then return lr end\n  return exprNext(fs, node)\nend\n\n-- Compile a call (CallE/Method). Places results at `base`; nresults=-1 => multi.\nlocal function compileCall(fs, node, base, nresults, line)\n  if node.k == 'Method' then\n    -- SELF: R[base+1]=obj, R[base]=obj[method]\n    local robj = exprAny(fs, node.obj)\n    fs.freereg = base\n    fs:reserve(2)\n    fs:emit({ op = Op.SELF, a = base, b = robj, c = fs:const(node.method) }, line)\n    local argBase = base + 2\n    fs.freereg = argBase\n    local b = fs:explistOpen(node.args, argBase) -- args after self\n    -- total args = self + nargs; adjust B (b is count field for args-after-self)\n    local B\n    if b == 0 then B = 0 else B = (b - 1) + 1 + 1 end -- (nargs) + self + 1\n    fs:emit({ op = Op.CALL, a = base, b = B, c = (nresults == -1) and 0 or (nresults + 1) }, line)\n  else\n    fs.freereg = base\n    local rfn = base\n    fs:reserve(1)\n    compileExprInto(fs, node.func, rfn)\n    local b = fs:explistOpen(node.args, base + 1)\n    fs:emit({ op = Op.CALL, a = base, b = b, c = (nresults == -1) and 0 or (nresults + 1) }, line)\n  end\n  fs.freereg = base + math.max(nresults, 0)\nend\n\n-- Compile a list of exprs into consecutive regs from `base`.\n-- Returns the CALL/RETURN \"count\" field: exact = n+1, or 0 (multi, to top).\nfunction FS:explistOpen(exprs, base)\n  local n = #exprs\n  self.freereg = base\n  if n == 0 then return 1 end\n  for i = 1, n - 1 do\n    local r = base + i - 1\n    self.freereg = r\n    self:reserve(1)\n    compileExprInto(self, exprs[i], r)\n  end\n  local last = exprs[n]\n  local lastReg = base + n - 1\n  if isMultiExpr(last) then\n    self.freereg = lastReg\n    if last.k == 'Vararg' then\n      assertVararg(self, last.line)\n      self:reserve(1)\n      self:emit({ op = Op.VARARG, a = lastReg, b = 0 }, last.line)\n    else\n      compileCall(self, last, lastReg, -1, last.line)\n    end\n    return 0\n  else\n    self.freereg = lastReg\n    self:reserve(1)\n    compileExprInto(self, last, lastReg)\n    return n + 1\n  end\nend\n\n-- Compile `exprs` so EXACTLY `want` values land in base..base+want-1. A trailing\n-- call/vararg is closed to the exact number still needed (so a call returning\n-- fewer values nil-fills the rest, instead of leaving stale registers), and any\n-- shortfall is padded with nil. Used by local-decl and multi-assign, which  unlike\n-- return/call-args  need a fixed value count regardless of what the RHS produces.\nfunction FS:explistExact(exprs, base, want)\n  local n = #exprs\n  self.freereg = base\n  if n == 0 then\n    for i = 0, want - 1 do self:emit({ op = Op.LOADNIL, a = base + i, b = 0 }) end\n  else\n    for i = 1, n - 1 do -- all but the last: one value each (evaluated for effect even if beyond want)\n      local r = base + i - 1\n      self.freereg = r; self:reserve(1)\n      compileExprInto(self, exprs[i], r)\n    end\n    local last = exprs[n]\n    local lastReg = base + n - 1\n    local remaining = want - (n - 1) -- values the last expr must supply\n    if isMultiExpr(last) then\n      local req = remaining >= 1 and remaining or 1 -- evaluate even when discarded (side effects)\n      self.freereg = lastReg; self:reserve(req)\n      if last.k == 'Vararg' then\n        assertVararg(self, last.line)\n        self:emit({ op = Op.VARARG, a = lastReg, b = req + 1 }, last.line)\n      else\n        compileCall(self, last, lastReg, req, last.line)\n      end\n    else\n      self.freereg = lastReg; self:reserve(1)\n      compileExprInto(self, last, lastReg)\n      for i = 1, remaining - 1 do -- want > #exprs: pad the extra targets with nil\n        self:emit({ op = Op.LOADNIL, a = lastReg + i, b = 0 }, last.line)\n      end\n    end\n  end\n  self.freereg = base + want\n  if self.freereg > self.proto.maxstack then self.proto.maxstack = self.freereg end\nend\n\nlocal BINOP = {\n  ['+'] = Op.ADD, ['-'] = Op.SUB, ['*'] = Op.MUL, ['/'] = Op.DIV, ['%'] = Op.MOD,\n  ['^'] = Op.POW, ['//'] = Op.IDIV, ['&'] = Op.BAND, ['|'] = Op.BOR, ['~'] = Op.BXOR,\n  ['<<'] = Op.SHL, ['>>'] = Op.SHR,\n}\n\ncompileExprInto = function(fs, node, target)\n  local k = node.k\n  local line = node.line\n  if k == 'Nil' then fs:emit({ op = Op.LOADNIL, a = target, b = 0 }, line)\n  elseif k == 'True' then fs:emit({ op = Op.LOADBOOL, a = target, b = 1 }, line)\n  elseif k == 'False' then fs:emit({ op = Op.LOADBOOL, a = target, b = 0 }, line)\n  elseif k == 'Number' then\n    local v = tonumber(node.value)\n    -- small integer immediates avoid a constant slot\n    if math.type and math.type(v) == 'integer' and v >= -32768 and v <= 32767 then\n      fs:emit({ op = Op.LOADINT, a = target, sbx = v }, line)\n    elseif not math.type and v == math.floor(v) and v >= -32768 and v <= 32767 then\n      fs:emit({ op = Op.LOADINT, a = target, sbx = v }, line)\n    else\n      fs:emit({ op = Op.LOADK, a = target, bx = fs:const(v) }, line)\n    end\n  elseif k == 'String' then fs:emit({ op = Op.LOADK, a = target, bx = fs:const(node.value) }, line)\n  elseif k == 'Vararg' then assertVararg(fs, line); fs:emit({ op = Op.VARARG, a = target, b = 2 }, line)\n  elseif k == 'Paren' then\n    compileExprInto(fs, node.expr, target) -- single value already\n  elseif k == 'Name' then\n    local d = node.decl\n    if not d then\n      fs:emit({ op = Op.GETGLOBAL, a = target, bx = fs:const(node.name) }, line)\n    elseif d.owner == fs then\n      if d.captured then fs:emit({ op = Op.GETCELL, a = target, b = d.reg }, line)\n      elseif d.reg ~= target then fs:emit({ op = Op.MOVE, a = target, b = d.reg }, line) end\n    else\n      fs:emit({ op = Op.GETUPVAL, a = target, b = fs:upval(d) }, line)\n    end\n  elseif k == 'Field' then\n    local save = fs.freereg\n    local robj = exprAny(fs, node.obj)\n    fs:emit({ op = Op.GETFIELD, a = target, b = robj, bx = fs:const(node.name) }, line)\n    fs.freereg = save\n  elseif k == 'Index' then\n    local save = fs.freereg\n    local robj = exprAny(fs, node.obj)\n    local ridx = exprAny(fs, node.index)\n    fs:emit({ op = Op.GETTABLE, a = target, b = robj, c = ridx }, line)\n    fs.freereg = save\n  elseif k == 'CallE' or k == 'Method' then\n    compileCall(fs, node, target, 1, line)\n  elseif k == 'Function' then\n    compileFunc(fs, node, target)\n  elseif k == 'Table' then\n    compileTable(fs, node, target)\n  elseif k == 'Unop' then\n    local save = fs.freereg\n    local rb = exprAny(fs, node.operand)\n    local opmap = { ['-'] = Op.UNM, ['not'] = Op.NOT, ['#'] = Op.LEN, ['~'] = Op.BNOT }\n    fs:emit({ op = opmap[node.op], a = target, b = rb }, line)\n    fs.freereg = save\n  elseif k == 'Binop' then\n    compileBinop(fs, node, target)\n  elseif k == 'IfExpr' then\n    -- Luau if-then-else expression: each branch stores its value into `target`.\n    local endJumps = {}\n    for _, clause in ipairs(node.clauses) do\n      local save = fs.freereg\n      local rc = exprNext(fs, clause.cond)\n      fs.freereg = save\n      local jnext = fs:emit({ op = Op.JMPIFNOT, a = rc, sbx = 0 }, clause.cond.line)\n      compileExprInto(fs, clause.value, target)\n      endJumps[#endJumps + 1] = fs:emit({ op = Op.JMP, sbx = 0 }, line)\n      fs:patch(jnext, fs:here())\n    end\n    compileExprInto(fs, node.elseValue, target)\n    for _, j in ipairs(endJumps) do fs:patch(j, fs:here()) end\n  else\n    error('compiler: cannot compile expr ' .. tostring(k))\n  end\nend\n\nfunction compileBinop(fs, node, target)\n  local op, line = node.op, node.line\n  if op == 'and' then\n    compileExprInto(fs, node.left, target)\n    local j = fs:emit({ op = Op.JMPIFNOT, a = target, sbx = 0 }, line)\n    compileExprInto(fs, node.right, target)\n    fs:patch(j, fs:here())\n    return\n  elseif op == 'or' then\n    compileExprInto(fs, node.left, target)\n    local j = fs:emit({ op = Op.JMPIF, a = target, sbx = 0 }, line)\n    compileExprInto(fs, node.right, target)\n    fs:patch(j, fs:here())\n    return\n  end\n  local save = fs.freereg\n  if op == '..' then\n    local r1 = exprNext(fs, node.left)\n    local r2 = exprNext(fs, node.right)\n    fs:emit({ op = Op.CONCAT, a = target, b = r1, c = r2 }, line)\n  elseif BINOP[op] then\n    local rb = exprAny(fs, node.left)\n    local rc = exprAny(fs, node.right)\n    fs:emit({ op = BINOP[op], a = target, b = rb, c = rc }, line)\n  elseif op == '==' or op == '~=' then\n    local rb = exprAny(fs, node.left)\n    local rc = exprAny(fs, node.right)\n    fs:emit({ op = Op.EQ, a = target, b = rb, c = rc }, line)\n    if op == '~=' then fs:emit({ op = Op.NOT, a = target, b = target }, line) end\n  elseif op == '<' or op == '>' then\n    local l, r = node.left, node.right\n    if op == '>' then l, r = r, l end\n    local rb = exprAny(fs, l)\n    local rc = exprAny(fs, r)\n    fs:emit({ op = Op.LT, a = target, b = rb, c = rc }, line)\n  elseif op == '<=' or op == '>=' then\n    local l, r = node.left, node.right\n    if op == '>=' then l, r = r, l end\n    local rb = exprAny(fs, l)\n    local rc = exprAny(fs, r)\n    fs:emit({ op = Op.LE, a = target, b = rb, c = rc }, line)\n  else\n    error('compiler: bad binop ' .. tostring(op))\n  end\n  fs.freereg = save\nend\n\nfunction compileTable(fs, node, target)\n  -- Positional (array) values are held in a contiguous block above the table\n  -- register and flushed with one SETLIST at the END, so they win over any\n  -- same-index keyed field (matching Lua's evaluation order). Keyed/named\n  -- fields are stored as encountered, using temporaries above the block.\n  local save = fs.freereg\n  fs:emit({ op = Op.NEWTABLE, a = target }, node.line)\n  local arrayBase = target + 1\n  fs.freereg = arrayBase\n  local arrayCount = 0\n  local multiLast = false\n  local nfields = #node.fields\n  for i, f in ipairs(node.fields) do\n    if f.kind == 'item' then\n      local r = arrayBase + arrayCount\n      fs.freereg = r\n      if i == nfields and isMultiExpr(f.value) then\n        if f.value.k == 'Vararg' then\n          assertVararg(fs, node.line)\n          fs:reserve(1)\n          fs:emit({ op = Op.VARARG, a = r, b = 0 }, node.line)\n        else\n          compileCall(fs, f.value, r, -1, node.line)\n        end\n        multiLast = true\n      else\n        fs:reserve(1)\n        compileExprInto(fs, f.value, r)\n        arrayCount = arrayCount + 1\n      end\n    else\n      local blockTop = arrayBase + arrayCount\n      fs.freereg = blockTop\n      if f.kind == 'named' then\n        local rv = exprNext(fs, f.value)\n        fs:emit({ op = Op.SETFIELD, a = target, bx = fs:const(f.key), c = rv }, node.line)\n      else\n        local rk = exprNext(fs, f.key)\n        local rv = exprNext(fs, f.value)\n        fs:emit({ op = Op.SETTABLE, a = target, b = rk, c = rv }, node.line)\n      end\n      fs.freereg = blockTop -- keep the positional block intact\n    end\n  end\n  if multiLast then\n    fs:emit({ op = Op.SETLIST, a = target, b = 0, c = 0 }, node.line)\n  elseif arrayCount > 0 then\n    fs:emit({ op = Op.SETLIST, a = target, b = arrayCount, c = 0 }, node.line)\n  end\n  fs.freereg = save\nend\n\n--  function bodies \ncompileFunc = function(fs, node, target)\n  local child = newFS(fs, node.isVararg)\n  child.proto.numparams = #node.params\n  -- declare params as locals\n  for i, decl in ipairs(node.paramDecls) do\n    decl.owner = child\n    decl.reg = i - 1\n    child.freereg = math.max(child.freereg, i)\n  end\n  child:reserve(0)\n  if child.proto.numparams > child.proto.maxstack then child.proto.maxstack = child.proto.numparams + 2 end\n  -- box captured params\n  for _, decl in ipairs(node.paramDecls) do\n    if decl.captured then child:emit({ op = Op.NEWCELL, a = decl.reg }, node.line) end\n  end\n  compileBlock(child, node.body)\n  child:emit({ op = Op.RETURN, a = 0, b = 1 }, node.line) -- implicit return\n  local protos = fs.proto.protos\n  protos[#protos + 1] = child.proto\n  fs:emit({ op = Op.CLOSURE, a = target, bx = #protos }, node.line)\nend\n\n--  statements \nfunction compileBlock(fs, stmts)\n  local save = fs.freereg\n  local savedLocals = fs._activeCount or 0\n  for _, s in ipairs(stmts) do compileStmt(fs, s) end\n  fs.freereg = save\nend\n\nlocal function declareLocal(fs, decl, line)\n  local r = fs.freereg\n  fs:reserve(1)\n  decl.owner = fs\n  decl.reg = r\n  return r\nend\n\ncompileStmt = function(fs, s)\n  local k = s.k\n  local line = s.line\n  if k == 'Local' then\n    local base = fs.freereg\n    -- produce exactly #names values (nil-filling short calls / vararg)  see explistExact\n    fs:explistExact(s.exprs, base, #s.names)\n    for i, decl in ipairs(s.decls) do\n      decl.owner = fs\n      decl.reg = base + i - 1\n      if decl.captured then fs:emit({ op = Op.NEWCELL, a = decl.reg }, line) end\n    end\n  elseif k == 'LocalFunc' then\n    local r = declareLocal(fs, s.decl, line)\n    if s.decl.captured then\n      -- reserve cell first so recursion sees it\n      fs:emit({ op = Op.LOADNIL, a = r, b = 0 }, line)\n      fs:emit({ op = Op.NEWCELL, a = r }, line)\n      local tmp = fs.freereg\n      fs:reserve(1)\n      compileFunc(fs, s.func, tmp)\n      fs:emit({ op = Op.SETCELL, a = r, b = tmp }, line)\n      fs.freereg = r + 1\n    else\n      compileFunc(fs, s.func, r)\n    end\n  elseif k == 'Assign' then\n    compileAssign(fs, s)\n  elseif k == 'FuncDecl' then\n    compileFuncDecl(fs, s)\n  elseif k == 'CallStat' then\n    local save = fs.freereg\n    compileCall(fs, s.call, fs.freereg, 0, line)\n    fs.freereg = save\n  elseif k == 'Do' then\n    compileBlock(fs, s.body)\n  elseif k == 'Return' then\n    local base = fs.freereg\n    local count = fs:explistOpen(s.exprs, base)\n    fs:emit({ op = Op.RETURN, a = base, b = count }, line)\n    fs.freereg = base\n  elseif k == 'If' then\n    compileIf(fs, s)\n  elseif k == 'While' then\n    compileWhile(fs, s)\n  elseif k == 'Repeat' then\n    compileRepeat(fs, s)\n  elseif k == 'NumFor' then\n    compileNumFor(fs, s)\n  elseif k == 'GenFor' then\n    compileGenFor(fs, s)\n  elseif k == 'Break' then\n    local loop = fs.loops[#fs.loops]\n    if not loop then error('compiler: break outside loop') end\n    local j = fs:emit({ op = Op.JMP, sbx = 0 }, line)\n    loop.breaks[#loop.breaks + 1] = j\n  elseif k == 'Continue' then\n    local loop = fs.loops[#fs.loops]\n    if not loop then error('compiler: continue outside loop') end\n    local j = fs:emit({ op = Op.JMP, sbx = 0 }, line)\n    loop.continues[#loop.continues + 1] = j\n  elseif k == 'Goto' or k == 'Label' then\n    error('ferret-vm: goto/label is not supported (Luau has no goto)')\n  else\n    error('compiler: cannot compile stmt ' .. tostring(k))\n  end\nend\n\nfunction compileAssign(fs, s)\n  local save = fs.freereg\n  local n = #s.targets\n  if n == 1 and #s.exprs == 1 then\n    compileStore(fs, s.targets[1], s.exprs[1], s.line)\n    fs.freereg = save\n    return\n  end\n  -- evaluate exactly n RHS values into consecutive temps (nil-filling short\n  -- calls / vararg  see explistExact), then store into the targets\n  local base = fs.freereg\n  fs:explistExact(s.exprs, base, n)\n  fs.freereg = base + n\n  for i = 1, n do\n    compileStoreReg(fs, s.targets[i], base + i - 1, s.line)\n  end\n  fs.freereg = save\nend\n\n-- store the value of `valueNode` into target lvalue\nfunction compileStore(fs, target, valueNode, line)\n  if target.k == 'Name' then\n    local d = target.decl\n    if not d then\n      local r = exprNext(fs, valueNode)\n      fs:emit({ op = Op.SETGLOBAL, a = r, bx = fs:const(target.name) }, line)\n    elseif d.owner == fs then\n      if d.captured then\n        local r = exprNext(fs, valueNode)\n        fs:emit({ op = Op.SETCELL, a = d.reg, b = r }, line)\n      else\n        -- Calls/methods/tables use [target+1..] as scratch, which would clobber\n        -- other live locals (and args read from them). Evaluate into a fresh\n        -- temp above the locals, then move into place.\n        local vk = valueNode.k\n        if vk == 'CallE' or vk == 'Method' or vk == 'Table' then\n          local save = fs.freereg\n          local tmp = exprNext(fs, valueNode)\n          if tmp ~= d.reg then fs:emit({ op = Op.MOVE, a = d.reg, b = tmp }, line) end\n          fs.freereg = save\n        else\n          compileExprInto(fs, valueNode, d.reg)\n        end\n      end\n    else\n      local r = exprNext(fs, valueNode)\n      fs:emit({ op = Op.SETUPVAL, a = r, b = fs:upval(d) }, line)\n    end\n  elseif target.k == 'Field' then\n    local robj = exprAny(fs, target.obj)\n    local rv = exprNext(fs, valueNode)\n    fs:emit({ op = Op.SETFIELD, a = robj, bx = fs:const(target.name), c = rv }, line)\n  elseif target.k == 'Index' then\n    local robj = exprAny(fs, target.obj)\n    local rk = exprAny(fs, target.index)\n    local rv = exprNext(fs, valueNode)\n    fs:emit({ op = Op.SETTABLE, a = robj, b = rk, c = rv }, line)\n  end\nend\n\n-- store an already-computed value (in register `vreg`) into target lvalue\nfunction compileStoreReg(fs, target, vreg, line)\n  if target.k == 'Name' then\n    local d = target.decl\n    if not d then fs:emit({ op = Op.SETGLOBAL, a = vreg, bx = fs:const(target.name) }, line)\n    elseif d.owner == fs then\n      if d.captured then fs:emit({ op = Op.SETCELL, a = d.reg, b = vreg }, line)\n      elseif d.reg ~= vreg then fs:emit({ op = Op.MOVE, a = d.reg, b = vreg }, line) end\n    else fs:emit({ op = Op.SETUPVAL, a = vreg, b = fs:upval(d) }, line) end\n  elseif target.k == 'Field' then\n    local robj = exprAny(fs, target.obj)\n    fs:emit({ op = Op.SETFIELD, a = robj, bx = fs:const(target.name), c = vreg }, line)\n  elseif target.k == 'Index' then\n    local robj = exprAny(fs, target.obj)\n    local rk = exprAny(fs, target.index)\n    fs:emit({ op = Op.SETTABLE, a = robj, b = rk, c = vreg }, line)\n  end\nend\n\nfunction compileFuncDecl(fs, s)\n  -- build the target lvalue: base [.path]* [:method]\n  local line = s.line\n  if #s.path == 0 and not s.method then\n    -- assign to base (local/upval/global)\n    local nameNode = { k = 'Name', name = s.base, decl = s.baseDecl, line = line }\n    compileStore(fs, nameNode, s.func, line)\n  else\n    -- resolve base object, then descend fields, set last\n    local save = fs.freereg\n    local baseNode = { k = 'Name', name = s.base, decl = s.baseDecl, line = line }\n    local robj = exprNext(fs, baseNode)\n    for i = 1, #s.path - (s.method and 0 or 1) do\n      local nxt = fs.freereg\n      fs:reserve(1)\n      fs:emit({ op = Op.GETFIELD, a = nxt, b = robj, bx = fs:const(s.path[i]) }, line)\n      robj = nxt\n    end\n    local lastKey = s.method or s.path[#s.path]\n    local rv = exprNext(fs, s.func)\n    fs:emit({ op = Op.SETFIELD, a = robj, bx = fs:const(lastKey), c = rv }, line)\n    fs.freereg = save\n  end\nend\n\n-- if / elseif / else\nfunction compileIf(fs, s)\n  local endJumps = {}\n  for ci, clause in ipairs(s.clauses) do\n    local save = fs.freereg\n    local rc = exprNext(fs, clause.cond)\n    fs.freereg = save\n    local jnext = fs:emit({ op = Op.JMPIFNOT, a = rc, sbx = 0 }, clause.cond.line)\n    compileBlock(fs, clause.body)\n    if s.elseBody or ci < #s.clauses then\n      endJumps[#endJumps + 1] = fs:emit({ op = Op.JMP, sbx = 0 }, s.line)\n    end\n    fs:patch(jnext, fs:here())\n  end\n  if s.elseBody then compileBlock(fs, s.elseBody) end\n  for _, j in ipairs(endJumps) do fs:patch(j, fs:here()) end\nend\n\nfunction compileWhile(fs, s)\n  local top = fs:here()\n  local save = fs.freereg\n  local rc = exprNext(fs, s.cond)\n  fs.freereg = save\n  local jexit = fs:emit({ op = Op.JMPIFNOT, a = rc, sbx = 0 }, s.line)\n  fs.loops[#fs.loops + 1] = { breaks = {}, continues = {} }\n  compileBlock(fs, s.body)\n  local loop = fs.loops[#fs.loops]\n  for _, j in ipairs(loop.continues) do fs:patch(j, top) end -- continue -> re-test\n  local jback = fs:emit({ op = Op.JMP, sbx = 0 }, s.line)\n  fs:patch(jback, top)\n  fs:patch(jexit, fs:here())\n  table.remove(fs.loops)\n  for _, j in ipairs(loop.breaks) do fs:patch(j, fs:here()) end\nend\n\nfunction compileRepeat(fs, s)\n  local top = fs:here()\n  fs.loops[#fs.loops + 1] = { breaks = {}, continues = {} }\n  -- body and until share scope; compile inline (no freereg reset before cond)\n  local save = fs.freereg\n  for _, st in ipairs(s.body) do compileStmt(fs, st) end\n  local loop = fs.loops[#fs.loops]\n  for _, j in ipairs(loop.continues) do fs:patch(j, fs:here()) end -- continue -> until test\n  local rc = exprNext(fs, s.cond)\n  local jback = fs:emit({ op = Op.JMPIFNOT, a = rc, sbx = 0 }, s.line)\n  fs:patch(jback, top)\n  fs.freereg = save\n  table.remove(fs.loops)\n  for _, j in ipairs(loop.breaks) do fs:patch(j, fs:here()) end\nend\n\nfunction compileNumFor(fs, s)\n  local base = fs.freereg\n  exprNext(fs, s.start)  -- base\n  exprNext(fs, s.stop)   -- base+1\n  if s.step then exprNext(fs, s.step) else\n    fs:emit({ op = Op.LOADINT, a = fs.freereg, sbx = 1 }, s.line); fs:reserve(1)\n  end\n  fs:reserve(1) -- loop var at base+3\n  if fs.freereg > fs.proto.maxstack then fs.proto.maxstack = fs.freereg end\n  s.varDecl.owner = fs\n  s.varDecl.reg = base + 3\n  local jprep = fs:emit({ op = Op.FORPREP, a = base, sbx = 0 }, s.line)\n  fs.loops[#fs.loops + 1] = { breaks = {}, continues = {} }\n  local bodyStart = fs:here()\n  if s.varDecl.captured then fs:emit({ op = Op.NEWCELL, a = base + 3 }, s.line) end\n  compileBlock(fs, s.body)\n  local loop = fs.loops[#fs.loops]\n  for _, j in ipairs(loop.continues) do fs:patch(j, fs:here()) end -- continue -> step/test\n  local loopIns = fs:emit({ op = Op.FORLOOP, a = base, sbx = 0 }, s.line)\n  fs:patch(jprep, loopIns)     -- FORPREP jumps forward to the FORLOOP instruction\n  fs:patch(loopIns, bodyStart) -- FORLOOP jumps back to the body start\n  fs.freereg = base\n  table.remove(fs.loops)\n  for _, j in ipairs(loop.breaks) do fs:patch(j, fs:here()) end\nend\n\nfunction compileGenFor(fs, s)\n  local base = fs.freereg\n  -- iterator function, state, control (3 values) from exprs\n  local count = fs:explistOpen(s.exprs, base)\n  local have = (count == 0) and 3 or (count - 1)\n  for i = have, 2 do fs:emit({ op = Op.LOADNIL, a = base + i, b = 0 }, s.line) end\n  fs.freereg = base + 3\n  -- loop vars at base+3 ...\n  local nvars = #s.decls\n  fs:reserve(nvars)\n  if fs.freereg > fs.proto.maxstack then fs.proto.maxstack = fs.freereg end\n  for i, decl in ipairs(s.decls) do decl.owner = fs; decl.reg = base + 3 + (i - 1) end\n  -- normalize the iterator triple once for Luau generalized iteration (a bare\n  -- table / __iter object becomes a proper (iterfn, state, control) triple)\n  fs:emit({ op = Op.TFORPREP, a = base }, s.line)\n  local jto = fs:emit({ op = Op.JMP, sbx = 0 }, s.line) -- jump to TFORCALL\n  fs.loops[#fs.loops + 1] = { breaks = {}, continues = {} }\n  local bodyStart = fs:here()\n  for _, decl in ipairs(s.decls) do\n    if decl.captured then fs:emit({ op = Op.NEWCELL, a = decl.reg }, s.line) end\n  end\n  compileBlock(fs, s.body)\n  local loop = fs.loops[#fs.loops]\n  local contTarget = fs:here()\n  for _, j in ipairs(loop.continues) do fs:patch(j, contTarget) end -- continue -> next iter\n  fs:patch(jto, contTarget)\n  fs:emit({ op = Op.TFORCALL, a = base, c = nvars }, s.line)\n  local jloop = fs:emit({ op = Op.TFORLOOP, a = base, sbx = 0 }, s.line)\n  fs:patch(jloop, bodyStart)\n  fs.freereg = base\n  table.remove(fs.loops)\n  for _, j in ipairs(loop.breaks) do fs:patch(j, fs:here()) end\nend\n\n--  entry \nfunction Compiler.compileAST(chunk)\n  Scope.analyze(chunk)\n  local main = newFS(nil, true)\n  main.proto.isVararg = true\n  compileBlock(main, chunk.body)\n  main:emit({ op = Op.RETURN, a = 0, b = 1 }, 0)\n  return main.proto\nend\n\nfunction Compiler.compile(src, chunkName, opts)\n  opts = opts or {}\n  local chunk = Parser.parseString(src, chunkName)\n  if opts.optimize ~= false then\n    local Optimizer = require('optimizer')\n    Optimizer.optimizeAST(chunk)\n    -- Opaque-predicate injection runs AFTER folding (so predicates aren't\n    -- folded) and BEFORE scope analysis / codegen (so the compiler allocates\n    -- registers and jumps for the injected code). opts.opaque is a Harden.prng.\n    if opts.opaque then\n      require('obfuscate').inject(chunk, opts.opaque, { density = opts.opaqueDensity })\n    end\n    local proto = Compiler.compileAST(chunk)\n    Optimizer.peephole(proto)\n    return proto\n  end\n  if opts.opaque then\n    require('obfuscate').inject(chunk, opts.opaque, { density = opts.opaqueDensity })\n  end\n  return Compiler.compileAST(chunk)\nend\n\nreturn Compiler\n","serializer":"-- luau-vm/src/serializer.lua\n-- Compact binary encoding of a compiled proto tree, and its inverse loader.\n-- No loadstring: bytes -> runtime proto tables directly.\n--\n-- Format\n--   magic  'FVM' , version(1 byte)\n--   uint32 checksum (custom GraniteSum over the body)\n--   uint32 bodyLength\n--   body:  proto (recursive)\n-- Integers use zig-zag LEB128 varints; numbers round-trip via %.17g text so no\n-- string.pack dependency (works on Lua 5.1+/Luau uniformly).\n\nlocal Opcodes = require('opcodes')\n\nlocal Serializer = {}\n\nlocal MAGIC = 'FVM'\nlocal VERSION = 1\n\n--  writer \nlocal function Writer()\n  return { buf = {}, put = function(self, s) self.buf[#self.buf + 1] = s end }\nend\nlocal function writeByte(w, b) w:put(string.char(b % 256)) end\nlocal function writeUVarint(w, x)\n  x = math.floor(x)\n  while true do\n    local b = x % 128\n    x = math.floor(x / 128)\n    if x > 0 then writeByte(w, b + 128) else writeByte(w, b); break end\n  end\nend\nlocal function writeSVarint(w, x)\n  x = math.floor(x)\n  local zz = x >= 0 and (x * 2) or (-x * 2 - 1) -- zig-zag\n  writeUVarint(w, zz)\nend\nlocal function writeString(w, s)\n  writeUVarint(w, #s)\n  w:put(s)\nend\nlocal function writeU32(w, x)\n  x = math.floor(x) % 4294967296\n  for _ = 1, 4 do writeByte(w, x % 256); x = math.floor(x / 256) end\nend\n\n--  reader \nlocal function Reader(s) return { s = s, pos = 1 } end\n-- EOF-safe: a truncated/corrupt stream reports its position instead of faulting\n-- later on a nil (e.g. `nil % 128`). Keeps malformed input from crashing the host.\nlocal function readByte(r)\n  local b = string.byte(r.s, r.pos)\n  if b == nil then error('serializer: unexpected end of bytecode at offset ' .. r.pos) end\n  r.pos = r.pos + 1\n  return b\nend\nlocal function readUVarint(r)\n  local x, shift = 0, 1\n  while true do\n    local b = readByte(r)\n    x = x + (b % 128) * shift\n    if b < 128 then break end\n    shift = shift * 128\n  end\n  return x\nend\nlocal function readSVarint(r)\n  local zz = readUVarint(r)\n  -- math.floor keeps an integer subtype on Lua 5.4 (unlike `/`, which floats)\n  if zz % 2 == 0 then return math.floor(zz / 2) else return -math.floor((zz + 1) / 2) end\nend\nlocal function readString(r)\n  local n = readUVarint(r)\n  local s = r.s:sub(r.pos, r.pos + n - 1)\n  r.pos = r.pos + n\n  return s\nend\nlocal function readU32(r)\n  local x, m = 0, 1\n  for _ = 1, 4 do x = x + readByte(r) * m; m = m * 256 end\n  return x\nend\n\n--  value (constant) encoding \nlocal T_NIL, T_TRUE, T_FALSE, T_INT, T_NUM, T_STR = 0, 1, 2, 3, 4, 5\n-- Largest magnitude a double represents as an exact integer; the zig-zag varint\n-- stays lossless within it, so genuine integers up to here go through T_INT.\nlocal INT_EXACT = 9007199254740992 -- 2^53\n\n-- Format a float so tonumber() reconstructs the identical value AND float\n-- subtype: %.17g is round-trippable, but an integer-valued float (\"2\", \"-0\")\n-- would read back as an integer, so a trailing \".0\" forces the float subtype.\n-- inf/nan have no numeric literal, so they use their own text sentinels.\nlocal function numToStr(v)\n  if v ~= v then return 'nan' end\n  if v == math.huge then return 'inf' end\n  if v == -math.huge then return '-inf' end\n  local s = string.format('%.17g', v)\n  if not s:find('[.eE]') then s = s .. '.0' end\n  return s\nend\n\nlocal function isIntegerValue(v)\n  if math.type then return math.type(v) == 'integer' end\n  -- Lua 5.1 / Luau: no integer subtype; treat exact integers (but not -0.0,\n  -- whose sign must survive) as integers for compact storage.\n  if v ~= v or v == math.huge or v == -math.huge then return false end\n  if v == 0 and 1 / v < 0 then return false end\n  return math.floor(v) == v\nend\n\nlocal function writeValue(w, v)\n  local t = type(v)\n  if v == nil then writeByte(w, T_NIL)\n  elseif v == true then writeByte(w, T_TRUE)\n  elseif v == false then writeByte(w, T_FALSE)\n  elseif t == 'number' then\n    if isIntegerValue(v) then\n      if v >= -INT_EXACT and v <= INT_EXACT then\n        writeByte(w, T_INT); writeSVarint(w, v)\n      else\n        -- integer past exact-double range: plain integer text (no forced \".0\",\n        -- so it reads back as an integer rather than a lossy float)\n        writeByte(w, T_NUM); writeString(w, string.format('%.17g', v))\n      end\n    else\n      -- float subtype: keep the value, sign of -0.0, and float-ness\n      writeByte(w, T_NUM); writeString(w, numToStr(v))\n    end\n  elseif t == 'string' then writeByte(w, T_STR); writeString(w, v)\n  else error('serializer: cannot encode constant of type ' .. t) end\nend\nlocal function readValue(r)\n  local t = readByte(r)\n  if t == T_NIL then return nil\n  elseif t == T_TRUE then return true\n  elseif t == T_FALSE then return false\n  elseif t == T_INT then return readSVarint(r)\n  elseif t == T_NUM then\n    local s = readString(r)\n    local n = tonumber(s)\n    if n ~= nil then return n end\n    if s == 'inf' then return math.huge end\n    if s == '-inf' then return -math.huge end\n    if s == 'nan' or s == '-nan' then return 0 / 0 end\n    error('serializer: bad number literal ' .. tostring(s))\n  elseif t == T_STR then return readString(r)\n  else error('serializer: bad constant tag ' .. tostring(t)) end\nend\n\n--  proto encoding \n-- opMap (optional): canonical opcode -> the byte(s) written for it. A number\n-- gives a per-build opcode numbering; a { list } of bytes enables instruction\n-- mutation (one opcode has several interchangeable encodings, chosen per\n-- instruction via `pick`). ins.op stays canonical internally, so operand-layout\n-- lookup and the VM's dispatch are unaffected.\nlocal function opByte(opMap, op, pick)\n  local m = opMap and opMap[op]\n  if type(m) == 'table' then return m[(pick and pick() or 0) % #m + 1] end\n  return m or op\nend\nlocal function writeProto(w, p, opMap, pick)\n  writeUVarint(w, p.numparams)\n  writeByte(w, p.isVararg and 1 or 0)\n  writeUVarint(w, p.maxstack)\n  -- upvalues\n  writeUVarint(w, #p.upvals)\n  for _, d in ipairs(p.upvals) do\n    writeByte(w, d.kind == 'reg' and 0 or 1)\n    writeUVarint(w, d.index)\n  end\n  -- constants\n  writeUVarint(w, #p.consts)\n  for _, c in ipairs(p.consts) do writeValue(w, c) end\n  -- code\n  writeUVarint(w, #p.code)\n  for _, ins in ipairs(p.code) do\n    writeByte(w, opByte(opMap, ins.op, pick))\n    for _, field in ipairs(Opcodes.operands[ins.op]) do\n      writeSVarint(w, ins[field] or 0)\n    end\n  end\n  -- nested protos\n  writeUVarint(w, #p.protos)\n  for _, child in ipairs(p.protos) do writeProto(w, child, opMap, pick) end\nend\n\n-- invMap (optional): the inverse of opMap (written byte -> canonical opcode).\nlocal function readProto(r, invMap)\n  local p = { upvals = {}, consts = {}, code = {}, protos = {}, lines = {} }\n  p.numparams = readUVarint(r)\n  p.isVararg = readByte(r) == 1\n  p.maxstack = readUVarint(r)\n  for i = 1, readUVarint(r) do\n    local kind = readByte(r) == 0 and 'reg' or 'up'\n    p.upvals[i] = { kind = kind, index = readUVarint(r) }\n  end\n  for i = 1, readUVarint(r) do p.consts[i] = readValue(r) end\n  local ncode = readUVarint(r)\n  for i = 1, ncode do\n    local op = readByte(r)\n    if invMap then op = invMap[op] end\n    local ins = { op = op }\n    for _, field in ipairs(Opcodes.operands[op]) do ins[field] = readSVarint(r) end\n    p.code[i] = ins\n  end\n  for i = 1, readUVarint(r) do p.protos[i] = readProto(r, invMap) end\n  return p\nend\n\n--  custom container hash (32-bit, portable) \n-- Our own body hash (\"GraniteSum\")  NOT FNV-1a/CRC/djb2, and needs no bit32:\n-- two coupled accumulators (custom multiplier on lane `a`, positional sum on\n-- lane `b`) folded with a final multiply. Products stay < 2^53 so it is exact\n-- in Lua 5.1-5.4 + Luau doubles. Detects any body corruption before deserialize.\nlocal function ghash(s)\n  local a, b = 305419896, 2596069031\n  for i = 1, #s do\n    a = (a * 524287 + s:byte(i) + 1) % 4294967296\n    b = (b + a) % 4294967296\n  end\n  local bl = b % 65536\n  b = ((bl * 40503) + (((b - bl) / 65536 * 40503) % 65536) * 65536) % 4294967296\n  return (a + b) % 4294967296\nend\n\n--  public API \nfunction Serializer.serialize(proto, opMap, pick)\n  local w = Writer()\n  writeProto(w, proto, opMap, pick)\n  local body = table.concat(w.buf)\n  local head = Writer()\n  head:put(MAGIC)\n  writeByte(head, VERSION)\n  writeU32(head, ghash(body))\n  writeU32(head, #body)\n  return table.concat(head.buf) .. body\nend\n\nfunction Serializer.deserialize(bytes, invMap)\n  local r = Reader(bytes)\n  if bytes:sub(1, 3) ~= MAGIC then error('serializer: bad magic (not ferret bytecode)') end\n  r.pos = 4\n  local version = readByte(r)\n  if version ~= VERSION then error('serializer: unsupported version ' .. version) end\n  local checksum = readU32(r)\n  local bodyLen = readU32(r)\n  local body = bytes:sub(r.pos, r.pos + bodyLen - 1)\n  if ghash(body) ~= checksum then error('serializer: checksum mismatch (corrupt bytecode)') end\n  local br = Reader(body)\n  return readProto(br, invMap)\nend\n\n-- Recompute the container checksum over the current body. Lets tooling (e.g.\n-- the malformed-bytecode fuzzer) craft *well-formed-but-nonsense* bytecode that\n-- passes the checksum, so the structural validator  not the checksum  is what\n-- must catch it. Returns a resealed container the loader will accept.\nfunction Serializer.reseal(bytes)\n  local body = bytes:sub(13) -- MAGIC(3)+VERSION(1)+checksum(4)+bodyLen(4)\n  local head = Writer()\n  head:put(MAGIC)\n  writeByte(head, VERSION)\n  writeU32(head, ghash(body))\n  writeU32(head, #body)\n  return table.concat(head.buf) .. body\nend\n\nSerializer.MAGIC = MAGIC\nSerializer.VERSION = VERSION\nreturn Serializer\n","seal":"-- luau-vm/src/seal.lua\n-- Sealed, streamed code  the runtime JIT/on-demand-decode layer, applied AFTER\n-- the build-time GraniteCipher payload has been decoded to proto tables.\n--\n-- Each proto's instruction array is packed into per-instruction encrypted slices\n-- and the plaintext `code` table is dropped. vm.lua then decodes exactly ONE\n-- instruction at a time, immediately before executing it. Consequences:\n--   * Streamed execution  the whole plaintext instruction stream is never\n--     resident; only the current instruction exists, as a short-lived local the\n--     GC reclaims (best-effort \"memory scrubbing\" in a managed runtime).\n--   * Ephemeral session key  the key is derived at RUNTIME (per execution), so\n--     the in-memory encrypted form differs every run; a memory dump is unstable.\n--   * Compact representation  instructions live as opaque encrypted bytes, not\n--     an easy-to-inspect {op=,a=,b=} mirror.\n--\n-- Additive keystream over a GraniteRNG-style split-multiply LCG (products < 2^53,\n-- exact on Luau/Lua doubles, no bit library); per-instruction seeds give random\n-- access without decrypting neighbours.\n\nlocal Opcodes = require('opcodes')\n\nlocal M = {}\n\n-- split-multiply (a*b) mod 2^32, exact in doubles (matches harden.gmul style)\nlocal function gmul(a, b)\n  local al = a % 65536\n  return ((al * b) + (((a - al) / 65536 * b) % 65536) * 65536) % 4294967296\nend\n\nlocal function putUV(t, x)\n  x = math.floor(x)\n  while true do\n    local b = x % 128; x = math.floor(x / 128)\n    if x > 0 then t[#t + 1] = b + 128 else t[#t + 1] = b; break end\n  end\nend\nlocal function putSV(t, x)\n  x = math.floor(x)\n  putUV(t, x >= 0 and x * 2 or (-x * 2 - 1)) -- zig-zag\nend\n\n-- keystream state for instruction i under session key sk (never zero)\nlocal function seed1(sk, i)\n  local s = (gmul(sk, 2654435761) + i * 40503 + 1) % 4294967296\n  if s == 0 then s = 1 end\n  return s\nend\n-- independent keystream seed for string constant i (its own domain)\nlocal function seedK(sk, i)\n  local s = (gmul(sk, 40503) + i * 2654435761 + 7) % 4294967296\n  if s == 0 then s = 1 end\n  return s\nend\nlocal function nextByte(st)\n  st = (gmul(st, 3218467781) + 2596069031) % 4294967296\n  return st, st % 256\nend\n\n-- Additive mask for numeric constant i (own domain). A 31-bit integer, so for an\n-- integer-valued constant with |v| <= 2^52 the sum v+mask stays < 2^53 and is\n-- exact in both Lua integers (modular) and Luau doubles; subtracting the same\n-- mask recovers v exactly, and Lua's arithmetic preserves the int/float subtype.\nlocal function maskFor(sk, i)\n  local st = (gmul(sk, 2246822519) + i * 3266489917 + 11) % 4294967296\n  st = (gmul(st, 3218467781) + 2596069031) % 4294967296\n  -- math.floor forces an integer subtype on Lua 5.4 (gmul's `/` yields a float),\n  -- so an integer constant + mask stays an integer and keeps its subtype.\n  return math.floor(st) % 2147483648 + 1 -- integer in 1 .. 2^31\nend\n\n-- Seal a proto tree in place: proto.code -> proto.sealed (encrypted slices),\n-- plaintext code removed. sk is the runtime-derived session key.\nfunction M.seal(proto, sk)\n  local code = proto.code\n  local n = #code\n  local slices = {}\n  for i = 1, n do\n    local ins = code[i]\n    local raw = { ins.op % 256 }\n    for _, f in ipairs(Opcodes.operands[ins.op]) do putSV(raw, ins[f] or 0) end\n    local st, kb = seed1(sk, i), nil\n    local enc = {}\n    for j = 1, #raw do\n      st, kb = nextByte(st)\n      enc[j] = string.char((raw[j] + kb) % 256) -- additive stream cipher\n    end\n    slices[i] = table.concat(enc)\n  end\n  proto.sealed = { slices = slices, n = n, sk = sk }\n  proto.code = nil\n\n  -- Constant encryption: string constants (the dump target  URLs, remote names,\n  -- keys, messages) are encrypted and stored behind a proxy that decrypts on\n  -- access, so they are never resident in plaintext even after a devirtualizer\n  -- recovers the bytecode. Non-strings pass through. Strings intern in Lua, so\n  -- decrypting the same constant twice yields the same object (identity safe).\n  local K = proto.consts\n  local realK, hasEnc, nk = {}, false, #K\n  for i = 1, nk do\n    local v = K[i]\n    local t = type(v)\n    if t == 'string' then\n      hasEnc = true\n      local st, kb = seedK(sk, i), nil\n      local out = {}\n      for j = 1, #v do st, kb = nextByte(st); out[j] = string.char((v:byte(j) + kb) % 256) end\n      realK[i] = { s = table.concat(out) }\n    elseif t == 'number' and v == v and v <= 4503599627370496 and v >= -4503599627370496\n        and math.floor(v) == v then\n      -- integer-valued number: hide behind an additive keystream mask (fractional\n      -- / inf / nan pass through untouched to avoid any precision or subtype bug)\n      hasEnc = true\n      realK[i] = { n = v + maskFor(sk, i) }\n    else\n      realK[i] = v\n    end\n  end\n  if hasEnc then\n    proto.consts = setmetatable({}, { __index = function(_, i)\n      local e = realK[i]\n      if type(e) == 'table' then\n        if e.n ~= nil then return e.n - maskFor(sk, i) end -- numeric constant\n        local st, kb = seedK(sk, i), nil                   -- string constant\n        local enc, o = e.s, {}\n        for j = 1, #enc do st, kb = nextByte(st); o[j] = string.char((enc:byte(j) - kb) % 256) end\n        return table.concat(o)\n      end\n      return e\n    end })\n  end\n\n  for _, child in ipairs(proto.protos) do M.seal(child, sk) end\nend\n\n-- Decode a single instruction i from a sealed proto  called right before it\n-- runs. Returns a fresh {op=,a=,...} table (a short-lived local at the call site).\nfunction M.decode(sealed, i)\n  local s = sealed.slices[i]\n  local st, kb = seed1(sealed.sk, i), nil\n  local len = #s\n  local bytes = {}\n  for k = 1, len do\n    st, kb = nextByte(st)\n    bytes[k] = (s:byte(k) - kb) % 256 -- inverse of additive cipher\n  end\n  local op = bytes[1]\n  local ins = { op = op }\n  local rp = 2\n  for _, f in ipairs(Opcodes.operands[op]) do\n    local x, shift = 0, 1\n    while true do\n      local bb = bytes[rp]; rp = rp + 1\n      x = x + (bb % 128) * shift\n      if bb < 128 then break end\n      shift = shift * 128\n    end\n    ins[f] = (x % 2 == 0) and math.floor(x / 2) or -math.floor((x + 1) / 2) -- un-zig-zag\n  end\n  return ins\nend\n\nreturn M\n","vm":"-- luau-vm/src/vm.lua\n-- Register-based interpreter for the ferret custom bytecode.\n--\n-- Design choices that buy correctness + Luau compatibility cheaply:\n--   * A VM closure is a REAL Lua function (see makeClosure) that runs `execute`.\n--     So VM and host functions are invoked identically, and metamethods, pcall,\n--     coroutines, table.sort(cmp), etc. all work because a compiled function is\n--     an ordinary callable Lua value.\n--   * All operators use the host's native ops (R[b] + R[c], R[b][k], #x, ..),\n--     so metatables (__index/__add/__concat/__len/) are honored by the host.\n--   * Captured locals & upvalues are \"cells\" ({v=...}); closures capture cell\n--     references, so no open/closed-upvalue bookkeeping is needed.\n--\n-- table.pack/unpack carry multiple values across call boundaries, so multiple\n-- returns and varargs are exact.\n\nlocal Opcodes = require('opcodes')\nlocal Bit = require('bitops')\nlocal Seal = require('seal')\nlocal Op = Opcodes.Op\n\nlocal pack = table.pack or function(...) return { n = select('#', ...), ... } end\nlocal unpack = table.unpack or unpack\n\nlocal VM = {}\n\n-- Optional dynamic opcode profiler. When non-nil, the dispatch loop counts\n-- executed opcodes into it (one nil-check per instruction when disabled).\nlocal PROF = nil\nfunction VM.setProfile(counters) PROF = counters end\n\n-- Forward declaration: execute runs a proto with its upvalues/env/args.\nlocal execute\n\n-- Wrap a proto + captured upvalues + env into a callable Lua value.\nlocal function makeClosure(proto, upvals, env)\n  return function(...)\n    local args = pack(...)\n    local res = execute(proto, upvals, env, args, args.n)\n    return unpack(res, 1, res.n)\n  end\nend\n\n-- The interpreter. Returns a packed results table {..., n=}.\nexecute = function(proto, upvals, env, args, argN)\n  local code = proto.code\n  local sealed = proto.sealed -- when set, instructions are decoded on demand (seal.lua)\n  local K = proto.consts\n  local protos = proto.protos\n  local R = {}\n\n  local np = proto.numparams\n  for i = 0, np - 1 do R[i] = args[i + 1] end\n\n  local varargs, varargN = nil, 0\n  if proto.isVararg then\n    varargs = {}\n    for i = np + 1, argN do\n      varargN = varargN + 1\n      varargs[varargN] = args[i]\n    end\n  end\n\n  local top = 0\n  local pc = 1\n\n  while true do\n    -- JIT/streamed: decode exactly this instruction now, then let it be reclaimed\n    local ins = sealed and Seal.decode(sealed, pc) or code[pc]\n    pc = pc + 1\n    local op = ins.op\n    local a = ins.a\n    if PROF then PROF[op] = (PROF[op] or 0) + 1 end\n\n    -- Dispatch is ordered hottest-first: in a linear if/elseif chain each branch\n    -- costs one comparison, so the common ops (calls, arithmetic, compares,\n    -- jumps, moves, loads) are checked before the rare ones. See docs/perf.md.\n    if op == Op.MOVE then R[a] = R[ins.b]\n    elseif op == Op.CALL then\n      local fn = R[a]\n      local b = ins.b\n      local nargs = (b == 0) and (top - a - 1) or (b - 1)\n      local callArgs = {}\n      for i = 1, nargs do callArgs[i] = R[a + i] end\n      local res = pack(fn(unpack(callArgs, 1, nargs)))\n      local c = ins.c\n      if c == 0 then\n        for i = 1, res.n do R[a + i - 1] = res[i] end\n        top = a + res.n\n      else\n        for i = 1, c - 1 do R[a + i - 1] = res[i] end\n      end\n    elseif op == Op.RETURN then\n      local b = ins.b\n      local nret = (b == 0) and (top - a) or (b - 1)\n      local out = {}\n      for i = 1, nret do out[i] = R[a + i - 1] end\n      out.n = nret\n      return out\n    elseif op == Op.ADD then R[a] = R[ins.b] + R[ins.c]\n    elseif op == Op.SUB then R[a] = R[ins.b] - R[ins.c]\n    elseif op == Op.LT then R[a] = (R[ins.b] < R[ins.c])\n    elseif op == Op.JMPIFNOT then if not R[a] then pc = pc + ins.sbx end\n    elseif op == Op.JMPIF then if R[a] then pc = pc + ins.sbx end\n    elseif op == Op.JMP then pc = pc + ins.sbx\n    elseif op == Op.LOADINT then R[a] = ins.sbx\n    elseif op == Op.LOADK then R[a] = K[ins.bx]\n    elseif op == Op.GETGLOBAL then R[a] = env[K[ins.bx]]\n    elseif op == Op.GETCELL then R[a] = R[ins.b].v\n    elseif op == Op.SETCELL then R[a].v = R[ins.b]\n    elseif op == Op.GETUPVAL then R[a] = upvals[ins.b].v\n    elseif op == Op.SETUPVAL then upvals[ins.b].v = R[a]\n    elseif op == Op.MUL then R[a] = R[ins.b] * R[ins.c]\n    elseif op == Op.LE then R[a] = (R[ins.b] <= R[ins.c])\n    elseif op == Op.EQ then R[a] = (R[ins.b] == R[ins.c])\n    elseif op == Op.GETFIELD then R[a] = R[ins.b][K[ins.bx]]\n    elseif op == Op.GETTABLE then R[a] = R[ins.b][R[ins.c]]\n    elseif op == Op.FORLOOP then\n      local step = R[a + 2]\n      local idx = R[a] + step\n      R[a] = idx\n      local limit = R[a + 1]\n      if (step >= 0 and idx <= limit) or (step < 0 and idx >= limit) then\n        R[a + 3] = idx\n        pc = pc + ins.sbx\n      end\n    elseif op == Op.FORPREP then\n      if R[a + 2] == 0 then error(\"'for' step is zero\") end\n      R[a] = R[a] - R[a + 2]\n      pc = pc + ins.sbx\n\n    --  colder opcodes \n    elseif op == Op.SETTABLE then R[a][R[ins.b]] = R[ins.c]\n    elseif op == Op.SETFIELD then R[a][K[ins.bx]] = R[ins.c]\n    elseif op == Op.SETGLOBAL then env[K[ins.bx]] = R[a]\n    elseif op == Op.NEWTABLE then R[a] = {}\n    elseif op == Op.SELF then\n      R[a + 1] = R[ins.b]\n      R[a] = R[ins.b][K[ins.c]]\n    elseif op == Op.SETLIST then\n      local t = R[a]\n      local count = ins.b\n      if count == 0 then count = top - a - 1 end\n      local base = ins.c\n      for i = 1, count do t[base + i] = R[a + i] end\n    elseif op == Op.CLOSURE then\n      local child = protos[ins.bx]\n      local newUp = {}\n      for i, d in ipairs(child.upvals) do\n        if d.kind == 'reg' then newUp[i] = R[d.index]\n        else newUp[i] = upvals[d.index] end\n      end\n      R[a] = makeClosure(child, newUp, env)\n    elseif op == Op.VARARG then\n      local b = ins.b\n      local count = (b == 0) and varargN or (b - 1)\n      for i = 1, count do R[a + i - 1] = varargs[i] end\n      if b == 0 then top = a + varargN end\n    elseif op == Op.NEWCELL then R[a] = { v = R[a] }\n    elseif op == Op.LOADBOOL then R[a] = (ins.b ~= 0)\n    elseif op == Op.LOADNIL then for i = a, a + ins.b do R[i] = nil end\n    elseif op == Op.DIV then R[a] = R[ins.b] / R[ins.c]\n    elseif op == Op.MOD then R[a] = R[ins.b] % R[ins.c]\n    elseif op == Op.POW then R[a] = R[ins.b] ^ R[ins.c]\n    elseif op == Op.IDIV then R[a] = math.floor(R[ins.b] / R[ins.c])\n    elseif op == Op.BAND then R[a] = Bit.band(R[ins.b], R[ins.c])\n    elseif op == Op.BOR then R[a] = Bit.bor(R[ins.b], R[ins.c])\n    elseif op == Op.BXOR then R[a] = Bit.bxor(R[ins.b], R[ins.c])\n    elseif op == Op.SHL then R[a] = Bit.lshift(R[ins.b], R[ins.c])\n    elseif op == Op.SHR then R[a] = Bit.rshift(R[ins.b], R[ins.c])\n    elseif op == Op.CONCAT then\n      local s = R[ins.b]\n      for i = ins.b + 1, ins.c do s = s .. R[i] end\n      R[a] = s\n    elseif op == Op.UNM then R[a] = -R[ins.b]\n    elseif op == Op.NOT then R[a] = not R[ins.b]\n    elseif op == Op.LEN then R[a] = #R[ins.b]\n    elseif op == Op.BNOT then R[a] = Bit.bnot(R[ins.b])\n    elseif op == Op.TAILCALL then\n      local fn = R[a]\n      local b = ins.b\n      local nargs = (b == 0) and (top - a - 1) or (b - 1)\n      local callArgs = {}\n      for i = 1, nargs do callArgs[i] = R[a + i] end\n      return pack(fn(unpack(callArgs, 1, nargs)))\n    elseif op == Op.TFORPREP then\n      -- Luau generalized iteration: `for vars in exp do`. If the iterator value\n      -- is already a function, keep the classic protocol (pairs/ipairs/custom).\n      -- Otherwise resolve an __iter metamethod, or fall back to iterating a plain\n      -- table via `next`  matching Luau, where a bare table is iterable.\n      local it = R[a]\n      if type(it) ~= 'function' then\n        local mt = getmetatable(it)\n        local iterMM = mt and mt.__iter\n        if iterMM then\n          local f, s, c = iterMM(it)\n          R[a], R[a + 1], R[a + 2] = f, s, c\n        elseif type(it) == 'table' then\n          R[a], R[a + 1], R[a + 2] = next, it, nil\n        end\n        -- else: leave as-is; TFORCALL will raise, as Luau does for a non-iterable\n      end\n    elseif op == Op.TFORCALL then\n      local fn = R[a]\n      local res = pack(fn(R[a + 1], R[a + 2]))\n      for i = 1, ins.c do R[a + 2 + i] = res[i] end\n    elseif op == Op.TFORLOOP then\n      if R[a + 3] ~= nil then\n        R[a + 2] = R[a + 3]\n        pc = pc + ins.sbx\n      end\n    elseif op == Op.NOP then -- nothing\n    else\n      error('ferret-vm: bad opcode ' .. Opcodes.mnemonic(op) .. ' at pc ' .. (pc - 1))\n    end\n  end\nend\n\n-- Public: build a callable from a top-level proto and an environment.\nfunction VM.load(proto, env)\n  env = env or _ENV or _G\n  return makeClosure(proto, {}, env)\nend\n\nVM.execute = execute\nVM.makeClosure = makeClosure\nreturn VM\n","api":"-- luau-vm/src/api.lua\n-- Convenience front end: source -> bytecode -> callable, with no loadstring.\n\nlocal Compiler = require('compiler')\nlocal VM = require('vm')\nlocal Serializer = require('serializer')\n\nlocal API = {}\n\nfunction API.compile(src, chunkName)\n  return Compiler.compile(src, chunkName)\nend\n\nfunction API.load(src, env, chunkName)\n  return VM.load(Compiler.compile(src, chunkName), env or _G)\nend\n\n-- Compile to a portable binary bytecode string (no loadstring on either side).\nfunction API.serialize(src, chunkName)\n  return Serializer.serialize(Compiler.compile(src, chunkName))\nend\n\n-- Load and run bytecode produced by API.serialize.\nfunction API.loadBytecode(bytes, env)\n  return VM.load(Serializer.deserialize(bytes), env or _G)\nend\n\nfunction API.run(src, env, chunkName, ...)\n  return API.load(src, env, chunkName)(...)\nend\n\nAPI.VM = VM\nAPI.Compiler = Compiler\nAPI.Serializer = Serializer\nreturn API\n","harden":"-- luau-vm/src/harden.lua\n-- Per-build hardening primitives for the VM bundler. These make two emitted\n-- builds of the same source differ, and raise the cost of a generic\n-- devirtualizer, without touching the (validated) compiler/VM core:\n--\n--   * opcode permutation   the serialized bytecode uses a per-build opcode\n--     numbering, so tooling keyed to the canonical opcode set can't read it.\n--   * bytecode encryption  a custom GraniteRNG XOR keystream over the whole\n--     serialized blob, so a base64 decode no longer reveals the proto tables.\n--   * key factoring        the keystream seed is emitted as an arithmetic\n--     expression, not a single grep-able literal.\n--   * comment stripping    the bundled interpreter ships without its\n--     self-documenting comments, so opcode semantics aren't handed over.\n--\n-- None of this is unbreakable (no self-contained client-side obfuscator can\n-- be  the key and decoder must be present to run). It defeats automated /\n-- canned tooling and casual copy-paste, which is the realistic threat.\n\nlocal Bit = require('bitops')\n\nlocal H = {}\n\n-- Hardened-bundle format version. Bumped when the emitted envelope (version +\n-- build fingerprint + compression + multi-round cipher) changes shape. Emitted\n-- into the sealed payload and gated by the decoder, so a bundle produced by a\n-- newer builder refuses to run on a mismatched decoder instead of misbehaving.\nH.VM_VERSION = 2\n\n--  GraniteRNG: our own PRNG (not Park-Miller / not any named generator) \n-- A full-period LCG over 2^32 (GA % 4 == 1, GC odd) whose raw output is run\n-- through a custom multiply-rotate-multiply avalanche so the emitted bytes mix\n-- well. Every product stays < 2^53, so the sequence is bit-identical in Lua\n-- 5.1-5.4 doubles AND Luau doubles. Uses no bit32 and no recognizable constant.\nlocal GA, GC = 3218467781, 2596069031     -- LCG multiplier / increment\nlocal GM1, GM2 = 3812015801, 1274126177   -- avalanche multipliers (odd)\nlocal TWO32 = 4294967296\n\n-- (a * b) mod 2^32, computed split so the intermediate stays exact in doubles.\nlocal function gmul(a, b)\n  local al = a % 65536\n  return ((al * b) + (((a - al) / 65536 * b) % 65536) * 65536) % TWO32\nend\n\n-- Custom avalanche: multiply, swap the two 16-bit halves, multiply again.\nlocal function gmix(s)\n  local x = gmul(s, GM1)\n  x = (x % 65536) * 65536 + (x - x % 65536) / 65536\n  return gmul(x, GM2)\nend\n\n-- Stateful generator. `int`/`byte` advance the LCG and return a mixed value;\n-- `next` returns the full mixed 32-bit word (used to draw sub-seeds).\nfunction H.prng(seed)\n  local st = seed % TWO32\n  local function step() st = (gmul(st, GA) + GC) % TWO32; return gmix(st) end\n  return {\n    next = function() return step() end,\n    int = function(n) return step() % n end,\n    byte = function() return step() % 256 end,\n  }\nend\n\nH.gmul = gmul\nH.gmix = gmix\n\n-- Build a per-build opcode permutation for `count` canonical opcodes (1..count).\n-- Returns fwd (canonical -> emitted byte) and inv (emitted byte -> canonical),\n-- each opcode mapped to a distinct byte in [1, 255].\nfunction H.opPermutation(count, rng)\n  local pool = {}\n  for b = 1, 255 do pool[b] = b end\n  -- Fisher-Yates shuffle the byte pool\n  for i = 255, 2, -1 do\n    local j = rng.int(i) + 1\n    pool[i], pool[j] = pool[j], pool[i]\n  end\n  local fwd, inv = {}, {}\n  for op = 1, count do\n    local b = pool[op]\n    fwd[op] = b\n    inv[b] = op\n  end\n  return fwd, inv\nend\n\n-- Instruction mutation: like opPermutation, but each opcode gets 1..aliasMax\n-- interchangeable byte encodings. The serializer picks among them per\n-- instruction, so one opcode shows up as several different bytes  defeating a\n-- byte-frequency 1:1 opcode map. Returns fwd (op -> { bytes }) and inv (any\n-- alias byte -> canonical op). Requires count*aliasMax <= 255.\nfunction H.opMutationMap(count, rng, aliasMax)\n  aliasMax = aliasMax or 3\n  local pool = {}\n  for b = 1, 255 do pool[b] = b end\n  for i = 255, 2, -1 do\n    local j = rng.int(i) + 1\n    pool[i], pool[j] = pool[j], pool[i]\n  end\n  local fwd, inv, idx = {}, {}, 0\n  for op = 1, count do\n    local k = 1 + rng.int(aliasMax)\n    local list = {}\n    for _ = 1, k do\n      if idx >= 255 then break end\n      idx = idx + 1\n      local b = pool[idx]\n      list[#list + 1] = b\n      inv[b] = op\n    end\n    fwd[op] = list\n  end\n  return fwd, inv\nend\n\n-- XOR `data` with a GraniteRNG keystream seeded by `seed`. Symmetric: the\n-- emitted bootstrap runs the identical routine to decrypt.\nfunction H.encrypt(data, seed)\n  local rng = H.prng(seed)\n  local out, len = {}, #data\n  for i = 1, len do\n    out[i] = string.char(Bit.bxor(data:byte(i), rng.byte()))\n  end\n  return table.concat(out)\nend\n\n--  custom multi-stage bytecode cipher (\"GraniteCipher\") \n-- A per-build, fully custom cipher over the serialized bytecode blob. Chain:\n--\n--   plaintext bytes\n--       (1) per-build random seed  -> (2) key schedule: derive sub-seeds\n--     \n--   (3) byte permutation     keyed Fisher-Yates over byte POSITIONS\n--     \n--   (4) byte substitution    per-build bijective S-box over byte VALUES\n--     \n--   (5) stream masking        GraniteRNG keystream XOR with cipher-feedback\n--                             chaining (CBC-like), so one flipped byte\n--                             avalanches through the rest\n--     \n--   (6) integrity checksum    custom 32-bit rolling sum prepended\n--     \n--   (7) base64                (done by the bundler)\n--\n-- Every stage is regenerable from the sub-seeds alone, so the emitted decoder\n-- ships only three small factored seeds + an IV  never the S-box, permutation\n-- table, or keystream  and inverts the chain in pure Luau (no loadstring).\n\n-- Deterministic bijective S-box: Fisher-Yates over 0..255 driven by `seed`.\n-- Returns the forward map s[v] (0-indexed values held at 0-indexed keys).\nfunction H.sbox(seed)\n  local rng = H.prng(seed)\n  local s = {}\n  for i = 0, 255 do s[i] = i end\n  for i = 255, 1, -1 do\n    local j = rng.int(i + 1) -- 0..i\n    s[i], s[j] = s[j], s[i]\n  end\n  return s\nend\n\n-- Swap partners for a keyed position permutation of `n` bytes. js[i] (i=2..n)\n-- is the 1-based partner used at step i. Applying the swaps for i=n..2 permutes;\n-- applying them for i=2..n inverts (each swap is its own inverse).\nfunction H.permSwaps(seed, n)\n  local rng = H.prng(seed)\n  local js = {}\n  for i = n, 2, -1 do js[i] = rng.int(i) + 1 end -- 1..i\n  return js\nend\n\n-- Our own 32-bit integrity checksum (\"GraniteSum\")  NOT djb2/FNV/CRC. Two\n-- coupled accumulators: lane `a` folds each byte with a custom multiplier, lane\n-- `b` sums the running `a` (so position matters and one flipped byte avalanches\n-- through the tail). Products stay < 2^53, exact in Lua 5.1-5.4 + Luau doubles.\n-- Authenticates the *ciphertext* before any decode.\nfunction H.checksum(s)\n  local a, b = 19088743, 1985229328\n  for i = 1, #s do\n    a = (a * 178711 + s:byte(i) + 1) % 4294967296\n    b = (b + a) % 4294967296\n  end\n  return (a + gmul(b, 40503)) % 4294967296\nend\n\n--  custom bytecode compression (\"GraniteRLE\") \n-- A tiny run-length scheme with a self-describing escape byte, applied to the\n-- serialized bytecode BEFORE encryption so the plaintext exposed after a decrypt\n-- is still compressed (and smaller). Not zlib/LZ77/any named codec. Layout:\n--   flag(1)  0 = stored (raw bytes follow), 1 = RLE\n--   RLE body: esc(1) then a stream where `esc,val,count` means val x count and\n--             any other byte is a literal (literals are never the esc byte).\n-- `esc` is chosen as the least-frequent byte so forced escapes are minimal; the\n-- stored fallback guarantees output never grows by more than one byte.\nfunction H.compress(s)\n  local n = #s\n  if n == 0 then return string.char(0) end\n  local freq = {}\n  for v = 0, 255 do freq[v] = 0 end\n  for i = 1, n do local v = s:byte(i); freq[v] = freq[v] + 1 end\n  local esc, best = 0, freq[0]\n  for v = 1, 255 do if freq[v] < best then best = freq[v]; esc = v end end\n  local out, i = {}, 1\n  while i <= n do\n    local b = s:byte(i)\n    local run = 1\n    while i + run <= n and s:byte(i + run) == b and run < 255 do run = run + 1 end\n    if run >= 4 or b == esc then\n      out[#out + 1] = string.char(esc, b, run)\n    else\n      for _ = 1, run do out[#out + 1] = string.char(b) end\n    end\n    i = i + run\n  end\n  local rle = string.char(esc) .. table.concat(out)\n  if #rle + 1 < n + 1 then return string.char(1) .. rle end\n  return string.char(0) .. s\nend\n\nfunction H.decompress(s)\n  local flag = s:byte(1)\n  local rest = s:sub(2)\n  if flag == 0 then return rest end\n  local esc = rest:byte(1)\n  local out, i, n = {}, 2, #rest\n  while i <= n do\n    local c = rest:byte(i)\n    if c == esc then\n      local val, cnt = rest:byte(i + 1), rest:byte(i + 2)\n      out[#out + 1] = string.rep(string.char(val), cnt)\n      i = i + 3\n    else\n      out[#out + 1] = string.char(c)\n      i = i + 1\n    end\n  end\n  return table.concat(out)\nend\n\n-- Pack a 32-bit value big-endian.\nlocal function u32be(x)\n  x = x % 4294967296\n  return string.char(\n    math.floor(x / 16777216) % 256,\n    math.floor(x / 65536) % 256,\n    math.floor(x / 256) % 256,\n    x % 256)\nend\nH.u32be = u32be\n\n-- Wrap already-compressed bytecode in a verifiable envelope: a version byte and\n-- a 4-byte build fingerprint (GraniteSum over version+payload). The decoder\n-- checks the version (VM versioning) and the fingerprint (anti-tamper: editing\n-- the payload, seeds, or version after the fact fails closed with a clear\n-- error, instead of silently running altered bytecode).\nfunction H.envelope(payload)\n  local v = string.char(H.VM_VERSION)\n  local fp = H.checksum(v .. payload)\n  return v .. u32be(fp) .. payload\nend\n\n-- Apply one cipher round (byte permutation -> S-box -> chained stream mask) to\n-- the byte array `a` (length n) in place, using the given sub-seeds/iv.\nlocal function sealRound(a, n, permSeed, sboxSeed, maskSeed, iv)\n  local js = H.permSwaps(permSeed, n)\n  for i = n, 2, -1 do a[i], a[js[i]] = a[js[i]], a[i] end\n  local sbox = H.sbox(sboxSeed)\n  for i = 1, n do a[i] = sbox[a[i]] end\n  local mrng = H.prng(maskSeed)\n  local prev = iv\n  for i = 1, n do\n    local c = Bit.bxor(Bit.bxor(a[i], mrng.byte()), prev)\n    a[i] = c\n    prev = c\n  end\nend\n\n-- Seal `plain` with the full chain using per-build sub-seeds drawn from `rng`.\n-- `rounds` (default 1) stacks independent cipher layers, each with its own\n-- sub-seeds, so peeling one layer leaves another. Returns the sealed byte\n-- string (checksum-prefixed ciphertext) and the per-layer params the emitted\n-- decoder needs to invert it (outermost layer last, so the decoder peels the\n-- list in reverse).\nfunction H.seal(plain, rng, rounds)\n  rounds = rounds or 1\n  local n = #plain\n  local a = {}\n  for i = 1, n do a[i] = plain:byte(i) end\n\n  local layers = {}\n  for _ = 1, rounds do\n    local L = {\n      permSeed = rng.next(),\n      sboxSeed = rng.next(),\n      maskSeed = rng.next(),\n      iv = rng.byte(),\n    }\n    sealRound(a, n, L.permSeed, L.sboxSeed, L.maskSeed, L.iv)\n    layers[#layers + 1] = L\n  end\n\n  local body = {}\n  for i = 1, n do body[i] = string.char(a[i]) end\n  local cipher = table.concat(body)\n\n  -- (6) integrity checksum over the whole ciphertext, 4 bytes big-endian\n  local head = u32be(H.checksum(cipher))\n  -- Back-compat single-layer fields plus the full layer list.\n  local first = layers[1] or {}\n  return head .. cipher, {\n    rounds = rounds,\n    layers = layers,\n    permSeed = first.permSeed,\n    sboxSeed = first.sboxSeed,\n    maskSeed = first.maskSeed,\n    iv = first.iv,\n  }\nend\n\n-- Emit `seed` as an arithmetic expression `(m*q+r)` rather than a bare literal,\n-- so the keystream seed is not directly grep-able in the output. Factors are\n-- kept < 2^31 so the product is exact in every target runtime.\nfunction H.factorKey(seed, rng)\n  local m = rng.int(40000) + 4096         -- 4096 .. 44095\n  local q = math.floor(seed / m)\n  local r = seed % m\n  return string.format('(%d*%d+%d)', m, q, r)  -- == m*q + r == seed\nend\n\n-- Render a { byte = canonical } Lua table literal (the inverse opcode map the\n-- bootstrap hands to the deserializer).\nfunction H.invMapLiteral(inv)\n  local parts = {}\n  for b, op in pairs(inv) do parts[#parts + 1] = string.format('[%d]=%d', b, op) end\n  return '{' .. table.concat(parts, ',') .. '}'\nend\n\n-- Strip Lua comments (line and long-bracket) and blank/whitespace-only lines\n-- from `src`, correctly skipping over string literals and long-bracket strings\n-- so code is never touched. Returns the stripped source. Callers should still\n-- guard the result with load() and fall back to the original on any surprise.\nfunction H.stripComments(src)\n  local out, i, n = {}, 1, #src\n  local function peek(k) return src:sub(i + (k or 0), i + (k or 0)) end\n  -- match a long-bracket opener at position i: returns level (>=0) or nil\n  local function longOpen()\n    if peek() ~= '[' then return nil end\n    local j, eq = i + 1, 0\n    while src:sub(j, j) == '=' do eq = eq + 1; j = j + 1 end\n    if src:sub(j, j) == '[' then return eq end\n    return nil\n  end\n  local function skipLong(eq)\n    local close = ']' .. string.rep('=', eq) .. ']'\n    local at = src:find(close, i, true)\n    return at and (at + #close) or (n + 1)\n  end\n  while i <= n do\n    local c = peek()\n    if c == '-' and peek(1) == '-' then\n      -- comment: long or line\n      i = i + 2\n      local eq = longOpen()\n      if eq ~= nil then\n        i = i + eq + 2\n        i = skipLong(eq)\n      else\n        while i <= n and src:sub(i, i) ~= '\\n' do i = i + 1 end\n      end\n    elseif c == '\"' or c == \"'\" then\n      out[#out + 1] = c; i = i + 1\n      while i <= n do\n        local d = src:sub(i, i)\n        out[#out + 1] = d; i = i + 1\n        if d == '\\\\' then out[#out + 1] = src:sub(i, i); i = i + 1\n        elseif d == c then break end\n      end\n    else\n      local eq = longOpen()\n      if eq ~= nil then\n        local from = i\n        i = i + eq + 2\n        local to = skipLong(eq)\n        out[#out + 1] = src:sub(from, to - 1)\n        i = to\n      else\n        out[#out + 1] = c; i = i + 1\n      end\n    end\n  end\n  -- drop trailing whitespace on each line and blank lines\n  local text = table.concat(out)\n  local kept = {}\n  for line in (text .. '\\n'):gmatch('([^\\n]*)\\n') do\n    local trimmed = line:gsub('%s+$', '')\n    if trimmed:match('%S') then kept[#kept + 1] = trimmed end\n  end\n  return table.concat(kept, '\\n')\nend\n\nreturn H\n","webbundle":"-- luau-vm/src/webbundle.lua\n-- Browser-friendly bundler: compile a Luau source string to a self-contained,\n-- HARDENED VM-protected script. Unlike tools/bundle.lua it never touches the\n-- filesystem; the runtime module sources are passed in (the website embeds\n-- them), so this runs unchanged inside Fengari (Lua-in-JS) in the browser.\n--\n-- Hardening applied per build (see harden.lua): opcode permutation, the custom\n-- multi-stage GraniteCipher over the serialized blob (byte permutation -> S-box\n-- -> chained stream mask -> GraniteSum checksum), a per-build permuted output\n-- alphabet, factored (non-literal) sub-seeds, randomized decoder variable names,\n-- and comment-stripped runtime sources. Every primitive is our own (no bit32,\n-- no Base64/DJB2/FNV/Park-Miller). Still no loadstring, and the original source\n-- is never reconstructed  the logic exists only as encrypted bytecode.\n\nlocal Compiler = require('compiler')\nlocal Serializer = require('serializer')\nlocal Opcodes = require('opcodes')\nlocal Harden = require('harden')\n\nlocal M = {}\n\n-- Custom output encoding: a 64-symbol pool (letters/digits + `_` `~`, all safe\n-- inside a single-quoted Lua string AND a Lua pattern char-class) that is\n-- permuted per build, so the output alphabet is never the standard Base64 one.\nlocal B64POOL = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789_~'\n\n-- Per-build permutation of the symbol pool (keyed Fisher-Yates over `rng`).\nlocal function permuteAlphabet(rng)\n  local a = {}\n  for i = 1, 64 do a[i] = B64POOL:sub(i, i) end\n  for i = 64, 2, -1 do\n    local j = rng.int(i) + 1\n    a[i], a[j] = a[j], a[i]\n  end\n  return table.concat(a)\nend\n\n-- Base64-style 6-bit encoder over an arbitrary 64-char `alpha` (pad char '=').\nlocal function encodeWith(alpha, data)\n  local out, len = {}, #data\n  local function sym(k) return alpha:sub(k + 1, k + 1) end\n  for i = 1, len, 3 do\n    local b1 = data:byte(i)\n    local b2 = i + 1 <= len and data:byte(i + 1) or 0\n    local b3 = i + 2 <= len and data:byte(i + 2) or 0\n    local n = b1 * 65536 + b2 * 256 + b3\n    out[#out + 1] = sym(math.floor(n / 262144) % 64)\n    out[#out + 1] = sym(math.floor(n / 4096) % 64)\n    out[#out + 1] = i + 1 <= len and sym(math.floor(n / 64) % 64) or '='\n    out[#out + 1] = i + 2 <= len and sym(n % 64) or '='\n  end\n  return table.concat(out)\nend\n\n-- Pick a per-build seed. Deterministic when opts.seed is given (tests); else\n-- derived from wall clock + math.random so each build differs.\nlocal function pickSeed(opts)\n  if opts and opts.seed then return opts.seed end\n  local t = (os and os.time and os.time()) or 0\n  local r = math.random(1, 2147483646)\n  local s = (t * 2654435761 + r) % 2147483647\n  if s <= 0 then s = s + 2147483646 end\n  return s\nend\n\n-- Strip comments from a runtime source, but only if the result still parses.\nlocal function safeStrip(src)\n  local stripped = Harden.stripComments(src)\n  local chunk = (loadstring or load)(stripped)\n  if chunk then return stripped end\n  return src\nend\n\n-- Per-build fresh identifier generator: `_` + 5 chars from [a-z0-9]. The leading\n-- underscore + lowercase means a name can never collide with a Lua keyword, a\n-- stdlib global (string/math/table/...), `_ENV`/`_G`, or `require`, so the\n-- emitted decoder's locals are unrecognizable and differ every build.\nlocal function idGen(rng)\n  local pool = 'abcdefghijklmnopqrstuvwxyz0123456789'\n  local used = {}\n  return function()\n    while true do\n      local s = '_'\n      for _ = 1, 5 do local d = rng.int(#pool); s = s .. pool:sub(d + 1, d + 1) end\n      if not used[s] then used[s] = true; return s end\n    end\n  end\nend\n\n-- A single inert junk statement: a fresh, never-referenced local whose value is\n-- deterministic dead code (arithmetic, a dummy function, or a small table). Adds\n-- per-build noise between the real decoder statements without any side effect,\n-- so a reader can't tell signal from filler by shape alone.\nlocal function junkStmt(g, rng)\n  local kind = rng.int(3)\n  local name = g()\n  if kind == 0 then\n    return 'local ' .. name .. '=' .. (rng.int(90000) + 10000) .. '*'\n      .. (rng.int(9000) + 1000) .. '+' .. rng.int(1000)\n  elseif kind == 1 then\n    return 'local function ' .. name .. '(' .. g() .. ') return '\n      .. rng.int(100000) .. ' end'\n  else\n    return 'local ' .. name .. '={' .. rng.int(1000) .. ',' .. rng.int(1000)\n      .. ',' .. rng.int(1000) .. '}'\n  end\nend\n\n-- runtimeSrc: table of Lua source strings for { opcodes, bitops, serializer, vm }.\nfunction M.bundle(src, runtimeSrc, chunkName, opts)\n  local seed = pickSeed(opts)\n  local rng = Harden.prng(seed)\n\n  -- 1. compile, 2. permute opcodes, 3. serialize with the permutation,\n  -- 4. compress + wrap in a versioned, fingerprinted envelope,\n  -- 5. seal with the multi-round GraniteCipher, 6. encode (permuted alphabet).\n  -- Opaque-predicate injection (bogus, always-taken/never-taken control flow)\n  -- uses an INDEPENDENT prng derived from the build seed, so it does not disturb\n  -- the main rng stream used for opcode mutation / cipher below. Deterministic\n  -- per build; disable with opts.opaque == false.\n  local copts = { chunkName = chunkName }\n  if not (opts and opts.opaque == false) then\n    copts.opaque = Harden.prng((seed + 2166136261) % 4294967296)\n    copts.opaqueDensity = (opts and opts.opaqueDensity) or 350\n  end\n  local proto = Compiler.compile(src, chunkName or 'input', copts)\n  -- Basic-block REORDERING (semantics-exact relative of control-flow\n  -- flattening): scramble the physical block layout so byte order no longer\n  -- matches control flow. Applied first so junk fills the reordered layout.\n  if not (opts and opts.flatten == false) then\n    require('obfuscate').flatten(proto, Harden.prng((seed + 2654435761) % 4294967296))\n  end\n  -- Bytecode JUNK: splice provably-unreachable dead opcodes after unconditional\n  -- transfers, so a linear-sweep disassembler decodes filler that never runs.\n  -- Independent prng again; disable with opts.junk == false.\n  if not (opts and opts.junk == false) then\n    require('obfuscate').junk(proto, Harden.prng((seed + 40503) % 4294967296),\n      { density = (opts and opts.junkDensity) or 600, maxRun = 3 })\n  end\n  -- opcode MUTATION: each opcode has several interchangeable byte encodings,\n  -- picked per instruction, so one opcode appears as different bytes.\n  local fwd, inv = Harden.opMutationMap(Opcodes.count, rng, 3)\n  local bc = Serializer.serialize(proto, fwd, function() return rng.int(1000003) end)\n  local env = Harden.envelope(Harden.compress(bc))\n  local rounds = (opts and opts.rounds) or 2\n  local sealed, cp = Harden.seal(env, rng, rounds)\n  local alpha = permuteAlphabet(rng)\n  local payload = encodeWith(alpha, sealed)\n\n  -- per-layer sub-seeds emitted as arithmetic expressions (not grep-able\n  -- literals), as Lua table constructors the decoder peels in reverse.\n  local function exprList(field)\n    local t = {}\n    for i = 1, #cp.layers do t[i] = Harden.factorKey(cp.layers[i][field], rng) end\n    return '{' .. table.concat(t, ',') .. '}'\n  end\n  local permList = exprList('permSeed')\n  local sboxList = exprList('sboxSeed')\n  local maskList = exprList('maskSeed')\n  local ivParts = {}\n  for i = 1, #cp.layers do ivParts[i] = tostring(cp.layers[i].iv) end\n  local ivList = '{' .. table.concat(ivParts, ',') .. '}'\n  local invLit = Harden.invMapLiteral(inv)\n\n  -- per-build randomized names for every decoder local (keeps `require` and\n  -- stdlib names, which the inlined module sources reference).\n  local g = idGen(rng)\n  local N = {}\n  for _, k in ipairs({\n    'mreg', 'mcache', 'b64', 'gm', 'pr', 'alpha', 'sealed', 'ct', 'csa', 'csb',\n    'csum', 'want', 'n', 't', 'mr', 'prev', 'k', 'cur', 'sr', 'sb', 'is',\n    'ps', 'rg', 'bb', 'plain', 'inv', 'ser', 'vm', 'proto', 'env', 'bit',\n    'msk', 'sbs', 'prm', 'ivs', 'rr', 'envb', 'ver', 'fpw', 'fpg', 'pay',\n    'dz', 'fa', 'fb', 'ei', 'ec', 'dc', 'seal', 'sk',\n  }) do N[k] = g() end\n\n  local order = { 'opcodes', 'bitops', 'serializer', 'seal', 'vm' }\n  local parts = {}\n  -- banner (ASCII only  the browser build ASCII-sanitizes this source)\n  parts[#parts + 1] = '-- ================================================================'\n  parts[#parts + 1] = '--  Obfuscated by Granite Lock  |  https://granitelockvm.vercel.app'\n  parts[#parts + 1] = '--  Custom bytecode VM  |  encrypted  |  no loadstring'\n  parts[#parts + 1] = '-- ================================================================'\n  -- module registry: `require` keeps its name (module sources call it by name).\n  parts[#parts + 1] = 'local ' .. N.mreg .. ',' .. N.mcache .. '={},{}'\n  parts[#parts + 1] = 'local function require(n) if ' .. N.mcache .. '[n]==nil then '\n    .. N.mcache .. '[n]=' .. N.mreg .. '[n]() end return ' .. N.mcache .. '[n] end'\n  parts[#parts + 1] = junkStmt(g, rng)\n  for _, name in ipairs(order) do\n    local s = runtimeSrc[name]\n    if not s then error('webbundle: missing runtime source for ' .. name) end\n    parts[#parts + 1] = N.mreg .. \"['\" .. name .. \"']=function()\\n\" .. safeStrip(s) .. '\\nend'\n    if rng.int(2) == 0 then parts[#parts + 1] = junkStmt(g, rng) end\n  end\n  for _ = 1, rng.int(3) + 2 do parts[#parts + 1] = junkStmt(g, rng) end\n\n  -- custom decoder + GraniteCipher unseal + bootstrap. Verifies the ciphertext\n  -- checksum, peels every cipher round in reverse (stream unmask -> inverse\n  -- S-box -> inverse permutation), checks the VM version + build fingerprint,\n  -- decompresses, then deserializes. All tables (S-box / permutation /\n  -- keystream) are regenerated from the emitted sub-seeds via our own PRNG.\n  -- No loadstring; bytes -> proto.\n  --\n  -- NOTE: no anti-debug / debug-hook abort. A `debug.gethook()` check aborts in\n  -- any environment that has a hook installed (executors, Roblox Studio's own\n  -- debugger), so it false-positives on legitimate use and stops the script\n  -- before it runs -- while providing negligible protection against a real\n  -- attacker. Correct execution is the priority; it is intentionally omitted.\n  parts[#parts + 1] = table.concat({\n    -- per-build permuted alphabet + decoder (reverse lookup by find)\n    'local ' .. N.alpha .. \"='\" .. alpha .. \"'\",\n    'local function ' .. N.b64 .. '(s)',\n    '  local r,v,b={},0,0',\n    \"  s=s:gsub('[^'..\" .. N.alpha .. \"..'=]','')\",\n    '  for i=1,#s do',\n    '    local c=s:sub(i,i)',\n    \"    if c=='=' then break end\",\n    '    local p=' .. N.alpha .. ':find(c,1,true)',\n    '    if not p then break end',\n    '    v=v*64+(p-1) b=b+6',\n    '    if b>=8 then b=b-8 r[#r+1]=string.char(math.floor(v/2^b)%256) v=v%(2^b) end',\n    '  end',\n    '  return table.concat(r)',\n    'end',\n    'local ' .. N.bit .. '=require(\"bitops\")',\n    -- custom GraniteRNG (our own PRNG): split multiply + avalanche, identical\n    -- stream to build-time Harden.prng.\n    'local function ' .. N.gm .. '(a,b) local al=a%65536 return ((al*b)+(((a-al)/65536*b)%65536)*65536)%4294967296 end',\n    'local function ' .. N.pr .. '(sd)',\n    '  local st=sd%4294967296',\n    '  return function(n)',\n    '    st=(' .. N.gm .. '(st,3218467781)+2596069031)%4294967296',\n    '    local x=' .. N.gm .. '(st,3812015801)',\n    '    x=(x%65536)*65536+(x-x%65536)/65536',\n    '    x=' .. N.gm .. '(x,1274126177)',\n    '    if n then return x%n else return x end',\n    '  end',\n    'end',\n    'local ' .. N.sealed .. '=' .. N.b64 .. \"('\" .. payload .. \"')\",\n    -- (6) verify our custom GraniteSum checksum over the ciphertext\n    'local ' .. N.ct .. '=' .. N.sealed .. ':sub(5)',\n    'local ' .. N.csa .. ',' .. N.csb .. '=19088743,1985229328',\n    '  for i=1,#' .. N.ct .. ' do ' .. N.csa .. '=(' .. N.csa .. '*178711+' .. N.ct .. ':byte(i)+1)%4294967296 '\n      .. N.csb .. '=(' .. N.csb .. '+' .. N.csa .. ')%4294967296 end',\n    'local ' .. N.csum .. '=(' .. N.csa .. '+' .. N.gm .. '(' .. N.csb .. ',40503))%4294967296',\n    'local ' .. N.want .. '=' .. N.sealed .. ':byte(1)*16777216+' .. N.sealed .. ':byte(2)*65536+'\n      .. N.sealed .. ':byte(3)*256+' .. N.sealed .. ':byte(4)',\n    'if ' .. N.csum .. '~=' .. N.want .. ' then error(\"granite: integrity check failed\") end',\n    'local ' .. N.n .. '=#' .. N.ct,\n    'local ' .. N.t .. '={}',\n    '  for i=1,' .. N.n .. ' do ' .. N.t .. '[i]=' .. N.ct .. ':byte(i) end',\n    -- per-layer sub-seeds (factored expressions) + IVs, peeled in reverse\n    'local ' .. N.msk .. '=' .. maskList,\n    'local ' .. N.sbs .. '=' .. sboxList,\n    'local ' .. N.prm .. '=' .. permList,\n    'local ' .. N.ivs .. '=' .. ivList,\n    'for ' .. N.rr .. '=#' .. N.msk .. ',1,-1 do',\n    -- (5) inverse stream masking (cipher-feedback chaining)\n    '  local ' .. N.mr .. '=' .. N.pr .. '(' .. N.msk .. '[' .. N.rr .. '])',\n    '  local ' .. N.prev .. '=' .. N.ivs .. '[' .. N.rr .. ']',\n    '  for i=1,' .. N.n .. ' do local ' .. N.k .. '=' .. N.mr .. '(256) local ' .. N.cur .. '=' .. N.t .. '[i] '\n      .. N.t .. '[i]=' .. N.bit .. '.bxor(' .. N.bit .. '.bxor(' .. N.cur .. ',' .. N.k .. '),' .. N.prev .. ') '\n      .. N.prev .. '=' .. N.cur .. ' end',\n    -- (4) inverse byte substitution: rebuild the S-box, invert it, apply\n    '  local ' .. N.sr .. '=' .. N.pr .. '(' .. N.sbs .. '[' .. N.rr .. '])',\n    '  local ' .. N.sb .. '={} for i=0,255 do ' .. N.sb .. '[i]=i end',\n    '  for i=255,1,-1 do local j=' .. N.sr .. '(i+1) ' .. N.sb .. '[i],' .. N.sb .. '[j]=' .. N.sb .. '[j],' .. N.sb .. '[i] end',\n    '  local ' .. N.is .. '={} for i=0,255 do ' .. N.is .. '[' .. N.sb .. '[i]]=i end',\n    '  for i=1,' .. N.n .. ' do ' .. N.t .. '[i]=' .. N.is .. '[' .. N.t .. '[i]] end',\n    -- (3) inverse byte permutation: regenerate swap partners, undo in order\n    '  local ' .. N.ps .. '={} do local ' .. N.rg .. '=' .. N.pr .. '(' .. N.prm .. '[' .. N.rr .. ']) for i=' .. N.n .. ',2,-1 do '\n      .. N.ps .. '[i]=' .. N.rg .. '(i)+1 end end',\n    '  for i=2,' .. N.n .. ' do ' .. N.t .. '[i],' .. N.t .. '[' .. N.ps .. '[i]]=' .. N.t .. '[' .. N.ps .. '[i]],' .. N.t .. '[i] end',\n    'end',\n    'local ' .. N.bb .. '={}',\n    '  for i=1,' .. N.n .. ' do ' .. N.bb .. '[i]=string.char(' .. N.t .. '[i]) end',\n    'local ' .. N.envb .. '=table.concat(' .. N.bb .. ')',\n    -- VM versioning gate\n    'local ' .. N.ver .. '=' .. N.envb .. ':byte(1)',\n    'if ' .. N.ver .. '~=' .. Harden.VM_VERSION .. ' then error(\"granite: VM version mismatch\") end',\n    -- build fingerprint (GraniteSum over version+payload): anti-tamper\n    'local ' .. N.pay .. '=' .. N.envb .. ':sub(6)',\n    'local ' .. N.fpw .. '=' .. N.envb .. ':byte(2)*16777216+' .. N.envb .. ':byte(3)*65536+'\n      .. N.envb .. ':byte(4)*256+' .. N.envb .. ':byte(5)',\n    'local ' .. N.fa .. ',' .. N.fb .. '=19088743,1985229328',\n    'do local ' .. N.dz .. '=string.char(' .. N.ver .. ')..' .. N.pay,\n    '  for i=1,#' .. N.dz .. ' do ' .. N.fa .. '=(' .. N.fa .. '*178711+' .. N.dz .. ':byte(i)+1)%4294967296 '\n      .. N.fb .. '=(' .. N.fb .. '+' .. N.fa .. ')%4294967296 end end',\n    'local ' .. N.fpg .. '=(' .. N.fa .. '+' .. N.gm .. '(' .. N.fb .. ',40503))%4294967296',\n    'if ' .. N.fpg .. '~=' .. N.fpw .. ' then error(\"granite: tamper check failed\") end',\n    -- GraniteRLE decompress -> serialized bytecode\n    'local function ' .. N.dc .. '(s)',\n    '  local fl=s:byte(1) local rest=s:sub(2)',\n    '  if fl==0 then return rest end',\n    '  local ec=rest:byte(1) local o={} local i=2 local m=#rest',\n    '  while i<=m do local c=rest:byte(i)',\n    '    if c==ec then o[#o+1]=string.rep(string.char(rest:byte(i+1)),rest:byte(i+2)) i=i+3',\n    '    else o[#o+1]=string.char(c) i=i+1 end',\n    '  end',\n    '  return table.concat(o)',\n    'end',\n    'local ' .. N.plain .. '=' .. N.dc .. '(' .. N.pay .. ')',\n    'local ' .. N.inv .. '=' .. invLit,\n    'local ' .. N.ser .. '=require(\"serializer\")',\n    'local ' .. N.vm .. '=require(\"vm\")',\n    'local ' .. N.proto .. '=' .. N.ser .. '.deserialize(' .. N.plain .. ',' .. N.inv .. ')',\n    -- Runtime SEAL: derive an ephemeral per-execution session key (clock +\n    -- randomness), then seal the proto tree so instructions are decoded one at a\n    -- time, on demand (streamed execution). The full plaintext bytecode is never\n    -- resident and the in-memory encrypted form differs every run.\n    'local ' .. N.seal .. '=require(\"seal\")',\n    'if math.randomseed then math.randomseed((tick and math.floor(tick()*1e6)) or (os and os.time and os.time()) or 0) end',\n    'local ' .. N.sk .. '=(((tick and math.floor(tick()*1e6)) or (os and os.time and os.time()) or 1)*131+math.random(1,2147483646))%4294967296',\n    'if ' .. N.sk .. '==0 then ' .. N.sk .. '=1 end',\n    N.seal .. '.seal(' .. N.proto .. ',' .. N.sk .. ')',\n    -- Resolve the global environment for the VM (Roblox Luau has no _ENV).\n    'local ' .. N.env,\n    'if type(_ENV)==\"table\" then ' .. N.env .. '=_ENV',\n    'elseif getfenv then local __ok,__e=pcall(getfenv,1) ' .. N.env .. '=(__ok and type(__e)==\"table\") and __e or _G',\n    'else ' .. N.env .. '=_G end',\n    'return ' .. N.vm .. '.load(' .. N.proto .. ',' .. N.env .. ')()',\n  }, '\\n')\n  return table.concat(parts, '\\n')\nend\n\nreturn M\n"};
window.LUAU_VM_RUNTIME={"opcodes":"-- luau-vm/src/opcodes.lua\n-- Custom instruction set for the ferret VM.\n--\n-- Register-based. Operands are register indices unless noted. Multi-value\n-- calls/returns/varargs follow a Lua-style convention: a count field of 0 means\n-- \"up to the current frame top\" (set by a preceding multi-value producer), and\n-- a result count of 0 means \"produce all results and set top\". Everything else\n-- uses exact counts, which keeps the common case simple and fast.\n--\n-- Instructions are stored at compile time as tables {op=, a=, b=, c=, bx=, sbx=}\n-- for readability; the serializer packs them into a compact binary form.\n--\n-- Captured locals and upvalues are unified as \"cells\" (a 1-field box {v=...}),\n-- so closures never touch the parent's live registers  no open/closed upvalue\n-- machinery is required.\n\nlocal Op = {}\nlocal names = {}\nlocal n = 0\nlocal function def(name)\n  n = n + 1\n  Op[name] = n\n  names[n] = name\n  return n\nend\n\n--  data movement / constants \ndef('MOVE')      -- A B      R[A] = R[B]\ndef('LOADK')     -- A Bx     R[A] = K[Bx]\ndef('LOADINT')   -- A sBx    R[A] = sBx                (immediate small integer)\ndef('LOADBOOL')  -- A B      R[A] = (B ~= 0)\ndef('LOADNIL')   -- A B      R[A..A+B] = nil\n\n--  globals / environment \ndef('GETGLOBAL') -- A Bx     R[A] = ENV[K[Bx]]\ndef('SETGLOBAL') -- A Bx     ENV[K[Bx]] = R[A]\n\n--  cells (captured locals) & upvalues \ndef('NEWCELL')   -- A        R[A] = { v = R[A] }       (box a captured local)\ndef('GETCELL')   -- A B      R[A] = R[B].v\ndef('SETCELL')   -- A B      R[A].v = R[B]\ndef('GETUPVAL')  -- A B      R[A] = U[B].v\ndef('SETUPVAL')  -- A B      U[B].v = R[A]\n\n--  tables \ndef('NEWTABLE')  -- A        R[A] = {}\ndef('GETTABLE')  -- A B C    R[A] = R[B][R[C]]\ndef('SETTABLE')  -- A B C    R[A][R[B]] = R[C]\ndef('GETFIELD')  -- A B Bx   R[A] = R[B][K[Bx]]        (const-string key fast path)\ndef('SETFIELD')  -- A Bx C   R[A][K[Bx]] = R[C]\ndef('SELF')      -- A B C    R[A+1] = R[B]; R[A] = R[B][K[C]]  (method prep)\ndef('SETLIST')   -- A B C    R[A][C + i] = R[A+i], i=1..B (B=0 -> up to top)\n\n--  arithmetic (R[A] = R[B] op R[C]) \ndef('ADD'); def('SUB'); def('MUL'); def('DIV'); def('MOD'); def('POW'); def('IDIV')\n--  bitwise \ndef('BAND'); def('BOR'); def('BXOR'); def('SHL'); def('SHR')\n--  concat \ndef('CONCAT')    -- A B C    R[A] = R[B] .. R[B+1] .. ... .. R[C]\n--  unary \ndef('UNM'); def('NOT'); def('LEN'); def('BNOT')  -- A B   R[A] = op R[B]\n--  comparison (R[A] = R[B] op R[C]) \ndef('EQ'); def('LT'); def('LE')\n\n--  control flow \ndef('JMP')       -- sBx      pc += sBx\ndef('JMPIF')     -- A sBx    if truthy(R[A]) then pc += sBx\ndef('JMPIFNOT')  -- A sBx    if not truthy(R[A]) then pc += sBx\n\n--  calls / returns \ndef('CALL')      -- A B C    call R[A] with (B-1) args; keep (C-1) results (0 = to top)\ndef('TAILCALL')  -- A B      return R[A]((B-1) args)   (no host TCO; result-preserving)\ndef('RETURN')    -- A B      return R[A..A+B-2]        (B=0 -> to top)\n\n--  closures / varargs \ndef('CLOSURE')   -- A Bx     R[A] = closure(protos[Bx], captured upvals)\ndef('VARARG')    -- A B      R[A..A+B-2] = varargs     (B=0 -> to top)\n\n--  loops \ndef('FORPREP')   -- A sBx    numeric-for init; jump to loop test\ndef('FORLOOP')   -- A sBx    numeric-for step + test; jump back if continuing\ndef('TFORPREP')  -- A        generic-for setup: normalize R[A..A+2] for Luau\n                 --          generalized iteration (table/__iter -> next-triple)\ndef('TFORCALL')  -- A C      generic-for: call iterator, C results into R[A+3..]\ndef('TFORLOOP')  -- A sBx    generic-for: if R[A+1] ~= nil then R[A]=R[A+1]; pc += sBx\n\ndef('NOP')       -- (used by peephole/DCE)\n\n-- Operand layout per opcode: which instruction fields carry data. Used by the\n-- serializer for a compact, self-validating encoding, and as documentation.\nlocal A, AB, ABC = { 'a' }, { 'a', 'b' }, { 'a', 'b', 'c' }\nlocal operands = {\n  [Op.MOVE] = AB, [Op.LOADK] = { 'a', 'bx' }, [Op.LOADINT] = { 'a', 'sbx' },\n  [Op.LOADBOOL] = AB, [Op.LOADNIL] = AB,\n  [Op.GETGLOBAL] = { 'a', 'bx' }, [Op.SETGLOBAL] = { 'a', 'bx' },\n  [Op.NEWCELL] = A, [Op.GETCELL] = AB, [Op.SETCELL] = AB, [Op.GETUPVAL] = AB, [Op.SETUPVAL] = AB,\n  [Op.NEWTABLE] = A, [Op.GETTABLE] = ABC, [Op.SETTABLE] = ABC,\n  [Op.GETFIELD] = { 'a', 'b', 'bx' }, [Op.SETFIELD] = { 'a', 'bx', 'c' },\n  [Op.SELF] = ABC, [Op.SETLIST] = ABC,\n  [Op.ADD] = ABC, [Op.SUB] = ABC, [Op.MUL] = ABC, [Op.DIV] = ABC, [Op.MOD] = ABC,\n  [Op.POW] = ABC, [Op.IDIV] = ABC,\n  [Op.BAND] = ABC, [Op.BOR] = ABC, [Op.BXOR] = ABC, [Op.SHL] = ABC, [Op.SHR] = ABC,\n  [Op.CONCAT] = ABC,\n  [Op.UNM] = AB, [Op.NOT] = AB, [Op.LEN] = AB, [Op.BNOT] = AB,\n  [Op.EQ] = ABC, [Op.LT] = ABC, [Op.LE] = ABC,\n  [Op.JMP] = { 'sbx' }, [Op.JMPIF] = { 'a', 'sbx' }, [Op.JMPIFNOT] = { 'a', 'sbx' },\n  [Op.CALL] = ABC, [Op.TAILCALL] = AB, [Op.RETURN] = AB,\n  [Op.CLOSURE] = { 'a', 'bx' }, [Op.VARARG] = AB,\n  [Op.FORPREP] = { 'a', 'sbx' }, [Op.FORLOOP] = { 'a', 'sbx' },\n  [Op.TFORPREP] = A, [Op.TFORCALL] = { 'a', 'c' }, [Op.TFORLOOP] = { 'a', 'sbx' },\n  [Op.NOP] = {},\n}\n\nlocal Opcodes = { Op = Op, name = names, count = n, operands = operands }\n\nfunction Opcodes.mnemonic(op)\n  return names[op] or ('?' .. tostring(op))\nend\n\nreturn Opcodes\n","bitops":"-- luau-vm/src/bitops.lua\n-- Custom 32-bit bitwise ops. Deliberately does NOT use the standard `bit32`\n-- library: the ops are our own, built from per-nibble lookup tables so a build\n-- ships no recognizable bit32.* calls. Semantics match 32-bit unsigned bit32\n-- (the model Luau uses), so VM programs behave identically on Luau and Lua 5.4.\n-- Processing 4 bits at a time via a 16x16 table keeps this ~8 lookups per op\n-- (far cheaper than a 32-iteration per-bit loop) so hot bitwise code stays fast.\n\nlocal M = {}\nlocal TWO32 = 4294967296\n\n-- Per-nibble truth tables for our three primitive binary ops, built once.\nlocal AND, OR, XOR = {}, {}, {}\nfor x = 0, 15 do\n  AND[x], OR[x], XOR[x] = {}, {}, {}\n  for y = 0, 15 do\n    local a, b, ra, ro, rx, p = x, y, 0, 0, 0, 1\n    for _ = 1, 4 do\n      local xb, yb = a % 2, b % 2\n      if xb == 1 and yb == 1 then ra = ra + p end\n      if xb == 1 or yb == 1 then ro = ro + p end\n      if xb ~= yb then rx = rx + p end\n      a = (a - xb) / 2; b = (b - yb) / 2; p = p * 2\n    end\n    AND[x][y] = ra; OR[x][y] = ro; XOR[x][y] = rx\n  end\nend\n\nlocal function norm(x) return math.floor(x) % TWO32 end\n\n-- Combine two 32-bit values a nibble at a time through table T.\nlocal function apply(a, b, T)\n  a = norm(a); b = norm(b)\n  local r, p = 0, 1\n  for _ = 1, 8 do\n    local an, bn = a % 16, b % 16\n    r = r + T[an][bn] * p\n    a = (a - an) / 16; b = (b - bn) / 16; p = p * 16\n  end\n  return r\nend\n\nfunction M.band(a, b) return apply(a, b, AND) end\nfunction M.bor(a, b) return apply(a, b, OR) end\nfunction M.bxor(a, b) return apply(a, b, XOR) end\nfunction M.lshift(a, n) return norm(norm(a) * (2 ^ n)) end\nfunction M.rshift(a, n) return math.floor(norm(a) / (2 ^ n)) end\nfunction M.bnot(a) return (TWO32 - 1) - norm(a) end\n\nreturn M\n","serializer":"-- luau-vm/src/serializer.lua\n-- Compact binary encoding of a compiled proto tree, and its inverse loader.\n-- No loadstring: bytes -> runtime proto tables directly.\n--\n-- Format\n--   magic  'FVM' , version(1 byte)\n--   uint32 checksum (custom GraniteSum over the body)\n--   uint32 bodyLength\n--   body:  proto (recursive)\n-- Integers use zig-zag LEB128 varints; numbers round-trip via %.17g text so no\n-- string.pack dependency (works on Lua 5.1+/Luau uniformly).\n\nlocal Opcodes = require('opcodes')\n\nlocal Serializer = {}\n\nlocal MAGIC = 'FVM'\nlocal VERSION = 1\n\n--  writer \nlocal function Writer()\n  return { buf = {}, put = function(self, s) self.buf[#self.buf + 1] = s end }\nend\nlocal function writeByte(w, b) w:put(string.char(b % 256)) end\nlocal function writeUVarint(w, x)\n  x = math.floor(x)\n  while true do\n    local b = x % 128\n    x = math.floor(x / 128)\n    if x > 0 then writeByte(w, b + 128) else writeByte(w, b); break end\n  end\nend\nlocal function writeSVarint(w, x)\n  x = math.floor(x)\n  local zz = x >= 0 and (x * 2) or (-x * 2 - 1) -- zig-zag\n  writeUVarint(w, zz)\nend\nlocal function writeString(w, s)\n  writeUVarint(w, #s)\n  w:put(s)\nend\nlocal function writeU32(w, x)\n  x = math.floor(x) % 4294967296\n  for _ = 1, 4 do writeByte(w, x % 256); x = math.floor(x / 256) end\nend\n\n--  reader \nlocal function Reader(s) return { s = s, pos = 1 } end\n-- EOF-safe: a truncated/corrupt stream reports its position instead of faulting\n-- later on a nil (e.g. `nil % 128`). Keeps malformed input from crashing the host.\nlocal function readByte(r)\n  local b = string.byte(r.s, r.pos)\n  if b == nil then error('serializer: unexpected end of bytecode at offset ' .. r.pos) end\n  r.pos = r.pos + 1\n  return b\nend\nlocal function readUVarint(r)\n  local x, shift = 0, 1\n  while true do\n    local b = readByte(r)\n    x = x + (b % 128) * shift\n    if b < 128 then break end\n    shift = shift * 128\n  end\n  return x\nend\nlocal function readSVarint(r)\n  local zz = readUVarint(r)\n  -- math.floor keeps an integer subtype on Lua 5.4 (unlike `/`, which floats)\n  if zz % 2 == 0 then return math.floor(zz / 2) else return -math.floor((zz + 1) / 2) end\nend\nlocal function readString(r)\n  local n = readUVarint(r)\n  local s = r.s:sub(r.pos, r.pos + n - 1)\n  r.pos = r.pos + n\n  return s\nend\nlocal function readU32(r)\n  local x, m = 0, 1\n  for _ = 1, 4 do x = x + readByte(r) * m; m = m * 256 end\n  return x\nend\n\n--  value (constant) encoding \nlocal T_NIL, T_TRUE, T_FALSE, T_INT, T_NUM, T_STR = 0, 1, 2, 3, 4, 5\n-- Largest magnitude a double represents as an exact integer; the zig-zag varint\n-- stays lossless within it, so genuine integers up to here go through T_INT.\nlocal INT_EXACT = 9007199254740992 -- 2^53\n\n-- Format a float so tonumber() reconstructs the identical value AND float\n-- subtype: %.17g is round-trippable, but an integer-valued float (\"2\", \"-0\")\n-- would read back as an integer, so a trailing \".0\" forces the float subtype.\n-- inf/nan have no numeric literal, so they use their own text sentinels.\nlocal function numToStr(v)\n  if v ~= v then return 'nan' end\n  if v == math.huge then return 'inf' end\n  if v == -math.huge then return '-inf' end\n  local s = string.format('%.17g', v)\n  if not s:find('[.eE]') then s = s .. '.0' end\n  return s\nend\n\nlocal function isIntegerValue(v)\n  if math.type then return math.type(v) == 'integer' end\n  -- Lua 5.1 / Luau: no integer subtype; treat exact integers (but not -0.0,\n  -- whose sign must survive) as integers for compact storage.\n  if v ~= v or v == math.huge or v == -math.huge then return false end\n  if v == 0 and 1 / v < 0 then return false end\n  return math.floor(v) == v\nend\n\nlocal function writeValue(w, v)\n  local t = type(v)\n  if v == nil then writeByte(w, T_NIL)\n  elseif v == true then writeByte(w, T_TRUE)\n  elseif v == false then writeByte(w, T_FALSE)\n  elseif t == 'number' then\n    if isIntegerValue(v) then\n      if v >= -INT_EXACT and v <= INT_EXACT then\n        writeByte(w, T_INT); writeSVarint(w, v)\n      else\n        -- integer past exact-double range: plain integer text (no forced \".0\",\n        -- so it reads back as an integer rather than a lossy float)\n        writeByte(w, T_NUM); writeString(w, string.format('%.17g', v))\n      end\n    else\n      -- float subtype: keep the value, sign of -0.0, and float-ness\n      writeByte(w, T_NUM); writeString(w, numToStr(v))\n    end\n  elseif t == 'string' then writeByte(w, T_STR); writeString(w, v)\n  else error('serializer: cannot encode constant of type ' .. t) end\nend\nlocal function readValue(r)\n  local t = readByte(r)\n  if t == T_NIL then return nil\n  elseif t == T_TRUE then return true\n  elseif t == T_FALSE then return false\n  elseif t == T_INT then return readSVarint(r)\n  elseif t == T_NUM then\n    local s = readString(r)\n    local n = tonumber(s)\n    if n ~= nil then return n end\n    if s == 'inf' then return math.huge end\n    if s == '-inf' then return -math.huge end\n    if s == 'nan' or s == '-nan' then return 0 / 0 end\n    error('serializer: bad number literal ' .. tostring(s))\n  elseif t == T_STR then return readString(r)\n  else error('serializer: bad constant tag ' .. tostring(t)) end\nend\n\n--  proto encoding \n-- opMap (optional): canonical opcode -> the byte(s) written for it. A number\n-- gives a per-build opcode numbering; a { list } of bytes enables instruction\n-- mutation (one opcode has several interchangeable encodings, chosen per\n-- instruction via `pick`). ins.op stays canonical internally, so operand-layout\n-- lookup and the VM's dispatch are unaffected.\nlocal function opByte(opMap, op, pick)\n  local m = opMap and opMap[op]\n  if type(m) == 'table' then return m[(pick and pick() or 0) % #m + 1] end\n  return m or op\nend\nlocal function writeProto(w, p, opMap, pick)\n  writeUVarint(w, p.numparams)\n  writeByte(w, p.isVararg and 1 or 0)\n  writeUVarint(w, p.maxstack)\n  -- upvalues\n  writeUVarint(w, #p.upvals)\n  for _, d in ipairs(p.upvals) do\n    writeByte(w, d.kind == 'reg' and 0 or 1)\n    writeUVarint(w, d.index)\n  end\n  -- constants\n  writeUVarint(w, #p.consts)\n  for _, c in ipairs(p.consts) do writeValue(w, c) end\n  -- code\n  writeUVarint(w, #p.code)\n  for _, ins in ipairs(p.code) do\n    writeByte(w, opByte(opMap, ins.op, pick))\n    for _, field in ipairs(Opcodes.operands[ins.op]) do\n      writeSVarint(w, ins[field] or 0)\n    end\n  end\n  -- nested protos\n  writeUVarint(w, #p.protos)\n  for _, child in ipairs(p.protos) do writeProto(w, child, opMap, pick) end\nend\n\n-- invMap (optional): the inverse of opMap (written byte -> canonical opcode).\nlocal function readProto(r, invMap)\n  local p = { upvals = {}, consts = {}, code = {}, protos = {}, lines = {} }\n  p.numparams = readUVarint(r)\n  p.isVararg = readByte(r) == 1\n  p.maxstack = readUVarint(r)\n  for i = 1, readUVarint(r) do\n    local kind = readByte(r) == 0 and 'reg' or 'up'\n    p.upvals[i] = { kind = kind, index = readUVarint(r) }\n  end\n  for i = 1, readUVarint(r) do p.consts[i] = readValue(r) end\n  local ncode = readUVarint(r)\n  for i = 1, ncode do\n    local op = readByte(r)\n    if invMap then op = invMap[op] end\n    local ins = { op = op }\n    for _, field in ipairs(Opcodes.operands[op]) do ins[field] = readSVarint(r) end\n    p.code[i] = ins\n  end\n  for i = 1, readUVarint(r) do p.protos[i] = readProto(r, invMap) end\n  return p\nend\n\n--  custom container hash (32-bit, portable) \n-- Our own body hash (\"GraniteSum\")  NOT FNV-1a/CRC/djb2, and needs no bit32:\n-- two coupled accumulators (custom multiplier on lane `a`, positional sum on\n-- lane `b`) folded with a final multiply. Products stay < 2^53 so it is exact\n-- in Lua 5.1-5.4 + Luau doubles. Detects any body corruption before deserialize.\nlocal function ghash(s)\n  local a, b = 305419896, 2596069031\n  for i = 1, #s do\n    a = (a * 524287 + s:byte(i) + 1) % 4294967296\n    b = (b + a) % 4294967296\n  end\n  local bl = b % 65536\n  b = ((bl * 40503) + (((b - bl) / 65536 * 40503) % 65536) * 65536) % 4294967296\n  return (a + b) % 4294967296\nend\n\n--  public API \nfunction Serializer.serialize(proto, opMap, pick)\n  local w = Writer()\n  writeProto(w, proto, opMap, pick)\n  local body = table.concat(w.buf)\n  local head = Writer()\n  head:put(MAGIC)\n  writeByte(head, VERSION)\n  writeU32(head, ghash(body))\n  writeU32(head, #body)\n  return table.concat(head.buf) .. body\nend\n\nfunction Serializer.deserialize(bytes, invMap)\n  local r = Reader(bytes)\n  if bytes:sub(1, 3) ~= MAGIC then error('serializer: bad magic (not ferret bytecode)') end\n  r.pos = 4\n  local version = readByte(r)\n  if version ~= VERSION then error('serializer: unsupported version ' .. version) end\n  local checksum = readU32(r)\n  local bodyLen = readU32(r)\n  local body = bytes:sub(r.pos, r.pos + bodyLen - 1)\n  if ghash(body) ~= checksum then error('serializer: checksum mismatch (corrupt bytecode)') end\n  local br = Reader(body)\n  return readProto(br, invMap)\nend\n\n-- Recompute the container checksum over the current body. Lets tooling (e.g.\n-- the malformed-bytecode fuzzer) craft *well-formed-but-nonsense* bytecode that\n-- passes the checksum, so the structural validator  not the checksum  is what\n-- must catch it. Returns a resealed container the loader will accept.\nfunction Serializer.reseal(bytes)\n  local body = bytes:sub(13) -- MAGIC(3)+VERSION(1)+checksum(4)+bodyLen(4)\n  local head = Writer()\n  head:put(MAGIC)\n  writeByte(head, VERSION)\n  writeU32(head, ghash(body))\n  writeU32(head, #body)\n  return table.concat(head.buf) .. body\nend\n\nSerializer.MAGIC = MAGIC\nSerializer.VERSION = VERSION\nreturn Serializer\n","seal":"-- luau-vm/src/seal.lua\n-- Sealed, streamed code  the runtime JIT/on-demand-decode layer, applied AFTER\n-- the build-time GraniteCipher payload has been decoded to proto tables.\n--\n-- Each proto's instruction array is packed into per-instruction encrypted slices\n-- and the plaintext `code` table is dropped. vm.lua then decodes exactly ONE\n-- instruction at a time, immediately before executing it. Consequences:\n--   * Streamed execution  the whole plaintext instruction stream is never\n--     resident; only the current instruction exists, as a short-lived local the\n--     GC reclaims (best-effort \"memory scrubbing\" in a managed runtime).\n--   * Ephemeral session key  the key is derived at RUNTIME (per execution), so\n--     the in-memory encrypted form differs every run; a memory dump is unstable.\n--   * Compact representation  instructions live as opaque encrypted bytes, not\n--     an easy-to-inspect {op=,a=,b=} mirror.\n--\n-- Additive keystream over a GraniteRNG-style split-multiply LCG (products < 2^53,\n-- exact on Luau/Lua doubles, no bit library); per-instruction seeds give random\n-- access without decrypting neighbours.\n\nlocal Opcodes = require('opcodes')\n\nlocal M = {}\n\n-- split-multiply (a*b) mod 2^32, exact in doubles (matches harden.gmul style)\nlocal function gmul(a, b)\n  local al = a % 65536\n  return ((al * b) + (((a - al) / 65536 * b) % 65536) * 65536) % 4294967296\nend\n\nlocal function putUV(t, x)\n  x = math.floor(x)\n  while true do\n    local b = x % 128; x = math.floor(x / 128)\n    if x > 0 then t[#t + 1] = b + 128 else t[#t + 1] = b; break end\n  end\nend\nlocal function putSV(t, x)\n  x = math.floor(x)\n  putUV(t, x >= 0 and x * 2 or (-x * 2 - 1)) -- zig-zag\nend\n\n-- keystream state for instruction i under session key sk (never zero)\nlocal function seed1(sk, i)\n  local s = (gmul(sk, 2654435761) + i * 40503 + 1) % 4294967296\n  if s == 0 then s = 1 end\n  return s\nend\n-- independent keystream seed for string constant i (its own domain)\nlocal function seedK(sk, i)\n  local s = (gmul(sk, 40503) + i * 2654435761 + 7) % 4294967296\n  if s == 0 then s = 1 end\n  return s\nend\nlocal function nextByte(st)\n  st = (gmul(st, 3218467781) + 2596069031) % 4294967296\n  return st, st % 256\nend\n\n-- Additive mask for numeric constant i (own domain). A 31-bit integer, so for an\n-- integer-valued constant with |v| <= 2^52 the sum v+mask stays < 2^53 and is\n-- exact in both Lua integers (modular) and Luau doubles; subtracting the same\n-- mask recovers v exactly, and Lua's arithmetic preserves the int/float subtype.\nlocal function maskFor(sk, i)\n  local st = (gmul(sk, 2246822519) + i * 3266489917 + 11) % 4294967296\n  st = (gmul(st, 3218467781) + 2596069031) % 4294967296\n  -- math.floor forces an integer subtype on Lua 5.4 (gmul's `/` yields a float),\n  -- so an integer constant + mask stays an integer and keeps its subtype.\n  return math.floor(st) % 2147483648 + 1 -- integer in 1 .. 2^31\nend\n\n-- Seal a proto tree in place: proto.code -> proto.sealed (encrypted slices),\n-- plaintext code removed. sk is the runtime-derived session key.\nfunction M.seal(proto, sk)\n  local code = proto.code\n  local n = #code\n  local slices = {}\n  for i = 1, n do\n    local ins = code[i]\n    local raw = { ins.op % 256 }\n    for _, f in ipairs(Opcodes.operands[ins.op]) do putSV(raw, ins[f] or 0) end\n    local st, kb = seed1(sk, i), nil\n    local enc = {}\n    for j = 1, #raw do\n      st, kb = nextByte(st)\n      enc[j] = string.char((raw[j] + kb) % 256) -- additive stream cipher\n    end\n    slices[i] = table.concat(enc)\n  end\n  proto.sealed = { slices = slices, n = n, sk = sk }\n  proto.code = nil\n\n  -- Constant encryption: string constants (the dump target  URLs, remote names,\n  -- keys, messages) are encrypted and stored behind a proxy that decrypts on\n  -- access, so they are never resident in plaintext even after a devirtualizer\n  -- recovers the bytecode. Non-strings pass through. Strings intern in Lua, so\n  -- decrypting the same constant twice yields the same object (identity safe).\n  local K = proto.consts\n  local realK, hasEnc, nk = {}, false, #K\n  for i = 1, nk do\n    local v = K[i]\n    local t = type(v)\n    if t == 'string' then\n      hasEnc = true\n      local st, kb = seedK(sk, i), nil\n      local out = {}\n      for j = 1, #v do st, kb = nextByte(st); out[j] = string.char((v:byte(j) + kb) % 256) end\n      realK[i] = { s = table.concat(out) }\n    elseif t == 'number' and v == v and v <= 4503599627370496 and v >= -4503599627370496\n        and math.floor(v) == v then\n      -- integer-valued number: hide behind an additive keystream mask (fractional\n      -- / inf / nan pass through untouched to avoid any precision or subtype bug)\n      hasEnc = true\n      realK[i] = { n = v + maskFor(sk, i) }\n    else\n      realK[i] = v\n    end\n  end\n  if hasEnc then\n    proto.consts = setmetatable({}, { __index = function(_, i)\n      local e = realK[i]\n      if type(e) == 'table' then\n        if e.n ~= nil then return e.n - maskFor(sk, i) end -- numeric constant\n        local st, kb = seedK(sk, i), nil                   -- string constant\n        local enc, o = e.s, {}\n        for j = 1, #enc do st, kb = nextByte(st); o[j] = string.char((enc:byte(j) - kb) % 256) end\n        return table.concat(o)\n      end\n      return e\n    end })\n  end\n\n  for _, child in ipairs(proto.protos) do M.seal(child, sk) end\nend\n\n-- Decode a single instruction i from a sealed proto  called right before it\n-- runs. Returns a fresh {op=,a=,...} table (a short-lived local at the call site).\nfunction M.decode(sealed, i)\n  local s = sealed.slices[i]\n  local st, kb = seed1(sealed.sk, i), nil\n  local len = #s\n  local bytes = {}\n  for k = 1, len do\n    st, kb = nextByte(st)\n    bytes[k] = (s:byte(k) - kb) % 256 -- inverse of additive cipher\n  end\n  local op = bytes[1]\n  local ins = { op = op }\n  local rp = 2\n  for _, f in ipairs(Opcodes.operands[op]) do\n    local x, shift = 0, 1\n    while true do\n      local bb = bytes[rp]; rp = rp + 1\n      x = x + (bb % 128) * shift\n      if bb < 128 then break end\n      shift = shift * 128\n    end\n    ins[f] = (x % 2 == 0) and math.floor(x / 2) or -math.floor((x + 1) / 2) -- un-zig-zag\n  end\n  return ins\nend\n\nreturn M\n","vm":"-- luau-vm/src/vm.lua\n-- Register-based interpreter for the ferret custom bytecode.\n--\n-- Design choices that buy correctness + Luau compatibility cheaply:\n--   * A VM closure is a REAL Lua function (see makeClosure) that runs `execute`.\n--     So VM and host functions are invoked identically, and metamethods, pcall,\n--     coroutines, table.sort(cmp), etc. all work because a compiled function is\n--     an ordinary callable Lua value.\n--   * All operators use the host's native ops (R[b] + R[c], R[b][k], #x, ..),\n--     so metatables (__index/__add/__concat/__len/) are honored by the host.\n--   * Captured locals & upvalues are \"cells\" ({v=...}); closures capture cell\n--     references, so no open/closed-upvalue bookkeeping is needed.\n--\n-- table.pack/unpack carry multiple values across call boundaries, so multiple\n-- returns and varargs are exact.\n\nlocal Opcodes = require('opcodes')\nlocal Bit = require('bitops')\nlocal Seal = require('seal')\nlocal Op = Opcodes.Op\n\nlocal pack = table.pack or function(...) return { n = select('#', ...), ... } end\nlocal unpack = table.unpack or unpack\n\nlocal VM = {}\n\n-- Optional dynamic opcode profiler. When non-nil, the dispatch loop counts\n-- executed opcodes into it (one nil-check per instruction when disabled).\nlocal PROF = nil\nfunction VM.setProfile(counters) PROF = counters end\n\n-- Forward declaration: execute runs a proto with its upvalues/env/args.\nlocal execute\n\n-- Wrap a proto + captured upvalues + env into a callable Lua value.\nlocal function makeClosure(proto, upvals, env)\n  return function(...)\n    local args = pack(...)\n    local res = execute(proto, upvals, env, args, args.n)\n    return unpack(res, 1, res.n)\n  end\nend\n\n-- The interpreter. Returns a packed results table {..., n=}.\nexecute = function(proto, upvals, env, args, argN)\n  local code = proto.code\n  local sealed = proto.sealed -- when set, instructions are decoded on demand (seal.lua)\n  local K = proto.consts\n  local protos = proto.protos\n  local R = {}\n\n  local np = proto.numparams\n  for i = 0, np - 1 do R[i] = args[i + 1] end\n\n  local varargs, varargN = nil, 0\n  if proto.isVararg then\n    varargs = {}\n    for i = np + 1, argN do\n      varargN = varargN + 1\n      varargs[varargN] = args[i]\n    end\n  end\n\n  local top = 0\n  local pc = 1\n\n  while true do\n    -- JIT/streamed: decode exactly this instruction now, then let it be reclaimed\n    local ins = sealed and Seal.decode(sealed, pc) or code[pc]\n    pc = pc + 1\n    local op = ins.op\n    local a = ins.a\n    if PROF then PROF[op] = (PROF[op] or 0) + 1 end\n\n    -- Dispatch is ordered hottest-first: in a linear if/elseif chain each branch\n    -- costs one comparison, so the common ops (calls, arithmetic, compares,\n    -- jumps, moves, loads) are checked before the rare ones. See docs/perf.md.\n    if op == Op.MOVE then R[a] = R[ins.b]\n    elseif op == Op.CALL then\n      local fn = R[a]\n      local b = ins.b\n      local nargs = (b == 0) and (top - a - 1) or (b - 1)\n      local callArgs = {}\n      for i = 1, nargs do callArgs[i] = R[a + i] end\n      local res = pack(fn(unpack(callArgs, 1, nargs)))\n      local c = ins.c\n      if c == 0 then\n        for i = 1, res.n do R[a + i - 1] = res[i] end\n        top = a + res.n\n      else\n        for i = 1, c - 1 do R[a + i - 1] = res[i] end\n      end\n    elseif op == Op.RETURN then\n      local b = ins.b\n      local nret = (b == 0) and (top - a) or (b - 1)\n      local out = {}\n      for i = 1, nret do out[i] = R[a + i - 1] end\n      out.n = nret\n      return out\n    elseif op == Op.ADD then R[a] = R[ins.b] + R[ins.c]\n    elseif op == Op.SUB then R[a] = R[ins.b] - R[ins.c]\n    elseif op == Op.LT then R[a] = (R[ins.b] < R[ins.c])\n    elseif op == Op.JMPIFNOT then if not R[a] then pc = pc + ins.sbx end\n    elseif op == Op.JMPIF then if R[a] then pc = pc + ins.sbx end\n    elseif op == Op.JMP then pc = pc + ins.sbx\n    elseif op == Op.LOADINT then R[a] = ins.sbx\n    elseif op == Op.LOADK then R[a] = K[ins.bx]\n    elseif op == Op.GETGLOBAL then R[a] = env[K[ins.bx]]\n    elseif op == Op.GETCELL then R[a] = R[ins.b].v\n    elseif op == Op.SETCELL then R[a].v = R[ins.b]\n    elseif op == Op.GETUPVAL then R[a] = upvals[ins.b].v\n    elseif op == Op.SETUPVAL then upvals[ins.b].v = R[a]\n    elseif op == Op.MUL then R[a] = R[ins.b] * R[ins.c]\n    elseif op == Op.LE then R[a] = (R[ins.b] <= R[ins.c])\n    elseif op == Op.EQ then R[a] = (R[ins.b] == R[ins.c])\n    elseif op == Op.GETFIELD then R[a] = R[ins.b][K[ins.bx]]\n    elseif op == Op.GETTABLE then R[a] = R[ins.b][R[ins.c]]\n    elseif op == Op.FORLOOP then\n      local step = R[a + 2]\n      local idx = R[a] + step\n      R[a] = idx\n      local limit = R[a + 1]\n      if (step >= 0 and idx <= limit) or (step < 0 and idx >= limit) then\n        R[a + 3] = idx\n        pc = pc + ins.sbx\n      end\n    elseif op == Op.FORPREP then\n      if R[a + 2] == 0 then error(\"'for' step is zero\") end\n      R[a] = R[a] - R[a + 2]\n      pc = pc + ins.sbx\n\n    --  colder opcodes \n    elseif op == Op.SETTABLE then R[a][R[ins.b]] = R[ins.c]\n    elseif op == Op.SETFIELD then R[a][K[ins.bx]] = R[ins.c]\n    elseif op == Op.SETGLOBAL then env[K[ins.bx]] = R[a]\n    elseif op == Op.NEWTABLE then R[a] = {}\n    elseif op == Op.SELF then\n      R[a + 1] = R[ins.b]\n      R[a] = R[ins.b][K[ins.c]]\n    elseif op == Op.SETLIST then\n      local t = R[a]\n      local count = ins.b\n      if count == 0 then count = top - a - 1 end\n      local base = ins.c\n      for i = 1, count do t[base + i] = R[a + i] end\n    elseif op == Op.CLOSURE then\n      local child = protos[ins.bx]\n      local newUp = {}\n      for i, d in ipairs(child.upvals) do\n        if d.kind == 'reg' then newUp[i] = R[d.index]\n        else newUp[i] = upvals[d.index] end\n      end\n      R[a] = makeClosure(child, newUp, env)\n    elseif op == Op.VARARG then\n      local b = ins.b\n      local count = (b == 0) and varargN or (b - 1)\n      for i = 1, count do R[a + i - 1] = varargs[i] end\n      if b == 0 then top = a + varargN end\n    elseif op == Op.NEWCELL then R[a] = { v = R[a] }\n    elseif op == Op.LOADBOOL then R[a] = (ins.b ~= 0)\n    elseif op == Op.LOADNIL then for i = a, a + ins.b do R[i] = nil end\n    elseif op == Op.DIV then R[a] = R[ins.b] / R[ins.c]\n    elseif op == Op.MOD then R[a] = R[ins.b] % R[ins.c]\n    elseif op == Op.POW then R[a] = R[ins.b] ^ R[ins.c]\n    elseif op == Op.IDIV then R[a] = math.floor(R[ins.b] / R[ins.c])\n    elseif op == Op.BAND then R[a] = Bit.band(R[ins.b], R[ins.c])\n    elseif op == Op.BOR then R[a] = Bit.bor(R[ins.b], R[ins.c])\n    elseif op == Op.BXOR then R[a] = Bit.bxor(R[ins.b], R[ins.c])\n    elseif op == Op.SHL then R[a] = Bit.lshift(R[ins.b], R[ins.c])\n    elseif op == Op.SHR then R[a] = Bit.rshift(R[ins.b], R[ins.c])\n    elseif op == Op.CONCAT then\n      local s = R[ins.b]\n      for i = ins.b + 1, ins.c do s = s .. R[i] end\n      R[a] = s\n    elseif op == Op.UNM then R[a] = -R[ins.b]\n    elseif op == Op.NOT then R[a] = not R[ins.b]\n    elseif op == Op.LEN then R[a] = #R[ins.b]\n    elseif op == Op.BNOT then R[a] = Bit.bnot(R[ins.b])\n    elseif op == Op.TAILCALL then\n      local fn = R[a]\n      local b = ins.b\n      local nargs = (b == 0) and (top - a - 1) or (b - 1)\n      local callArgs = {}\n      for i = 1, nargs do callArgs[i] = R[a + i] end\n      return pack(fn(unpack(callArgs, 1, nargs)))\n    elseif op == Op.TFORPREP then\n      -- Luau generalized iteration: `for vars in exp do`. If the iterator value\n      -- is already a function, keep the classic protocol (pairs/ipairs/custom).\n      -- Otherwise resolve an __iter metamethod, or fall back to iterating a plain\n      -- table via `next`  matching Luau, where a bare table is iterable.\n      local it = R[a]\n      if type(it) ~= 'function' then\n        local mt = getmetatable(it)\n        local iterMM = mt and mt.__iter\n        if iterMM then\n          local f, s, c = iterMM(it)\n          R[a], R[a + 1], R[a + 2] = f, s, c\n        elseif type(it) == 'table' then\n          R[a], R[a + 1], R[a + 2] = next, it, nil\n        end\n        -- else: leave as-is; TFORCALL will raise, as Luau does for a non-iterable\n      end\n    elseif op == Op.TFORCALL then\n      local fn = R[a]\n      local res = pack(fn(R[a + 1], R[a + 2]))\n      for i = 1, ins.c do R[a + 2 + i] = res[i] end\n    elseif op == Op.TFORLOOP then\n      if R[a + 3] ~= nil then\n        R[a + 2] = R[a + 3]\n        pc = pc + ins.sbx\n      end\n    elseif op == Op.NOP then -- nothing\n    else\n      error('ferret-vm: bad opcode ' .. Opcodes.mnemonic(op) .. ' at pc ' .. (pc - 1))\n    end\n  end\nend\n\n-- Public: build a callable from a top-level proto and an environment.\nfunction VM.load(proto, env)\n  env = env or _ENV or _G\n  return makeClosure(proto, {}, env)\nend\n\nVM.execute = execute\nVM.makeClosure = makeClosure\nreturn VM\n"};
